INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (366937304121344, '2026-06-16 10:08:40.17911', 295514619002880, NULL, NULL, '', NULL, NULL, 'Iran’s top diplomat says any continued Israeli presence in Lebanon would violate the interim U.S.–Iran deal to end the war. Prime Minister Benjamin Netanyahu insists Israel will remain as long as necessary. DW has more.', NULL, 'https://www.dw.com/en/us-iran-deal-tehran-says-israel-withdrawal-from-lebanon-key/live-77573728?maca=en-rss-en-all-1573-rdf', '2026-06-16 10:00:00+00', 'US-Iran deal: Tehran says Israel withdrawal from Lebanon key', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (366937309167616, '2026-06-16 10:08:41.410714', 295500424519680, NULL, 'DIE ZEIT: Deutschland - Tom-Luca Freund', 'Deutschland', NULL, NULL, 'Ein neues Abwehrzentrum soll vor hybrider Kriegsführung von Staaten wie Russland schützen. Ziel ist laut Innenminister Dobrindt »Koordinierung statt Kompetenzgerangel«.', '{urn:uuid:0392f1eb-7a93-49e3-84cb-78349a128df3}', 'https://www.zeit.de/politik/deutschland/2026-06/hybride-bedrohungen-gemeinsames-zentrum-alexander-dobrindt-csu', '2026-06-16 10:00:16+00', 'Berlin: Alexander Dobrindt eröffnet Zentrum zur Abwehr hybrider Bedrohungen', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (366937309171712, '2026-06-16 10:08:41.411797', 295500424519680, NULL, 'DIE ZEIT: Sport - Leon Ginzel, Eric Voigt', 'Sport', NULL, NULL, 'Pro Tag zwei WM-Spiele, bequem im Privatjet – die Reisepläne von Gianni Infantino erzürnen Greenpeace. Nach dem Schweden-Debakel feuert Tunesien den Trainer. Das Liveblog', '{urn:uuid:e528ca8b-f67f-493e-b77e-30d2cb57e930}', 'https://www.zeit.de/sport/2026-05/fussball-wm-2026-liveblog', '2026-06-16 09:54:02+00', 'Fußball-WM 2026: Greenpeace kritisiert Fifa-Chef Infantino für Privatjet-Pläne', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (366937309175808, '2026-06-16 10:08:41.412327', 295500424519680, NULL, 'DIE ZEIT: Arbeit - Daniel Erk', 'Arbeit', NULL, NULL, 'Danny Klein schreibt Trauerreden für Beerdigungen. Im Podcast erzählt sie, warum sie dafür keine Lebensdaten sammelt. Sondern Geschichten.', '{urn:uuid:7bdc3d0e-7fa3-4b70-b37e-4c44d0841b6c}', 'https://www.zeit.de/arbeit/2026-06/danny-klein-trauerreden-beerdigung-arbeit-podcast', '2026-06-16 09:53:17+00', 'Danny Klein: »Ich kann nicht mehr als eine Rede pro Monat machen«', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (366937309175809, '2026-06-16 10:08:41.412327', 295500424519680, NULL, 'DIE ZEIT: Deutschland - Yannick von Eisenhart Rothe', 'Deutschland', NULL, NULL, 'Mit einem nächtlichen Charterflug sollen der Nachrichtenagentur dpa zufolge Menschen nach Afghanistan abgeschoben worden sein. Dabe habe es sich um Straftäter gehandelt.', '{urn:uuid:2a830b7f-7b2f-425e-9c53-bf1b0e793acb}', 'https://www.zeit.de/politik/deutschland/2026-06/abschiebung-afghanistan-charterflug-straftaeter-kabul', '2026-06-16 09:50:14+00', 'Abschiebungen: Deutschland schiebt laut Bericht etwa 30 Menschen nach Afghanistan ab', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (366937309745152, '2026-06-16 10:08:41.551096', 295853820891136, NULL, NULL, '', NULL, NULL, 'Mit 83,5 Millionen Einwohnern ist die Bevölkerung in Deutschland im vergangenen Jahr leicht gesunken. Die Zuwanderung kann das Geburtendefizit nicht mehr ausgleichen, wie Daten des Statistischen Bundesamtes zeigen.', 'e1efddb2-c1ad-46ed-af5b-6c2cf81759a4', 'https://www.tagesschau.de/inland/gesellschaft/schrumpfende-bevoelkerung-100.html', '2026-06-16 09:36:11+00', 'Zahl der Einwohner in Deutschland leicht gesunken', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (366937309745153, '2026-06-16 10:08:41.551096', 295853820891136, NULL, NULL, '', NULL, NULL, 'Weite Teile der Potsdamer Innenstadt stehen still. Dort soll eine Weltkriegsbombe entschärft werden. Tausende Menschen sind von den Evakuierungen betroffen, auch der Hauptbahnhof ist gesperrt.', 'tagesschau_fm-story-rbb_potsdam-bombe-entschaerfung-sperrkreis-evakuierung-innenstadt-pendler-hauptbahnhof', 'https://www.tagesschau.de/inland/regional/brandenburg/bombenentschaerfung-potsdam-sperrungen-100.html', '2026-06-16 09:37:06+00', 'Bombenentschärfung in Potsdam: Evakuierungen in der Innenstadt', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (366983568429056, '2026-06-16 13:16:55.175555', 295500424519680, NULL, 'DIE ZEIT: Gesundheit - Matthias Kreienbrink', 'Gesundheit', NULL, NULL, 'Bis vor Kurzem waren ADHS und Autismus zwei strikt getrennte Störungsbilder. Doch in der Forschung tritt immer stärker zutage, wie eng verbunden sie miteinander sind.', '{urn:uuid:9dbd3e47-514b-4ce8-a77d-b38d694dd509}', 'https://www.zeit.de/gesundheit/2026-06/audhs-adhs-autismus-diagnose-psychologie', '2026-06-16 13:10:25+00', 'AuDHS: ADHS oder Autismus? Manchmal ist es beides', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (366983568433152, '2026-06-16 13:16:55.176687', 295500424519680, NULL, 'DIE ZEIT: Digital - Alena Kammer', 'Digital', NULL, NULL, 'Mit Hilfe künstlicher Intelligenz können täuschend echt wirkende Bilder ins Netz gestellt werden. Für sexualisierte Deepfakes soll künftig ein EU-weites Verbot gelten.', '{urn:uuid:6f20d45a-47d6-48f1-be4c-4a0195383f6e}', 'https://www.zeit.de/digital/2026-06/deepfakes-eu-verbot-ki-anwendungen-parlament', '2026-06-16 12:59:01+00', 'Deepfakes in der EU: EU-Parlament beschließt Verbot von KI für sexualisierte Deepfakes', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (366983568433153, '2026-06-16 13:16:55.176687', 295500424519680, NULL, 'DIE ZEIT: Wirtschaft - Yannick von Eisenhart Rothe', 'Wirtschaft', NULL, NULL, 'Das Ifo-Institut hat Einsparmöglichkeiten im Bundeshaushalt analysiert. Eine Möglichkeit sei die deutliche Absenkung der Einkommensgrenze beim Elterngeld.', '{urn:uuid:522a1e9f-343e-47d7-b4ae-898bc67df9f8}', 'https://www.zeit.de/wirtschaft/2026-06/ifo-institut-bundeshaushalt-einsparungen-elterngeld-muetterrente', '2026-06-16 12:49:14+00', 'Ifo-Institut: Ifo bringt Kürzungen bei Elterngeld und Mütterrente ins Spiel', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (366983568433154, '2026-06-16 13:16:55.176687', 295500424519680, NULL, 'DIE ZEIT: Umwelt - Tom-Luca Freund', 'Umwelt', NULL, NULL, 'Die große Mehrheit von Europas Gewässern sind laut einem Bericht badetauglich. In Deutschland waren mehr als 90 Prozent der Meere, Flüsse und Seen sogar exzellent.', '{urn:uuid:0b05f775-729c-4bcc-b608-2238ac199a24}', 'https://www.zeit.de/wissenschaft/umwelt/2026-06/wasserqualitaet-badegewaesser-europa-eu-meere-seen', '2026-06-16 12:47:25+00', 'Wasserqualität: Fast alle Badegewässer in Europa erfüllen Mindeststandards', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (366983569002496, '2026-06-16 13:16:55.315231', 295853820891136, NULL, NULL, '', NULL, NULL, 'Die führenden demokratischen Wirtschaftsmächte wollen die Ukraine wieder stärker unterstützen. Dazu sollen neue Sanktionen gegen den russischen Öl- und Gassektor kommen, erklärten Teilnehmer des G7-Gipfels.', '81d7b620-243a-4a59-966f-2d63b7902cda', 'https://www.tagesschau.de/ausland/europa/g7-ukraine-sanktionen-russland-100.html', '2026-06-16 13:13:06+00', 'G7 planen neue Russland-Sanktionen', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (366983569588224, '2026-06-16 13:16:55.458413', 295514619002880, NULL, NULL, '', NULL, NULL, 'The sharp defense spending hike highlights lessons Pakistan has learned from recent conflicts with India and a growing focus on new warfare technologies, regardless of economic constraints imposed by the IMF.', NULL, 'https://www.dw.com/en/pakistan-raises-defense-spending-amid-regional-conflicts/a-77577772?maca=en-rss-en-all-1573-rdf', '2026-06-16 13:00:00+00', 'Pakistan raises defense spending amid regional conflicts', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (366983570251776, '2026-06-16 13:16:55.62013', 295880188006400, NULL, NULL, '', NULL, NULL, 'Im Westen der Ukraine am Fluss Dnister hat sich eine religiöse Gemeinschaft einen abgeschiedenen friedlichen Lebensraum geschaffen, in dem sie sich selbst versorgt und auf die meisten Annehmlichkeiten der Moderne verzichtet. Die pazifistische Haltung der „Mützenträger“ wird jedoch durch Russlands Krieg gegen die Ukraine vor eine Herausforderung gestellt; sie bleiben ihren Überzeugungen treu, backen aber Brot für die Soldaten. Der stille Dokumentarfilm fängt die Gemeinschaft über Landschaftstableaus ein, während die Mitglieder überwiegend im Off über ihr Leben, den Glauben, den Fluss und den Krieg reden. So verharrt er in einer Außenperspektive, die Sehnsucht nach einer friedlichen Welt verrät, den strikten Pazifismus aber auch hinterfragt.', 'https://www.filmdienst.de/film/details/626681/silent-flood', 'https://www.filmdienst.de/film/details/626681/silent-flood', '2026-06-16 12:57:05+00', 'Silent Flood', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367321637683202, '2026-06-17 12:12:31.614631', 295853820891136, NULL, NULL, '', NULL, NULL, 'Die G7-Staaten wollen den Druck auf Russland noch weiter erhöhen. Einige Staatschefs kündigten neue Sanktionen an - US-Präsident Trump will Sanktionen wieder aufnehmen. Sein Engagement für die Ukraine scheint wieder erwacht zu sein. Von K. Schmid.', '868a1f72-dde5-415e-812b-0d141d71fbf0', 'https://www.tagesschau.de/ausland/europa/g7-treffen-evian-100.html', '2026-06-16 17:44:59+00', 'G7-Treffen: Klare Kante gegen Russland - auch mit Trump?', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (366938811146240, '2026-06-16 10:14:48.1045', 295500424519680, NULL, 'DIE ZEIT: Ausland - Isabelle Daniel, Claudia Thaler', 'Ausland', NULL, NULL, 'Dem US-Präsidenten zufolge darf der Iran »niemals« Atomwaffen haben. Putin ruft er zu Friedensverhandlungen auf. Arabische Staatschefs bei G7 eingetroffen. Das Liveblog', '{urn:uuid:5723c41e-8120-4e74-b7e7-cdca99002193}', 'https://www.zeit.de/politik/ausland/2026-06/g7-evian-genf-proteste', '2026-06-16 10:07:28+00', 'Évian-les-Bains: Donald Trump kündigt bei G7-Gipfel »zweite Phase« von Iran-Abkommen an', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (366987170918400, '2026-06-16 13:31:34.689548', 295500424519680, NULL, 'DIE ZEIT: Kunst - Alexander Cammann', 'Kunst', NULL, NULL, 'Im 19. Jahrhundert schufen deutsche Künstler in Olevano bei Rom unzählige ikonische Landschaftsbilder. Der Kunsthistoriker Golo Maurer erinnert an ihr Werk und ihr Leben.', '{urn:uuid:9b41cb0f-07df-45dc-b228-16b733320570}', 'https://www.zeit.de/2026/26/olevano-rom-deutsche-kunst-landschaft-serpentara-joseph-anton-koch', '2026-06-16 13:19:52+00', 'Olevano bei Rom: Hier beginnt die deutsche Kunst', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (366987170922496, '2026-06-16 13:31:34.690547', 295500424519680, NULL, 'DIE ZEIT: Ausland - Tom-Luca Freund', 'Ausland', NULL, NULL, 'Zu seinem 80. Geburtstag ließ Donald Trump eine Arena für Käfigkämpfe errichten. Ein mutmaßlichen Anschlag auf das Event hat das FBI nach eigenen Angaben verhindert.', '{urn:uuid:df6d57cf-e254-4dcd-9aa8-43c1912289fd}', 'https://www.zeit.de/politik/ausland/2026-06/anschlag-geburtstag-donald-trump-fbi', '2026-06-16 13:19:46+00', 'Washington: Anschlag auf Käfigkampf am Weißen Haus laut FBI-Chef vereitelt', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (366987170922497, '2026-06-16 13:31:34.690547', 295500424519680, NULL, 'DIE ZEIT: Feuilleton - Ann-Kristin Tlusty', 'Feuilleton', NULL, NULL, 'Was ein neu entdeckter Brief von Sigmund Freud über den Begründer der Psychoanalyse verrät.', '{urn:uuid:f8a359e3-8f49-4a6f-87b6-e3bcddb097a9}', 'https://www.zeit.de/2026/26/sigmund-freud-brief-richard-coudenhove-kalergi-psychoanalyse', '2026-06-16 13:18:36+00', 'Sigmund Freud: »Den lieb’ ich, der Unmögliches begehrt«', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (366987170922498, '2026-06-16 13:31:34.690547', 295500424519680, NULL, 'DIE ZEIT: Ausland - Alexander Eydlin', 'Ausland', NULL, NULL, 'Weltweit können 2,4 Millionen Geflüchtete nach UN-Angaben nicht ausreichend versorgt werden oder sind in unsicheren Ländern. Zugleich können sie demnach nicht heimkehren.', '{urn:uuid:b6f0174e-062c-4f23-ad1c-7c12cf316ddd}', 'https://www.zeit.de/politik/ausland/2026-06/unhcr-bericht-fluechtlinge-sicherheit-nachbarlaender', '2026-06-16 13:16:29+00', 'UNHCR-Bericht: Millionen Flüchtlinge laut UN nicht sicher in Zufluchtsländern', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (366987171336192, '2026-06-16 13:31:34.791421', 295853820891136, NULL, NULL, '', NULL, NULL, 'Während die G7-Staaten wieder Friedensgespräche in Gang bringen wollen, setzt die Ukraine ihre Gegenangriffe im russischen Angriffskrieg fort. Ziel war erneut die Ölindustrie. In Moskau war auch der Flugbetrieb betroffen.', '3936572c-7784-4694-b821-c2ed3b553404', 'https://www.tagesschau.de/ausland/russland-meldet-ukrainische-angriffe-100.html', '2026-06-16 13:28:59+00', 'Raffinerie getroffen - Moskau meldet Attacken von 60 Drohnen', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367321637683203, '2026-06-17 12:12:31.614631', 295853820891136, NULL, NULL, '', NULL, NULL, 'Vor 50 Jahren gingen im südafrikanischen Township Soweto Tausende Schüler auf die Straße. Der Aufstand markierte einen Wendepunkt im Kampf der schwarzen Bevölkerungsmehrheit gegen das rassistische Apartheid-System. Von Stephan Ueberbach.', '819dca14-ee88-4dd7-8692-3d59d758f2e2', 'https://www.tagesschau.de/ausland/afrika/suedafrika-soweto-aufstand-100.html', '2026-06-16 17:44:51+00', '50 Jahre Soweto-Aufstand: Der Anfang vom Ende der Apartheid', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367321637683204, '2026-06-17 12:12:31.614631', 295853820891136, NULL, NULL, '', NULL, NULL, 'Vor der britischen Küste hat ein russisches Kriegsschiff Warnschüsse in Richtung einer Jacht abgefeuert. Laut Russland hat sich das Boot auf einem "gefährlichen Kurs" genähert. Die Jachtbesitzer widersprechen.', '7b9b1251-8978-4474-bca6-903598379e21', 'https://www.tagesschau.de/ausland/europa/russisches-kriegsschiff-aermelkanal-100.html', '2026-06-17 06:49:56+00', 'Russisches Kriegsschiff gibt im Ärmelkanal Warnschüsse ab', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367321637683205, '2026-06-17 12:12:31.614631', 295853820891136, NULL, NULL, '', NULL, NULL, 'Das FBI hat nach eigenen Angaben einen Anschlagsplan auf ein Kampfsportevent am Geburtstag des US-Präsidenten verhindert. Offenbar sollten Drohnen mit Sprengstoff und Scharfschützen zum Einsatz kommen.', '8309d499-4231-4ba9-890a-1be3ae0adaf8', 'https://www.tagesschau.de/ausland/amerika/trump-anschlag-vereitelt-100.html', '2026-06-17 04:49:51+00', 'Laut FBI wurde ein möglicher Anschlag auf Trumps Geburtstag vereitelt', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367321637683206, '2026-06-17 12:12:31.614631', 295853820891136, NULL, NULL, '', NULL, NULL, 'Die Hoffnung auf eine Friedenslösung am Persischen Golf hielt den DAX am Ende nur knapp im Plus. Zu groß sind die Unsicherheiten. Schlechte Nachrichten gab es für die Autowerte aus China.', '21879717-7ba5-4480-b522-3bddd04a1bca', 'https://www.tagesschau.de/wirtschaft/finanzen/marktberichte/marktbericht-dax-dow-geldanlage-132.html', '2026-06-16 16:28:33+00', 'Marktbericht: Iran-Deal zieht nicht mehr', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367321637683207, '2026-06-17 12:12:31.614631', 295853820891136, NULL, NULL, '', NULL, NULL, 'Gerade einmal 50 Jahre ist es her, dass erstmals eine Frau eine Ausgabe der tagesschau sprach. Was heute selbstverständlich ist, sorgte damals für viel Wirbel. Im Interview schaut Berghoff auf diesen besonderen Tag zurück.', 'ec616bd5-100b-4a03-bc73-5f29d134919d', 'https://www.tagesschau.de/inland/dagmar-berghoff-tagesschau-100.html', '2026-06-16 15:49:16+00', 'Vor 50 Jahren sprach Dagmar Berghoff ihre erste Tagesschau-Ausgabe', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367321637683208, '2026-06-17 12:12:31.614631', 295853820891136, NULL, NULL, '', NULL, NULL, 'Deutschland hat erneut mehr als 30 Straftäter nach Afghanistan abgeschoben - auf Basis einer Vereinbarung mit den islamistischen Taliban in dem Land. Kritiker der Aktion organisierten eine Mahnwache am Leipziger Flughafen.', '2bac00e0-8a79-47a6-9479-d87fed231a34', 'https://www.tagesschau.de/inland/gesellschaft/abschiebeflug-afghanen-100.html', '2026-06-16 15:35:09+00', 'Erneuter Abschiebeflug: Straftäter nach Afghanistan ausgewiesen', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367321637683209, '2026-06-17 12:12:31.614631', 295853820891136, NULL, NULL, '', NULL, NULL, 'Kriminelle greifen immer öfter zu illegalen Schusswaffen. Bislang ist der Besitz aber nur als Vergehen und nicht als Verbrechen eingestuft. Um das zu ändern, hat der Berliner Senat nun eine Bundesratsinitiative gestartet.', 'tagesschau_fm-story-rbb_berlin-bundesrat-waffenrecht-senat-lka-ferum-schusswaffen', 'https://www.tagesschau.de/inland/regional/berlin/schaerferes-waffenrecht-bundesratsinitiative-100.html', '2026-06-16 15:10:58+00', 'Bundesratsinitiative aus Berlin für schärferes Waffenrecht', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367321637683210, '2026-06-17 12:12:31.614631', 295853820891136, NULL, NULL, '', NULL, NULL, 'Gute Nachrichten für den Sommer: Europas Badegewässer sind in Topform. Wie eine Auswertung der Europäischen Umweltagentur EEA, zeigt schneidet Deutschland besonders gut ab. Wo die Qualität von Seen, Flüssen und Küstengewässern noch besser ist.', '555183cf-b3e1-4cef-b388-349ff86b4851', 'https://www.tagesschau.de/wissen/badegewaesser-qualitaet-europa-100.html', '2026-06-16 15:04:52+00', 'EU-Vergleich: Deutsche Badegewässer schneiden sehr gut ab', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367321637683211, '2026-06-17 12:12:31.614631', 295853820891136, NULL, NULL, '', NULL, NULL, 'Drei Abwehrzentren gibt es schon - nun sind es vier: Das neue Zentrum soll Maßnahmen zur Abwehr hybrider Bedrohungen koordinieren. Um welche Gefahren geht es? Und warum braucht es das gerade jetzt?', 'f039faaa-b0e3-4cf8-90af-c17a3c813e1d', 'https://www.tagesschau.de/inland/gesellschaft/abwehrzentrum-hybride-bedrohungen-100.html', '2026-06-16 15:02:07+00', 'Was soll das neue Abwehrzentrum für hybride Bedrohungen bringen?', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367321637683212, '2026-06-17 12:12:31.614631', 295853820891136, NULL, NULL, '', NULL, NULL, 'Die Fußballweltmeisterschaft wird in den Sozialen Netzwerken von zahlreichen Fakes begleitet. So kursiert ein KI-generiertes Bild eines Deutschlandfans, der an Hitler erinnert. Auch viele sexistische Fakes gehen viral. Von C. Reveland und P. Siggelkow.', 'c8241cac-d9bf-4923-be64-ecd860c6d798', 'https://www.tagesschau.de/faktenfinder/wm-2026-fakes-100.html', '2026-06-16 15:01:56+00', 'Fakes zur WM 2026 - KI-generierte Bilder und falsche Ticketshops', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (366945911242752, '2026-06-16 10:43:41.52609', 295500424519680, NULL, 'DIE ZEIT: Ausland - Rieke Havertz', 'Ausland', NULL, NULL, 'Donald Trump verkauft die Vereinbarung mit dem Iran als Erfolg. Doch den innenpolitischen Krisen, die sein Krieg ausgelöst hat, wird er vorerst nicht entkommen.', '{urn:uuid:aae873a1-cc5b-4578-a63e-c974da1228d5}', 'https://www.zeit.de/politik/ausland/2026-06/usa-iran-donald-trump-vereinbarung-krise-krieg', '2026-06-16 10:38:11+00', 'USA und Iran: So leicht wird er den Krieg nicht los', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (366945911246848, '2026-06-16 10:43:41.527595', 295500424519680, NULL, 'DIE ZEIT: Ausland - Marla  Noss, Hella Kemper, Tom-Luca Freund', 'Ausland', NULL, NULL, 'Der iranische Außenminister Abbas Araghtschi hat ein Ende des Kriegs mit dem Abzug Israels aus dem Libanon verknüpft. Das Liveblog', '{urn:uuid:2d57f875-64df-4ad6-b830-4fee12760ea8}', 'https://www.zeit.de/politik/ausland/2026-05/iran-krieg-donald-trump-hormus-live', '2026-06-16 10:29:44+00', 'Irankrieg: Israelische Angriffe wären laut Araghtschi Verstoß gegen US-Absprache', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (366945911246849, '2026-06-16 10:43:41.527595', 295500424519680, NULL, 'DIE ZEIT: Ausland - Isabelle Daniel, Claudia Thaler', 'Ausland', NULL, NULL, 'Dem US-Präsidenten zufolge darf der Iran »niemals« Atomwaffen haben. Putin ruft er zu Friedensverhandlungen auf. Arabische Staatschefs bei G7 eingetroffen. Das Liveblog', '{urn:uuid:5723c41e-8120-4e74-b7e7-cdca99002193}', 'https://www.zeit.de/politik/ausland/2026-06/g7-evian-genf-proteste', '2026-06-16 10:16:22+00', 'Évian-les-Bains: Donald Trump kündigt bei G7-Gipfel »zweite Phase« von Iranabkommen an', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (366945912385536, '2026-06-16 10:43:41.805334', 295514619002880, NULL, NULL, '', NULL, NULL, 'A potential US-Iran agreement could lower energy, fertilizer, and food prices in Africa if the Strait of Hormuz fully reopens. Oil exporters such as Nigeria and Angola might have to cope with less revenue, experts say.', NULL, 'https://www.dw.com/en/sigh-of-relief-in-africa-as-the-strait-of-hormuz-reopens/a-77564378?maca=en-rss-en-all-1573-rdf', '2026-06-16 10:25:00+00', 'Sigh of relief in Africa as the Strait of Hormuz ''reopens''', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (366945913790464, '2026-06-16 10:43:42.14832', 295880188006400, NULL, NULL, '', NULL, NULL, 'Im Westen der Ukraine am Fluss Dnister hat sich eine religiöse Gemeinschaft einen abgeschiedenen friedlichen Lebensraum geschaffen, in dem sie sich selbst versorgt und auf die meisten Annehmlichkeiten der Moderne verzichtet. Die pazifistische Haltung der „Mützenträger“ wird jedoch durch Russlands Krieg gegen die Ukraine vor eine Herausforderung gestellt; sie bleiben ihren Überzeugungen treu, backen aber Brot für die Soldaten. Der stille Dokumentarfilm fängt die Gemeinschaft über Landschaftstableaus ein, während die Mitglieder überwiegend im Off über ihr Leben, den Glauben, den Fluss und den Krieg reden. So verharrt er in einer Außenperspektive, die Sehnsucht nach einer friedlichen Welt verrät, den strikten Pazifismus aber auch hinterfragt.', 'https://www.filmdienst.de/film/details/626681/silent-flood', 'https://www.filmdienst.de/film/details/626681/silent-flood', '2026-06-16 10:25:22+00', 'Silent Flood', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (366945913790465, '2026-06-16 10:43:42.14832', 295880188006400, NULL, NULL, '', NULL, NULL, 'In der nahen Zukunft ist die Welt in kleine Stadtstaaten zerfallen, die um die verbliebenen Rohstoffe konkurrieren. Eine griechische Siedlung lebt vom Öl und wird patriarchal geführt, trotzdem präferiert der todkranke Herrscher seine Geliebte als Nachfolgerin. Diese findet in einer neu eingetroffenen Frau eine Verbündete und Geliebte, die ihr im Kampf gegen die Männerherrschaft beisteht. Ein an B-Film-Mustern geschulter feministischer Endzeit-Actionfilm, in dem der Mythos um den tödlichen Blick der Gorgone Medusa auf die Hauptfigur übertragen wird. Das ist eine Zeitlang reizvoll und formal eindrucksvoll, verliert sich aber letztlich zwischen Exploitationfilm und Künstlichkeit.', 'https://www.filmdienst.de/film/details/626219/gorgona', 'https://www.filmdienst.de/film/details/626219/gorgona', '2026-06-16 10:19:52+00', 'Gorgonà', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (366989234429952, '2026-06-16 13:39:58.476535', 295500424519680, NULL, 'DIE ZEIT: Ausland - Alexander Eydlin', 'Ausland', NULL, NULL, 'Weltweit können 2,4 Millionen Geflüchtete nach UN-Angaben nicht ausreichend versorgt werden oder sind in unsicheren Ländern. Zugleich können sie demnach nicht heimkehren.', '{urn:uuid:b6f0174e-062c-4f23-ad1c-7c12cf316ddd}', 'https://www.zeit.de/politik/ausland/2026-06/unhcr-bericht-fluechtlinge-sicherheit-nachbarlaender', '2026-06-16 13:36:19+00', 'UNHCR-Bericht: Millionen Flüchtlinge laut UN nicht sicher in Zufluchtsländern', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (366989234434048, '2026-06-16 13:39:58.477549', 295500424519680, NULL, 'DIE ZEIT: Wirtschaft - Yannick von Eisenhart Rothe', 'Wirtschaft', NULL, NULL, 'Das Ifo-Institut hat Einsparmöglichkeiten im Bundeshaushalt analysiert. Eine Möglichkeit sei die deutliche Absenkung der Einkommensgrenze beim Elterngeld.', '{urn:uuid:522a1e9f-343e-47d7-b4ae-898bc67df9f8}', 'https://www.zeit.de/wirtschaft/2026-06/ifo-institut-bundeshaushalt-einsparungen-elterngeld-muetterrente', '2026-06-16 13:33:08+00', 'Ifo-Institut: Ifo bringt Kürzungen bei Elterngeld und Mütterrente ins Spiel', NULL);
