INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (366989234974720, '2026-06-16 13:39:58.609232', 295853820891136, NULL, NULL, '', NULL, NULL, 'Nach monatelangen Verhandlungen hat das EU-Parlament Maßnahmen zur Regulierung von KI beschlossen. Anwendungen, die sexualisierte Deepfakes erstellen, sollen verboten werden. Das Reformpaket sieht aber auch Lockerungen vor.', '7b950b17-d72e-4e01-9ac8-2e7b4365c285', 'https://www.tagesschau.de/ausland/europa/eu-regulierung-deepfakes-100.html', '2026-06-16 13:32:20+00', 'Europaparlament stimmt für Gesetze zur KI-Regulierung', NULL);
