INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367321638260744, '2026-06-17 12:12:31.755268', 295514619002880, NULL, NULL, '', NULL, NULL, 'The third and final day of the summit will focus on economic growth and digital security. On a Ukraine-focused Tuesday, Trump said he had a "good" meeting with Zelenskyy. Follow DW for more.', NULL, 'https://www.dw.com/en/g7-leaders-discuss-economy-ai-security-risks/live-77556967?maca=en-rss-en-all-1573-rdf', '2026-06-17 05:01:00+00', 'G7: Leaders discuss economy, AI security risks', NULL);
