INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (366960177307648, '2026-06-16 11:41:44.452351', 295500424519680, NULL, 'DIE ZEIT: Wirtschaft - Hella Kemper', 'Wirtschaft', NULL, NULL, 'Die großen Netzbetreiber erzielen hohe Renditen, während Ausbau und Modernisierung der Stromnetze hinterherhinken. Regionale Anbieter profitieren von der Monopolstellung.', '{urn:uuid:4dd2b053-2335-430e-a281-f6b5ed0cccd2}', 'https://www.zeit.de/wirtschaft/2026-06/stromnetzbetreiber-verteilnetz-eigenkapitalrendite-rendite-gxe', '2026-06-16 11:15:05+00', 'Deutsches Stromnetz: Stromnetzbetreiber erzielen Rekordrenditen – Verbraucher zahlen mehr', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (366960177307649, '2026-06-16 11:41:44.452351', 295500424519680, NULL, 'DIE ZEIT: Sport - Caspar Leder', 'Sport', NULL, NULL, 'Tennisstar Serena Williams wird zum ersten Mal seit 2022 wieder am Grand-Slam-Turnier in Wimbledon teilnehmen. Mit ihrer Schwester Venus wird sie im Doppel antreten.', '{urn:uuid:e2f2cdcb-2d63-479c-81c5-4aba16dffcb6}', 'https://www.zeit.de/sport/2026-06/serena-williams-wimbledon-comeback-doppel-wildcard', '2026-06-16 11:06:03+00', 'Tennis: Williams-Schwestern Serena und Venus treten gemeinsam in Wimbledon an', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (366960177307650, '2026-06-16 11:41:44.452351', 295500424519680, NULL, 'DIE ZEIT: Digital - Alena Kammer', 'Digital', NULL, NULL, 'Frankreichs Inlandsgeheimdienst DGSI will bei KI unabhängiger von den USA werden. Dafür sollen Hunderte Millionen Euro in ein eigenes KI-System fließen.', '{urn:uuid:763d3f5c-c897-48fb-b037-1a3c03f9fede}', 'https://www.zeit.de/digital/2026-06/palantir-frankreich-geheimdienst-dgsi-sebastien-lecornu-gxe', '2026-06-16 10:55:07+00', 'US-Unternehmen: Französischer Inlandsgeheimdienst beendet Zusammenarbeit mit Palantir', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (366960177922048, '2026-06-16 11:41:44.602999', 295853820891136, NULL, NULL, '', NULL, NULL, 'Die Übernahme der Commerzbank durch UniCredit wird konkreter. Das freiwillige Angebot der Mailänder Bank läuft um Mitternacht ab - und wie sie selbst darstellt, wird es gut angenommen. Das wirft Fragen auf. Von Ursula Mayer.', 'e1940aeb-9c72-4dc7-a7aa-147c8c78a14d', 'https://www.tagesschau.de/wirtschaft/unternehmen/unicredit-commerzbank-106.html', '2026-06-16 11:29:56+00', 'Streit über UniCredit-Angebot für Commerzbank kurz vor Fristende', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (366960177922049, '2026-06-16 11:41:44.602999', 295853820891136, NULL, NULL, '', NULL, NULL, 'Abdullah Ibrahim prägte mit seiner Musik Generationen und setzte sich zeitlebens gegen Rassismus ein. Nun ist der weltberühmte Jazzpianist im Alter von 91 Jahren im Chiemgau nahe München gestorben. Von Stephan Ueberbach.', 'f7406b56-0043-44b4-817f-dba512e2338c', 'https://www.tagesschau.de/kultur/jazzlegende-ibrahim-verstorben-100.html', '2026-06-16 11:27:54+00', 'Jazzlegende Abdullah Ibrahim mit 91 Jahren gestorben', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (366960177922050, '2026-06-16 11:41:44.602999', 295853820891136, NULL, NULL, '', NULL, NULL, 'Das Rahmenabkommen zum Iran-Krieg ist gerade zwei Tage alt, da gibt es schon heftige Diskussionen. Iran fordert den Abzug Israels aus dem Libanon. Dessen Premier Netanjahu hat das aber bereits abgelehnt. Wie reagieren die USA?', '0a6ee90a-d85a-4664-aa2f-8969fb437ab0', 'https://www.tagesschau.de/ausland/asien/iran-usa-abkommen-libanon-israel-100.html', '2026-06-16 11:00:21+00', 'Scheitert das Iran-Abkommen an der Libanon-Frage?', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (366960177922051, '2026-06-16 11:41:44.602999', 295853820891136, NULL, NULL, '', NULL, NULL, 'Weite Teile der Potsdamer Innenstadt standen am Dienstagvormittag still, weil eine Weltkriegsbombe entschärft werden musste. Tausende Menschen waren von den Evakuierungen betroffen. Nun ist der Sperrkreis wieder freigegeben.', 'tagesschau_fm-story-rbb_potsdam-bombe-entschaerfung-sperrkreis-evakuierung-innenstadt-pendler-hauptbahnhof', 'https://www.tagesschau.de/inland/regional/brandenburg/bombenentschaerfung-potsdam-sperrungen-100.html', '2026-06-16 11:08:15+00', 'Fliegerbombe in Potsdam entschärft', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (366960178540544, '2026-06-16 11:41:44.75399', 295514619002880, NULL, NULL, '', NULL, NULL, 'Three days before his killing, Semyon Skrepetsky had protested outside the Russian embassy in Berlin. He held an icon-like caricature of Russian President Vladimir Putin with Soviet leader Josef Stalin.', NULL, 'https://www.dw.com/en/russian-artist-critical-of-putin-shot-dead-in-poland/a-77576814?maca=en-rss-en-all-1573-rdf', '2026-06-16 11:25:00+00', 'Russian artist critical of Putin shot dead in Poland', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (366960178540545, '2026-06-16 11:41:44.754986', 295514619002880, NULL, NULL, '', NULL, NULL, 'German Chancellor Friedrich Merz has forged relations with Donald Trump, Emmanuel Macron, Keir Starmer and Giorgia Meloni. With some he is surprisingly close.', NULL, 'https://www.dw.com/en/germany-s-merz-who-are-his-international-allies/a-77577111?maca=en-rss-en-all-1573-rdf', '2026-06-16 11:24:00+00', 'Germany''s Merz: Who are his international allies?', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (366960178544640, '2026-06-16 11:41:44.754986', 295514619002880, NULL, NULL, '', NULL, NULL, 'Domestic workers who were mistreated by diplomats are often denied justice due to their abusers enjoying diplomatic immunity. But court rulings in the UK and Switzerland have paved the way for change.', NULL, 'https://www.dw.com/en/diplomats-and-abuse-chipping-at-the-shied-of-immunity/a-77575633?maca=en-rss-en-all-1573-rdf', '2026-06-16 11:20:00+00', 'Diplomats and abuse — chipping at the shied of immunity', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (366960178544641, '2026-06-16 11:41:44.754986', 295514619002880, NULL, NULL, '', NULL, NULL, 'The European Parliament has approved cutting tariffs on many US imports to comply with a deal signed last year. US President Trump had given the bloc a July 4 deadline to meet its side of the deal.', NULL, 'https://www.dw.com/en/european-parliament-approves-us-trade-deal-to-lower-tariffs/a-77577033?maca=en-rss-en-all-1573-rdf', '2026-06-16 11:09:00+00', 'European Parliament approves US trade deal to lower tariffs', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (366960178544642, '2026-06-16 11:41:44.754986', 295514619002880, NULL, NULL, '', NULL, NULL, 'A dip in net migration meant it could not cancel out Germany''s low birth rates in 2025. Meanwhile, fuel prices dip amid news of a possible deal between the US and Iran. And Merz gives Trump a Germany jersey. DW has more.', NULL, 'https://www.dw.com/en/germany-news-population-shrinks-for-first-time-since-covid-induced-dip-in-2020/live-77574042?maca=en-rss-en-all-1573-rdf', '2026-06-16 11:02:00+00', 'Germany news: Population shrinks for first time since COVID-induced dip in 2020', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (366960178544643, '2026-06-16 11:41:44.754986', 295514619002880, NULL, NULL, '', NULL, NULL, 'After starring in Cape Verde''s draw with Spain, goalkeeper Vozinha shared his sadness that an expensive travel bond stopped his mother from attending. On the same day, Iran''s coach said his team were being "oppressed."', NULL, 'https://www.dw.com/en/world-cup-cape-verde-hero-and-iran-suffer-us-travel-woes/a-77574107?maca=en-rss-en-all-1573-rdf', '2026-06-16 10:57:00+00', 'World Cup: Cape Verde hero and Iran suffer US travel woes', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (366960179228672, '2026-06-16 11:41:44.92179', 295880188006400, NULL, NULL, '', NULL, NULL, 'Der Filmwissenschaftler Werner Dütsch (1939-2018) setzte vor allem als WDR-Redakteur Maßstäbe im deutschen Fernsehen, indem er die Umsetzung anspruchsvoller Essay- und Dokumentarfilme ermöglichte und Zugänge zu Filmgeschichte und Gegenwartskino vermittelte. Ein im Jahr seines Todes entstandenes Interview dient als Basis für einen dokumentarischen Abriss seines Lebenswegs, der ihn vom frühen Kino-Enthusiasten über Filmkritik und Filmclub-Bewegung zum Fernsehredakteur führte; bebildert werden die Erinnerungen nicht mit Filmausschnitten, sondern mit Zeichnungen der Regisseurin. So erzählt der Film eine Medien- und Institutionengeschichte nach 1945, erinnert an Meilensteine der Filmpublizistik und -förderung und erschließt Dütschs zahlreiche Verdienste einem nachgeborenen Publikum.', 'https://www.filmdienst.de/film/details/626610/erzahlungen-eines-kinogehers-werner-dutsch', 'https://www.filmdienst.de/film/details/626610/erzahlungen-eines-kinogehers-werner-dutsch', '2026-06-16 10:51:05+00', 'Erzählungen eines Kinogehers - Werner Dütsch', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367002090700800, '2026-06-16 14:32:17.214004', 295500424519680, NULL, 'DIE ZEIT: Ausland - Caspar Leder', 'Ausland', NULL, NULL, 'Das Rote Kreuz hat vor einem langen Kampf gegen den Ebola-Ausbruch gewarnt. Laut der afrikanischen Gesundheitsbehörde könnte dieser unbekannte Ausmaße annehmen.', '{urn:uuid:7fda54ad-5f07-42a1-a73f-147f7b8cb692}', 'https://www.zeit.de/politik/ausland/2026-06/ebola-ausbruch-demokratische-republik-kongo-rotes-kreuz-bruno-michon', '2026-06-16 14:19:57+00', 'Ebola-Ausbruch in Westafrika: Zehntausende Kontakte von Ebola-Infizierten noch nicht identifiziert', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (366960179228673, '2026-06-16 11:41:44.92179', 295880188006400, NULL, NULL, '', NULL, NULL, 'Als der frisch von seiner Ehefrau verlassene Eigentümer eines Möbelhauses einen Spalt entdeckt, der ihn in eine mysteriöse Zwischenwelt aus weiten Räumen und zahlreichen Wegen führt, vertraut er sich seiner Psychotherapeutin an. Gemeinsam mit zwei Mitarbeitern möchte er die Existenz dieses Phänomens beweisen, doch stoßen sie dabei auf schwer fassbare, unheimliche Wesen. Der auf einer Webserie basierende Horrorfilm führt sein Mysterium in unbehaglichen Szenen fort, die sich aus der Verbindung digitaler Konzepte und einer eigentümlichen Vertrautheit speisen. Auch wenn das Geschehen noch ungestümer hätte ausfallen können, entfaltet sich stellenweise eine beeindruckende Intensität.', 'https://www.filmdienst.de/film/details/626286/backrooms', 'https://www.filmdienst.de/film/details/626286/backrooms', '2026-06-16 11:04:30+00', 'Backrooms', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367002092765184, '2026-06-16 14:32:17.7187', 295853820891136, NULL, NULL, '', NULL, NULL, 'Vor wenigen Tagen erst hatte Elon Musk sein Unternehmen SpaceX erfolgreich an die Börse gebracht und sich zum ersten Billionär der Welt gemacht - jetzt der nächste Coup: SpaceX will das KI-Startup Anysphere übernehmen.', '5b07b8f7-eae2-4533-9505-79e8d5113551', 'https://www.tagesschau.de/wirtschaft/technologie/spacex-cursor-uebernahme-100.html', '2026-06-16 14:13:58+00', 'Milliarden-Deal: SpaceX will KI-Startup kaufen', NULL);
