INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367321638260749, '2026-06-17 12:12:31.755268', 295514619002880, NULL, NULL, '', NULL, NULL, 'Russia''s Defense Ministry fired at a boat that made a "dangerous approach." The incident took place outside of UK territorial waters in the English Channel south of the Isle of Wight.', NULL, 'https://www.dw.com/en/russian-ship-fires-warning-shots-at-british-yacht-in-channel/a-77581943?maca=en-rss-en-all-1573-rdf', '2026-06-16 18:47:00+00', 'Russian ship fires warning shots at British yacht in Channel', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367321638260750, '2026-06-17 12:12:31.755268', 295514619002880, NULL, NULL, '', NULL, NULL, 'The EU is poised to ease restrictions on crops developed using novel genetic techniques. While supporters say the technology could help farmers adapt to climate change, critics argue its effects remain poorly understood.', NULL, 'https://www.dw.com/en/crispr-gene-editing-for-crops-precision-tool-or-new-risk/a-77579053?maca=en-rss-en-all-1573-rdf', '2026-06-16 17:44:00+00', 'CRISPR gene-editing for crops: Precision tool or new risk?', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367321638260751, '2026-06-17 12:12:31.755268', 295514619002880, NULL, NULL, '', NULL, NULL, 'Sharia-based inheritance laws continue to disadvantage millions of women across the Middle East. What could prompt real change for the next generation of girls?', NULL, 'https://www.dw.com/en/why-women-s-inheritance-reform-has-stalled-across-arab-world/a-77577835?maca=en-rss-en-all-1573-rdf', '2026-06-16 16:29:00+00', 'Why women''s inheritance reform has stalled across Arab world', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367321638264832, '2026-06-17 12:12:31.756273', 295514619002880, NULL, NULL, '', NULL, NULL, 'The collapse of a Franco-German fighter jet project and a faltering joint battle tank program show how national industrial interests can outweigh common defense objectives.', NULL, 'https://www.dw.com/en/failed-joint-jet-project-highlights-europe-s-defense-dilemma/a-77572732?maca=en-rss-en-all-1573-rdf', '2026-06-16 16:03:00+00', 'Failed joint jet project highlights Europe''s defense dilemma', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367321638961152, '2026-06-17 12:12:31.926225', 295880188006400, NULL, NULL, '', NULL, NULL, 'Robin Hood ist am Ende seines Lebens angelangt. Während seine Legende eines edlen Banditen, der für die Gerechtigkeit eintritt, noch immer verbreitet ist, lebt er mit den Konsequenzen seiner wahren, von Mord und Gewalt geprägten Vergangenheit. Als er bei einem Kampf schwer verletzt wird, gelangt er auf eine Klosterinsel, wo sich eine Nonne seiner annimmt und seine Hoffnung auf Erlösung neu erweckt. Eine düstere Variante der Robin-Hood-Geschichte fernab des Mythos, die konsequent vom Weg aus der Barbarei heraus erzählt und dafür archaisches Pathos wie auch christliche Symbolik bemüht. Historie und Stoff legen dem Film eine besondere Schwere auf, die durch die Aussicht auf Erlösung aufgebrochen wird.', 'https://www.filmdienst.de/film/details/626287/the-death-of-robin-hood', 'https://www.filmdienst.de/film/details/626287/the-death-of-robin-hood', '2026-06-17 07:10:39+00', 'The Death of Robin Hood', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367321638961153, '2026-06-17 12:12:31.926225', 295880188006400, NULL, NULL, '', NULL, NULL, 'Ein charismatischer Motivationstrainer hat mit seinen Shows großen finanziellen Erfolg und viele Anhänger erworben. Als ein Gesetzesentwurf dem Boom selbsternannter Lebenshilfe-Ratgeber einen Riegel vorzuschieben droht, erfindet der Coach eine von Gewalterfahrungen geprägte Kindheit, um seine Sympathiewerte in der Öffentlichkeit zu steigern. Doch das erweist sich ebenso als potenzieller Fallstrick wie ein psychisch labiler Fan. Ein Thriller um einen begnadeten Selbstdarsteller, der ebenso geschäftstüchtig wie von der Wirkung seiner Motivationssprüche aufrichtig überzeugt ist. Sein Absturz in die Paranoia verläuft durchaus effektvoll, wird aber vom Drehbuch nur bedingt glaubhaft motiviert, während Zeitgeistkritik von der Faszination für die schillernde Hauptfigur weitgehend verschluckt wird.', 'https://www.filmdienst.de/film/details/626215/guru', 'https://www.filmdienst.de/film/details/626215/guru', '2026-06-17 07:02:30+00', 'Guru', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367321638961154, '2026-06-17 12:12:31.92725', 295880188006400, NULL, NULL, '', NULL, NULL, 'Eine 25-Jährige hat ihr Studium unterbrochen, um ihrer krebskranken Mutter in den letzten Tagen beistehen zu können. Nach deren Tod muss die junge Frau die Beisetzung allein organisieren, da der Rest der Familie zwar nicht mit Ratschlägen spart, sich bei der Frage nach Mithilfe aber wegduckt. Die Einschränkungen während des Corona-Lockdowns im Frühjahr 2020 kommen als zusätzliche Erschwernis hinzu, den Abschied im Sinne der Verstorbenen zu gestalten. Ein autobiographisch grundiertes und entsprechend detailgenaues, konzentriertes Drama um eine auf sich allein gestellte Protagonistin, die gegen Widerstände und die eigene Überforderung mit der Trauer zu kämpfen hat. Über eine phänomenale Hauptdarstellerin und die geschickte Rückbindung des persönlichen Ausnahmezustandes an die Corona-Zeit nähert sich der Film vielschichtig dem menschlichen Umgang mit dem Tod an.', 'https://www.filmdienst.de/film/details/624900/sechswochenamt', 'https://www.filmdienst.de/film/details/624900/sechswochenamt', '2026-06-17 08:55:29+00', 'Sechswochenamt', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367325703372800, '2026-06-17 12:29:04.214867', 295853820891136, NULL, NULL, '', NULL, NULL, 'Mehr als 80 Jahre nach dem Zweiten Weltkrieg hat Deutschland mehrere während der NS-Besatzung geraubte Kulturgüter an Polen zurückgegeben. Dazu gehören ein historischer Goldring und Eisenbahnmodelle.', '0351012e-a463-4bd0-9ef7-11591b3a391d', 'https://www.tagesschau.de/ausland/europa/deutschland-polen-beziehung-freundschaft-kulturgueter-100.html', '2026-06-17 12:26:42+00', 'Deutschland gibt NS-Raubgut an Polen zurück', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (366962021007360, '2026-06-16 11:49:14.57449', 295853820891136, NULL, NULL, '', NULL, NULL, 'Desinformation, Sabotage und Ausspähaktionen: Durch ein neues Abwehrzentrum soll Deutschland solche hybriden Angriffe künftig schneller bekämpfen können. Denn die Gefahr wachse täglich, warnt Innenminister Dobrindt.', '27109ea4-6671-4e09-82c8-952a81de9e4e', 'https://www.tagesschau.de/inland/abwehrzentrum-hybride-gefahren-100.html', '2026-06-16 11:46:48+00', 'Dobrindt öffnet Zentrum für die Abwehr hybrider Gefahren', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367004785950720, '2026-06-16 14:43:15.234395', 295853820891136, NULL, NULL, '', NULL, NULL, '2025 ist die Zahl der Sozialwohnungen in Deutschland weiter zurückgegangen. Besonders stark betroffen ist Nordrhein-Westfalen. Die Bundesregierung verspricht gegenzusteuern, Kritiker sagen: Die Investitionen reichen nicht.', '366dbe18-4b31-45a7-b940-248be4511ef9', 'https://www.tagesschau.de/wirtschaft/konjunktur/sozialwohnungen-148.html', '2026-06-16 14:35:21+00', 'Zahl der Sozialwohnungen auch 2025 wieder gesunken', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367321638965248, '2026-06-17 12:12:31.92725', 295880188006400, NULL, NULL, '', NULL, NULL, 'Eine fünfköpfige Familie lebt an der isländischen Küste. Während der Vater als Fischer oft auf See ist, hält die Mutter, eine Künstlerin, Alltag und Kinder zusammen. Zwar trennen sie sich, verbringen wegen der Kinder aber weiterhin Zeit miteinander. Zwischen gemeinsamen Mahlzeiten, kleinen Zwistigkeiten und skurrilen Fantasiesequenzen zeigt das stille Drama, wie Vertrautheit auch nach dem Ende der Liebesbeziehung bestehen bleiben kann. Dabei werden Parallelen zwischen der Natur und dem Wesen der Menschen gezogen, ohne sich in dramatischen Wendungen widerzuspiegeln. Stattdessen beobachtet der Film ruhig und mit Humor, wodurch die emotionalen und existenziellen Untertöne umso stärker hervortreten.', 'https://www.filmdienst.de/film/details/624721/the-love-that-remains', 'https://www.filmdienst.de/film/details/624721/the-love-that-remains', '2026-06-17 07:17:13+00', 'The Love That Remains', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367330144399360, '2026-06-17 12:47:08.449165', 295500424519680, NULL, 'DIE ZEIT: Gesellschaft - Sabine Rückert, Andreas Sentker', 'Gesellschaft', NULL, NULL, 'Ein exzellenter Kriminalreporter: Egon Erwin Kisch schrieb vor 100 Jahren über das Verbrechen. Und er schreckte vor nichts zurück.', '{urn:uuid:69523388-0a4a-4436-9982-c0211638dd52}', 'https://www.zeit.de/gesellschaft/2026-06/egon-erwin-kisch-reporter-verbrechen-podcast', '2026-06-17 12:40:24+00', 'Egon Erwin Kisch: Es zog ihn hin zum Mord', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367330144403456, '2026-06-17 12:47:08.450165', 295500424519680, NULL, 'DIE ZEIT: Wirtschaft - Thomas Fischermann, Ileana Grabitz, Marlies Uken, Heike Buchter', 'Wirtschaft', NULL, NULL, 'Die Welt hofft auf einen Durchbruch und die Öffnung der Straße von Hormus. Doch einen Weg zurück zur alten Normalität gibt es nicht mehr.', '{urn:uuid:583baf85-370d-4d90-a742-84cacddba4bc}', 'https://www.zeit.de/2026/27/strasse-von-hormus-schifffahrt-iran-minen', '2026-06-17 12:38:56+00', 'Straße von Hormus: Dauerhaft kaputt', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367330144403457, '2026-06-17 12:47:08.450165', 295500424519680, NULL, 'DIE ZEIT: Ausland - Alexander Eydlin', 'Ausland', NULL, NULL, 'Der russische Künstler Semjon Skrepezki wurde in Polen erschossen. Regierungschef Donald Tusk spekuliert über einen möglichen Auftrag aus Russland.', '{urn:uuid:f92c8cd7-0686-4b80-8a23-b00972ef1db9}', 'https://www.zeit.de/politik/ausland/2026-06/semyon-skrepetsky-russischer-kuenstler-schuesse-polen-donald-tusk', '2026-06-17 12:31:35+00', 'Polen: Tusk nennt Schüsse auf russischen Künstler in Polen »politischen Mord«', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367330144858112, '2026-06-17 12:47:08.561916', 295853820891136, NULL, NULL, '', NULL, NULL, 'Die Farben knallen, das Design ausgefallen: Fußballtrikots sind aus der Modewelt nicht mehr wegzudenken. Auch die großen Sportartikelhersteller reiten auf der Nostalgiewelle. Woher kommt der Hype? Von Emma Luna Velasco Willems.', '83c5f6e2-ed4c-47dc-b424-ca7ab84719ad', 'https://www.tagesschau.de/kultur/fussball-trikots-mode-100.html', '2026-06-17 12:28:19+00', 'Wie Fußballtrikots die Mode erobert haben', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367330145390592, '2026-06-17 12:47:08.691366', 295514619002880, NULL, NULL, '', NULL, NULL, 'As an Iran-US memorandum aimed at ending the war moves closer to formal signature, hardline supporters of the Islamic Republic fear losing influence as Iran''s politics shift from maximalist defiance to compromise.', NULL, 'https://www.dw.com/en/iran-s-hardliners-fear-being-sidelined-in-us-deal/a-77589196?maca=en-rss-en-all-1573-rdf', '2026-06-17 12:36:00+00', 'Iran''s hardliners fear being sidelined in US deal', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367361854279680, '2026-06-17 14:56:10.11952', 295500424519680, NULL, 'DIE ZEIT: Ausland - Leon Ginzel, Hella Kemper, Alexander Eydlin', 'Ausland', NULL, NULL, 'Der französische Präsident Emmanuel Macron betrachtet den G7-Gipfel als einen Moment der Einheit und Zusammenarbeit zwischen den Staats- und Regierungschefs. Das Liveblog', '{urn:uuid:5723c41e-8120-4e74-b7e7-cdca99002193}', 'https://www.zeit.de/politik/ausland/2026-06/g7-evian-genf-proteste', '2026-06-17 14:49:17+00', 'Évian-les-Bains: Macron bezeichnet G7-Gipfel als Erfolg', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367667221536773, '2026-06-18 11:38:42.672877', 295853820891136, NULL, NULL, '', NULL, NULL, 'Andy Burnham hat große Pläne - er will den angeschlagenen Premier Starmer herausfordern. Dafür muss Burnham heute aber zunächst die Nachwahl in Makerfield gewinnen. Denn nur mit einem Mandat kann er Starmer den Parteivorsitz streitig machen. Von Christoph Prössl.', '5c0e7457-e685-4111-9f75-abd49f865eb6', 'https://www.tagesschau.de/ausland/europa/wahlkampf-makerfield-100.html', '2026-06-18 04:07:35+00', 'Entscheidender Tag für Starmer: Schicksalswahl in Makerfield', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367667221536774, '2026-06-18 11:38:42.672877', 295853820891136, NULL, NULL, '', NULL, NULL, 'Die USA und Iran haben die Absichtserklärung für ein Konfliktende unterzeichnet - früher als geplant. US-Präsident Trump unterschrieb in Versailles, Iran digital. Laut Pakistan soll die Straße von Hormus geöffnet werden.', 'f430e006-7be2-4c5d-a2d2-23ddb7f553d5', 'https://www.tagesschau.de/ausland/vereinbarung-usa-iran-unterzeichnet-100.html', '2026-06-18 02:03:18+00', 'USA und Iran haben Rahmenabkommen bereits unterzeichnet', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367667221536775, '2026-06-18 11:38:42.672877', 295853820891136, NULL, NULL, '', NULL, NULL, 'Die Absichtserklärung zwischen den USA und Iran ist unterzeichnet. Bereits vorab berichten einige Medien über mehrere Punkte, auf die sich die beiden Länder geeinigt haben sollen - bestätigt von einem US-Beamten.', '3cb90810-caab-46ba-af7c-dbb2638d4d5e', 'https://www.tagesschau.de/ausland/amerika/abkommen-usa-iran-100.html', '2026-06-17 23:25:54+00', 'Was in der Absichtserklärung zwischen den USA und Iran steht', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367667221536776, '2026-06-18 11:38:42.672877', 295853820891136, NULL, NULL, '', NULL, NULL, 'Es ist die erste Zinsentscheidung unter dem neuen Fed-Chef Warsh: Der US-Leitzins bleibt unverändert und liegt weiter bei 3,5 bis 3,75 Prozent. Präsident Trump geht mit seinen Forderungen nach Zinssenkungen leer aus.', '5cc265d5-7fae-4828-a28a-08560d928f67', 'https://www.tagesschau.de/wirtschaft/fed-leitzins-154.html', '2026-06-17 20:00:47+00', 'US-Notenbank lässt Leitzins unverändert', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367667221536777, '2026-06-18 11:38:42.673878', 295853820891136, NULL, NULL, '', NULL, NULL, 'Künstliche Intelligenz ist auf dem Vormarsch - und macht auch vor der Politik nicht halt. Kaum ein Redenschreiber arbeitet ohne KI: Was bedeutet das für die Politik und für innovative Ideen? Von Frank Aischmann.', 'bd52574d-877b-4b6f-8224-30cccdaa1bcb', 'https://www.tagesschau.de/inland/innenpolitik/ki-politik-reden-100.html', '2026-06-17 18:40:43+00', 'Wie viel KI verträgt die deutsche Politik?', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367667221540864, '2026-06-18 11:38:42.673878', 295853820891136, NULL, NULL, '', NULL, NULL, 'Dass der G7-Gipfel zum Erfolg wurde, liegt vor allem an US-Präsident Trump, meint Julia Borutta. Das Treffen könnte die Wende gewesen sein - für die Ukraine und für das Verhältnis der Europäer zu den USA. Doch sicher ist nichts.', '9bbea157-bed3-4388-80f0-7463827ad197', 'https://www.tagesschau.de/kommentar/trump-g7-gipfel-100.html', '2026-06-17 18:36:43+00', 'G7-Gipfel: Die Lage bleibt fragil', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367667221540865, '2026-06-18 11:38:42.673878', 295853820891136, NULL, NULL, '', NULL, NULL, 'Zahlungen mit Karte oder Smartphone werden in Deutschland immer üblicher. Erstmals zahlten Verbraucher vergangenes Jahr häufiger bargeldlos als mit Scheinen oder Münzen, wie eine Bundesbank-Studie zeigt. Von Ursula Mayer.', 'e7dc0c8d-3f40-4e01-89bb-e1c41ebf1826', 'https://www.tagesschau.de/wirtschaft/finanzen/bargeld-studie-bundesbank-100.html', '2026-06-17 17:06:38+00', 'Bundesbank-Studie: Deutsche zahlen meistens ohne Bargeld', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367331677360128, '2026-06-17 12:53:22.707568', 295500424519680, NULL, 'DIE ZEIT: Politik - Leon Ginzel', 'Politik', NULL, NULL, 'Ein zufriedener Kanzler hebt beim G7-Gipfel die geschlossene Haltung zur Ukraine hervor. Merz spricht von einem »gemeinsamen Geist« – und schließt Trump dabei mit ein.', '{urn:uuid:23e55858-ff92-475d-bb12-d87b944b8acc}', 'https://www.zeit.de/politik/2026-06/g7-gipfel-friedrich-merz-russland-sanktionen-ruestung', '2026-06-17 12:51:56+00', 'G7-Gipfel: Kanzler Merz lobt »klare Botschaft« der G7-Staaten an Russland', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367364346191872, '2026-06-17 15:06:18.496297', 295500424519680, NULL, 'DIE ZEIT: Ausland - Hauke Friederichs', 'Ausland', NULL, NULL, 'Auf der Rüstungsmesse Eurosatory in Paris dominieren alte Waffensysteme. Die Firmen zeigen genau das, was europäische Streitkräfte bestellen – und das ist das Problem.', '{urn:uuid:d85f8c30-677e-4a6c-a452-28e5570c0e33}', 'https://www.zeit.de/politik/ausland/2026-06/eurosatory-paris-ruestung-messe-armee', '2026-06-17 15:01:58+00', 'Eurosatory 2026: Bereit für den Krieg von gestern', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367364346195968, '2026-06-17 15:06:18.497297', 295500424519680, NULL, 'DIE ZEIT: Musik - Magdalena Inou', 'Musik', NULL, NULL, 'Timmy und Puccini. Eine Oper kreist in Berlin um unseren liebsten verstorbenen Wal. Anders als dieser explodiert die Inszenierung in tausend Einzelteile.', '{urn:uuid:673aab59-8c49-4cab-8e6d-dd6f008e00e2}', 'https://www.zeit.de/feuilleton/musik/2026-06/deutsches-theater-berlin-oper-gesang-pottwal-openair', '2026-06-17 15:00:49+00', 'Deutsches Theater: Zu Tode gerettet', NULL);
