INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367364346200064, '2026-06-17 15:06:18.498295', 295500424519680, NULL, 'DIE ZEIT: Wirtschaft - Thomas Fischermann, Johanna Jürgens, Jakob von Lindern, Heike Buchter', 'Wirtschaft', NULL, NULL, 'Die US-Regierung verbietet Ausländern, die fortschrittlichste KI der Welt zu nutzen. Das macht Europa nervös. Und plötzlich wirkt eine Idee gar nicht mehr so abwegig.', '{urn:uuid:d138894d-ff8d-47bb-bb90-e972cc8e302b}', 'https://www.zeit.de/2026/27/anthropic-exportverbot-ki-modelle-claude-mythos-fable-usa', '2026-06-17 14:51:41+00', 'Anthropic: Zugriff ab sofort verweigert', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367364346200065, '2026-06-17 15:06:18.498295', 295500424519680, NULL, 'DIE ZEIT: Feuilleton - Götz Hamann', 'Feuilleton', NULL, NULL, 'Mit 94 Jahren überarbeitet der Designer Dieter Rams noch einmal seine schönste Türklinke. Da freut sich nicht nur der Daumen.', '{urn:uuid:9f7d1afa-3e4f-4746-bceb-c46d054478e9}', 'https://www.zeit.de/2026/27/dieter-rams-tuerklinke-rgs-fsb', '2026-06-17 14:51:39+00', 'Dieter Rams: Lass dich drücken', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (366963153711104, '2026-06-16 11:53:51.113678', 295500424519680, NULL, 'DIE ZEIT: Ausland - Isabelle Daniel, Claudia Thaler', 'Ausland', NULL, NULL, 'Dem US-Präsidenten zufolge darf der Iran »niemals« Atomwaffen haben. Putin ruft er zu Friedensverhandlungen auf. Arabische Staatschefs bei G7 eingetroffen. Das Liveblog', '{urn:uuid:5723c41e-8120-4e74-b7e7-cdca99002193}', 'https://www.zeit.de/politik/ausland/2026-06/g7-evian-genf-proteste', '2026-06-16 11:49:44+00', 'Évian-les-Bains: Donald Trump kündigt bei G7-Gipfel »zweite Phase« von Iranabkommen an', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367364346769408, '2026-06-17 15:06:18.637556', 295853820891136, NULL, NULL, '', NULL, NULL, 'Bis in die 1950er-Jahre entrissen belgische Kolonialisten im Gebiet der heutigen Demokratischen Republik Kongo Kinder ihren Müttern. Jetzt muss Belgien zum ersten Mal Opfer kolonialer Gewalt entschädigen. Von M. Krasenbrink.', 'fad2f333-02dd-49b1-aa1b-236c925f78df', 'https://www.tagesschau.de/ausland/europa/kolonialverbrechen-belgien-kongo-100.html', '2026-06-17 15:00:02+00', 'Belgien muss erstmals Opfer von Kolonialverbrechen entschädigen', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367364346769409, '2026-06-17 15:06:18.637556', 295853820891136, NULL, NULL, '', NULL, NULL, 'Die Ölvorräte der Industriestaaten sind infolge des Iran-Kriegs auf den tiefsten Stand seit Jahrzehnten gefallen. Gleichzeitig erwartet die Internationalen Energieagentur den stärksten Rückgang der weltweiten Nachfrage seit der Corona-Pandemie.', 'cd5429c9-1a63-4e5c-b6bc-ff082a9b2513', 'https://www.tagesschau.de/wirtschaft/weltwirtschaft/oelreserven-iea-iran-hormus-russland-100.html', '2026-06-17 14:59:23+00', 'Iran-Krieg drückt Ölvorräte auf tiefsten Stand seit 1990', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (366963153719296, '2026-06-16 11:53:51.115168', 295500424519680, NULL, 'DIE ZEIT: Sport - Leon Ginzel, Eric Voigt', 'Sport', NULL, NULL, 'Pro Tag zwei WM-Spiele, bequem im Privatjet – die Reisepläne von Gianni Infantino erzürnen Greenpeace. Nach dem Schweden-Debakel feuert Tunesien den Trainer. Das Liveblog', '{urn:uuid:e528ca8b-f67f-493e-b77e-30d2cb57e930}', 'https://www.zeit.de/sport/2026-05/fussball-wm-2026-liveblog', '2026-06-16 11:47:57+00', 'Fußball-WM 2026: Greenpeace kritisiert Fifa-Chef Infantino für Privatjet-Pläne', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367364346769410, '2026-06-17 15:06:18.637556', 295853820891136, NULL, NULL, '', NULL, NULL, '"Backrooms" ist ein Low-Budget-Projekt, das einen Nerv trifft. Aus einem vergilbten Internetfoto entsteht ein Horrorfilm, den schon mehr als 20 Millionen Menschen gesehen haben. Jetzt läuft er auch bei uns im Kino. Von B. Geschwinde.', 'bd49c0b3-bf86-4b12-9e98-f4f59e8f0a24', 'https://www.tagesschau.de/kultur/backrooms-100.html', '2026-06-17 14:58:18+00', 'Filmstart von "Backrooms": Verschwunden in gelben Fluren', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367667221540866, '2026-06-18 11:38:42.673878', 295853820891136, NULL, NULL, '', NULL, NULL, 'Im Supermarkt dürfen künftig bestimmte genveränderte Lebensmittel ohne Kennzeichnung im Regal stehen. In rund zwei Jahren sollen die Regeln gelten. Was genau ist geplant? Und welche Reaktionen gibt es?', 'a5407182-bbd3-4a3a-a410-63911cc2d646', 'https://www.tagesschau.de/faq-eu-gentechnik-100.html', '2026-06-17 17:05:59+00', 'Was bedeuten die neuen EU-Regeln zu Gentechnik?', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367667221540867, '2026-06-18 11:38:42.673878', 295853820891136, NULL, NULL, '', NULL, NULL, 'Bundeskanzler Merz lobt die "gemeinsame Sprache", Frankreichs Präsident Macron spricht vom "strategischen Erwachen": Die Erleichterung über den Verlauf des G7-Treffens ist spürbar. Das liegt vor allem an einem Teilnehmer. Von Kathrin Schmid.', '8f67cb4c-8950-4a64-a25f-c4bd0ac0f423', 'https://www.tagesschau.de/ausland/g7-evian-bilanz-100.html', '2026-06-17 16:47:43+00', 'Merz und Macron loben G7-Gipfel als Erfolg', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367667221540868, '2026-06-18 11:38:42.673878', 295853820891136, NULL, NULL, '', NULL, NULL, 'Deutschland und Polen haben ein Verteidigungsabkommen unterschrieben. Damit wollen beide Länder gegenseitigen Beistand bekräftigen und die Zusammenarbeit im Militärbereich ausbauen. Aus Warschau berichtet Palina Milling.', '7c6af40d-1fc9-4941-b2a0-05f431bfeaab', 'https://www.tagesschau.de/ausland/europa/verteidigungsabkommen-warschau-100.html', '2026-06-17 16:34:55+00', 'Pistorius unterzeichnet Verteidigungsabkommen in Warschau', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367667221540869, '2026-06-18 11:38:42.673878', 295853820891136, NULL, NULL, '', NULL, NULL, 'Vor dem Zinsentscheid der US-Notenbank bewegt sich der DAX seitwärts. BMW schockt mit einer Gewinnwarnung, die Commerzbank klettert an die Spitze des Leitindex.', '9f6228e4-de19-4cb6-97bb-571c48d58d0f', 'https://www.tagesschau.de/wirtschaft/finanzen/marktberichte/marktbericht-dow-dax-100.html', '2026-06-17 16:13:43+00', 'Anleger halten sich vor Fed-Entscheidung zurück', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367667221540870, '2026-06-18 11:38:42.673878', 295853820891136, NULL, NULL, '', NULL, NULL, 'Nach dem G7-Gipfel hat Bundeskanzler Merz im ARD-Interview eine positive Bilanz gezogen. Auf die Entwicklung in der Straße von Hormus blickt er zuversichtlich. Und für Präsident Trump hatte er viel Lob übrig.', '591a3f6a-bae6-4b03-82b8-b0003b2695ac', 'https://www.tagesschau.de/ausland/europa/merz-evian-g7-interview-100.html', '2026-06-17 16:00:28+00', 'Merz wertet Ergebnisse des G7-Gipfels als Erfolg', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367334122868736, '2026-06-17 13:03:19.755006', 295853820891136, NULL, NULL, '', NULL, NULL, 'Ravensburger steigt beim Plüschtierhersteller Steiff ein. Gemeinsam solle die weltweite Expansion vorangetrieben werden - und zwei der bekanntesten deutschen Spielwarenhersteller sind künftig eng verflochten.', 'cee962b4-f2df-48a3-a3a3-21920697681f', 'https://www.tagesschau.de/wirtschaft/unternehmen/ravensburger-uebernahme-steiff-100.html', '2026-06-17 12:58:58+00', 'Ravensburger übernimmt Mehrheit bei Plüschtier-Hersteller Steiff', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367365333872640, '2026-06-17 15:10:19.629568', 295500424519680, NULL, 'DIE ZEIT: Politik - Azadê Peşmen', 'Politik', NULL, NULL, 'Der Vorsitzende der Innenministerkonferenz fordert niedrigere Hürden für Abschiebungen. Bringt das mehr Sicherheit? Und: Meldestellen zählen mehr antisemitische Vorfälle.', '{urn:uuid:979dbb29-fdfe-4e0b-b2dc-dcc208685edb}', 'https://www.zeit.de/politik/2026-06/innenministerkonferenz-hamburg-migrationspolitik-nachrichtenpodcast', '2026-06-17 15:08:01+00', 'Innenministerkonferenz: Schiebt Deutschland bald mehr straffällige Geflüchtete ab?', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367365333872641, '2026-06-17 15:10:19.629568', 295500424519680, NULL, 'DIE ZEIT: Sinn - Tom Kroll', 'Sinn', NULL, NULL, 'Im niederländischen Kampen lebt eine Familie im Kirchenasyl. Die Gemeinde schützt sie mit einem Gottesdienst, durchgehend, seit über 500 Tagen. Doch wer hilft hier wem?', '{urn:uuid:efb3de5e-b2f2-4e98-b6f8-1b863d661338}', 'https://www.zeit.de/2026/26/kirchenasyl-niederlande-kampen-familie-usbekistan-gottesdienst', '2026-06-17 15:04:54+00', 'Kirchenasyl in den Niederlanden: 14.000 Stunden beten', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367667221544960, '2026-06-18 11:38:42.674887', 295853820891136, NULL, NULL, '', NULL, NULL, 'Die Zahl antisemitisch motivierter Vorfälle in Deutschland ist weiter hoch: 2025 verzeichneten die RIAS-Meldestellen insgesamt 8.725 Fälle. Immer mehr Anfeindungen und Bedrohungen werden in den sozialen Medien registriert. Von J.-B. Nickschas.', '55ca0c40-2992-4790-94cf-3b5476134818', 'https://www.tagesschau.de/inland/gesellschaft/rias-antisemitismus-104.html', '2026-06-17 15:37:36+00', 'Zahl antisemitischer Vorfälle verharrt auf hohem Niveau', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367667221544961, '2026-06-18 11:38:42.674887', 295853820891136, NULL, NULL, '', NULL, NULL, 'Das Bayerische Landesamt für Verfassungsschutz darf die AfD beobachten. Das hat der Bayerische Verwaltungsgerichtshof entschieden. Er begründete die Entscheidung unter anderem mit der Parteilinie zur "Remigration".', 'tagesschau_fm-story-br24-VMmpava', 'https://www.tagesschau.de/inland/regional/bayern/bayern-verfassungsschutz-afd-100.html', '2026-06-17 17:05:36+00', 'Urteil: Verfassungsschutz darf AfD in Bayern beobachten', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367667222069248, '2026-06-18 11:38:42.802752', 295514619002880, NULL, NULL, '', NULL, NULL, 'Prime Minister Donald Tusk says Lublin police arrested a suspect in the fatal shooting of the Russian national and critical artist known as Semyon Skrepetsky. He said investigators were still seeking a "mastermind."', NULL, 'https://www.dw.com/en/poland-arrest-after-russian-artist-and-putin-critic-killed/a-77602774?maca=en-rss-en-all-1573-rdf', '2026-06-18 10:47:00+00', 'Poland: Arrest after Russian artist and Putin critic killed', NULL);
