INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367667222069251, '2026-06-18 11:38:42.802752', 295514619002880, NULL, NULL, '', NULL, NULL, 'A strong option at left back is overdue for Germany. Nathaniel Brown is quickly becoming a star at the World Cup.', NULL, 'https://www.dw.com/en/nathaniel-brown-the-left-back-germany-have-been-waiting-for/a-77582557?maca=en-rss-en-all-1573-rdf', '2026-06-18 09:42:00+00', 'Nathaniel Brown: The left back Germany have been waiting for', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367667222069252, '2026-06-18 11:38:42.802752', 295514619002880, NULL, NULL, '', NULL, NULL, 'Cuba''s Communist Party has signed off on a package of free market reforms. One member called the changes a response to "economic war," while the party said they were not a "deviation" from the socialist project.', NULL, 'https://www.dw.com/en/cuba-approves-economic-reforms-amid-us-pressure/a-77597635?maca=en-rss-en-all-1573-rdf', '2026-06-18 09:12:00+00', 'Cuba approves economic reforms amid US pressure', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367667222069253, '2026-06-18 11:38:42.802752', 295514619002880, NULL, NULL, '', NULL, NULL, 'A new study shows the decline was due to weaker hiring activity rather than redundancies. And at the World Cup, Germany may be taking a break but German coaches are in the thick of the action. DW has more.', NULL, 'https://www.dw.com/en/germany-news-industrial-employment-falls-to-decade-low/live-77599561?maca=en-rss-en-all-1573-rdf', '2026-06-18 09:01:00+00', 'Germany news: Industrial employment falls to decade low', NULL);
