INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367667222073346, '2026-06-18 11:38:42.803833', 295514619002880, NULL, NULL, '', NULL, NULL, 'German Foreign Minister Johann Wadephul, in an interview with DW, underscores the trans-Atlantic partnership, close cooperation with Poland, continued support for Ukraine and European unity.', NULL, 'https://www.dw.com/en/germany-s-foreign-minister-european-unity-is-decisive/a-77594952?maca=en-rss-en-all-1573-rdf', '2026-06-18 06:34:00+00', 'Germany''s foreign minister: ''European unity is decisive''', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367667222073347, '2026-06-18 11:38:42.803833', 295514619002880, NULL, NULL, '', NULL, NULL, 'Ukraine hit Moscow''s refinery while Kyiv was hit by Russian missiles. The attacks come as Zelenskyy intensified efforts to end the war.', NULL, 'https://www.dw.com/en/russia-ukraine-trade-strikes-as-zelenskyy-talks-with-trump/a-77597307?maca=en-rss-en-all-1573-rdf', '2026-06-18 06:23:00+00', 'Russia, Ukraine trade strikes as Zelenskyy talks with Trump', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367667222073348, '2026-06-18 11:38:42.803833', 295514619002880, NULL, NULL, '', NULL, NULL, 'US President Donald Trump and Iranian President Masoud Pezeshkian have signed an initial agreement to extend the ceasefire for another 60 days and reopen the Strait of Hormuz. DW has the latest.', NULL, 'https://www.dw.com/en/trump-pezeshkian-sign-deal-to-end-iran-war-reopen-hormuz/live-77596195?maca=en-rss-en-all-1573-rdf', '2026-06-17 23:19:00+00', 'Trump, Pezeshkian sign deal to end Iran war, reopen Hormuz', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367667222073349, '2026-06-18 11:38:42.803833', 295514619002880, NULL, NULL, '', NULL, NULL, 'US officials have released an interim agreement that ends fighting on all fronts for 60 days and sets out provisions for the reopening of the Strait of Hormuz.', NULL, 'https://www.dw.com/en/what-s-in-the-14-point-us-iran-peace-plan/a-77595563?maca=en-rss-en-all-1573-rdf', '2026-06-17 21:01:00+00', 'What''s in the 14-point US-Iran peace plan?', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367339347099648, '2026-06-17 13:24:35.202086', 295853820891136, NULL, NULL, '', NULL, NULL, 'Ein russisches Kriegsschiff gibt im Ärmelkanal Warnschüsse ab - angeblich, weil eine Jacht auf Kollisionskurs war. Die Segler beschreiben den Fall anders. In Großbritannien wird der Fall breit diskutiert. Von Christoph Prössl, ARD London', '36edda88-6629-4ad1-9c39-8692b5df8038', 'https://www.tagesschau.de/ausland/europa/warnschuesse-aermelkanal-russisches-kriegsschiff-100.html', '2026-06-17 13:12:28+00', 'Was steckt hinter den russischen Warnschüssen im Ärmelkanal?', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367366908608512, '2026-06-17 15:16:44.086778', 297942154895360, NULL, NULL, '', NULL, NULL, 'Die EU lockert die Regeln für bestimmte gentechnisch veränderte Pflanzen. Das macht den Weg frei für mehr Versuche, Kulturpflanzen an Klimaveränderungen anzupassen, sagt Robert Hoffie vom Leibniz-Institut für Pflanzengenetik. Nicht alle wollen das. Büüsker, Ann-Kathrin; Hoffie, Robert; Küpper, Moritz', 'neue-gentechnik-sorgen-und-hoffnungen-100', 'https://www.deutschlandfunk.de/neue-gentechnik-sorgen-und-hoffnungen-100.html', '2026-06-17 09:36:00+00', 'Moderne Gentechnik - Hoffnung in der Forschung, Sorgen bei Kritikern', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367667222073350, '2026-06-18 11:38:42.803833', 295514619002880, NULL, NULL, '', NULL, NULL, 'The EU is backing tougher migration policies that seek to ramp up deportations of failed asylum-seekers. Under the new legislation, EU states can establish "return hubs."', NULL, 'https://www.dw.com/en/eu-lawmakers-approve-new-tougher-migrant-policy/a-77595342?maca=en-rss-en-all-1573-rdf', '2026-06-17 19:33:00+00', 'EU lawmakers approve new tougher migrant policy', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367667222073351, '2026-06-18 11:38:42.803833', 295514619002880, NULL, NULL, '', NULL, NULL, 'The Federal Association of Departments for Research and Information on Antisemitism (RIAS) recorded over 8,700 cases they classify as antisemitic hostility in 2025, many of which were connected with the State of Israel.', NULL, 'https://www.dw.com/en/germany-reports-of-antisemitism-in-2025-remain-high/a-77593695?maca=en-rss-en-all-1573-rdf', '2026-06-17 17:41:00+00', 'Germany: Reports of antisemitism in 2025 remain high', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367667222073352, '2026-06-18 11:38:42.803833', 295514619002880, NULL, NULL, '', NULL, NULL, 'G7 leaders called for a "strong and coordinated response" to the latest Ebola outbreak. The EU''s Ursula von der Leyen said that "health security is shared security." The recorded death toll in DRC is approaching 200.', NULL, 'https://www.dw.com/en/eu-g7-pledge-support-amid-drc-ebola-outbreak/a-77588901?maca=en-rss-en-all-1573-rdf', '2026-06-17 15:56:00+00', 'EU, G7 pledge support amid DRC Ebola outbreak', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367678772944896, '2026-06-18 12:25:42.840136', 295500424519680, NULL, 'DIE ZEIT: Ausland - Caspar Leder', 'Ausland', NULL, NULL, 'Die EU-Kommission hat entschieden, dass der Bund beim Rüstungskonzern KNDS einsteigen darf. Deutschland soll so die gleichen Rechte bekommen wie Frankreich.', '{urn:uuid:bd87c7b8-3c94-4ba0-a33b-aebfbb423ad2}', 'https://www.zeit.de/politik/ausland/2026-06/knds-bundesbeteiligung-frankreich-leopard-2-gxe', '2026-06-18 12:22:58+00', 'Rüstungskonzern KNDS: Bund darf bei Leopard-2-Hersteller KNDS einsteigen', NULL);
