INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367321636057088, '2026-06-17 12:12:31.217857', 297940250853376, NULL, NULL, '', NULL, NULL, 'Ein Mittel gegen die Wohnungsknappheit könnte der Umbau leer stehender Bürogebäude in Wohnungen sein. Immerhin stehen elf Millionen Quadratmeter Bürofläche leer. Investoren werden dabei aber eher Miniapartments als Familienwohnungen im Sinn haben.', 'wohnungsmangel-bueros-umbau-wohnungen-bauturbo-100', 'https://www.deutschlandfunk.de/wohnungsmangel-bueros-umbau-wohnungen-bauturbo-100.html', '2026-06-17 11:19:00+00', 'Wohnungsmarkt - Umbau von Büros zu Wohnungen: Nur eine Teillösung', NULL);
