INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367667220357120, '2026-06-18 11:38:42.384458', 297942154895360, NULL, NULL, '', NULL, NULL, 'Heute Abend steht der Mond am Westhimmel – rechts von ihm strahlen die Planeten Venus und Jupiter. Im Moment ist die uns zugewandte Seite des Mondes nur wenig beleuchtet – dafür liegt die Rückseite fast vollständig im Sonnenlicht. Lorenzen, Dirk', 'sternzeit-18-juni-2026-die-helle-dunkle-seite-des-mondes-100', 'https://www.deutschlandfunk.de/sternzeit-18-juni-2026-die-helle-dunkle-seite-des-mondes-100.html', '2026-06-18 00:57:41+00', 'Neumond - Wenn auf der dunklen Seite des Mondes die Sonne scheint', NULL);
