INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367667221057540, '2026-06-18 11:38:42.555608', 295500424519680, NULL, 'DIE ZEIT: Ausland - Iven Yorick Fenker', 'Ausland', NULL, NULL, 'Ein AfD-Politiker soll in Rostock angegriffen worden sein. Der Vorsitzende der Landtagsfraktion der Partei spricht von einem »Angriff auf die demokratische Grundordnung«.', '{urn:uuid:6e2b48fa-8e2a-4f05-8420-c7ce1b0f1055}', 'https://www.zeit.de/politik/ausland/2026-06/michael-meister-afd-angriff-rostock-gxe', '2026-06-18 11:21:59+00', 'Mecklenburg-Vorpommern: Ermittlungen nach mutmaßlichem Angriff auf AfD-Politiker in Rostock', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (366927131668480, '2026-06-16 09:27:16.669824', 297940250853376, NULL, NULL, '', NULL, NULL, 'Algen werden zunehmend als nützlicher Rohstoff wahrgenommen. Sie stecken bereits in Nahrungsmitteln und könnten künftig Plastik ersetzen oder als Kraftstoff verwendet werden. Außerdem speichern sie CO2 und schützen dadurch das Klima.', 'algen-klimawandel-co2-speicher-rohstoff-zukunft-100', 'https://www.deutschlandfunk.de/algen-klimawandel-co2-speicher-rohstoff-zukunft-100.html', '2026-06-13 08:10:00+00', 'Klimawandel - Warum Algen gut fürs Klima sind', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367351545372672, '2026-06-17 14:14:13.296181', 295514619002880, NULL, NULL, '', NULL, NULL, 'Hosting the 2030 World Cup is more than just a sporting event for Rabat. While the kingdom invests heavily in infrastructure and prestige projects, doubts and social conflicts grow alongside a sense of pride and hope.', NULL, 'https://www.dw.com/en/morocco-the-2030-world-cup-is-more-than-sports-it-is-a-national-project/a-77589339?maca=en-rss-en-all-1573-rdf', '2026-06-17 14:01:00+00', 'Morocco: The 2030 World Cup is more than sports, it is a national project', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367351545372673, '2026-06-17 14:14:13.296181', 295514619002880, NULL, NULL, '', NULL, NULL, 'Domestic workers who were mistreated by diplomats are often denied justice due to their abusers enjoying diplomatic immunity. But court rulings in the UK and Switzerland have paved the way for change.', NULL, 'https://www.dw.com/en/diplomats-and-abuse-chipping-at-the-shield-of-immunity/a-77575633?maca=en-rss-en-all-1573-rdf', '2026-06-17 14:00:00+00', 'Diplomats and abuse — chipping at the shield of immunity', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (366927132704768, '2026-06-16 09:27:16.922751', 297942154895360, NULL, NULL, '', NULL, NULL, 'Bis übermorgen präsentiert sich das abendliche Firmament so schön wie selten. Die hellen Planeten Jupiter und Venus sind Himmelsfans vertraut – nun gesellt sich auch noch die Mondsichel dazu. Zudem funkelt dort ein heller Stern. Lorenzen, Dirk', 'sternzeit-16-juni-2026-die-himmlische-viererkette-des-jahres-102', 'https://www.deutschlandfunk.de/sternzeit-16-juni-2026-die-himmlische-viererkette-des-jahres-102.html', '2026-06-16 00:57:09+00', 'Mond, Venus, Jupiter - Die himmlische Viererkette des Jahres', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (366927132704769, '2026-06-16 09:27:16.922751', 297942154895360, NULL, NULL, '', NULL, NULL, 'Angenommen, die Relativitätstheorie gäbe es nicht - könnte eine KI sie entdecken? Darüber wird gestritten. Fakt ist: Die KI übernimmt das Forschen. Manche meinen, es sei nur noch eine Frage der Zeit, bis dabei nobelpreiswürdige Erfolge herauskommen. Drösser, Christoph', 'kuenstliche-intelligenz-uebernimmt-forschung-nobelpreis-100', 'https://www.deutschlandfunk.de/kuenstliche-intelligenz-uebernimmt-forschung-nobelpreis-100.html', '2026-06-15 06:00:00+00', 'Nobelpreis für die KI - Künstliche Intelligenz übernimmt das Forschen', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (366927132704770, '2026-06-16 09:27:16.922751', 297942154895360, NULL, NULL, '', NULL, NULL, 'Das Team der Artemis-2-Mission hat im April beim Flug um den Mond eine Sonnenfinsternis erlebt. Fast eine Stunde lang zog die Kapsel durch den Schatten des Mondes – auf der Erde dauert so ein Schauspiel maximal sieben Minuten. Lorenzen, Dirk', 'sternzeit-15-juni-2026-sonnenfinsternis-hinter-dem-mond-100', 'https://www.deutschlandfunk.de/sternzeit-15-juni-2026-sonnenfinsternis-hinter-dem-mond-100.html', '2026-06-15 00:05:09+00', 'Neumond - Sonnenfinsternis hinter dem Mond', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (366927132704771, '2026-06-16 09:27:16.922751', 297942154895360, NULL, NULL, '', NULL, NULL, 'Der erste Weltmeisterschaftsgegner der deutschen Männer-Nationalmannschaft gehört fußballerisch wie astronomisch in die Rubrik „ferner liefen“. Ein himmlisches Highlight war dort die totale Sonnenfinsternis im Februar 1998. Lorenzen, Dirk', 'sternzeit-14-juni-2026-der-karibik-himmel-ueber-cura-ao-100', 'https://www.deutschlandfunk.de/sternzeit-14-juni-2026-der-karibik-himmel-ueber-cura-ao-100.html', '2026-06-14 00:05:14+00', 'WM-Gegner - Der Karibik-Himmel über Curaçao', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (366927132708864, '2026-06-16 09:27:16.923753', 297942154895360, NULL, NULL, '', NULL, NULL, 'Die EU erwägt ein Verbot von per- und polyfluorierten Alkylsubstanzen (PFAS). Zu Recht? Darüber diskutieren Frauke Averbeck von der Bundesanstalt für Arbeitsschutz und Arbeitsmedizin mit Sarah Brückner vom Verband Deutscher Maschinen- und Anlagenbau. Neumeier, Claudia', 'sollten-pfas-in-der-eu-verboten-werden-frauke-averbeck-vs-sarah-brueckner-100', 'https://www.deutschlandfunk.de/sollten-pfas-in-der-eu-verboten-werden-frauke-averbeck-vs-sarah-brueckner-100.html', '2026-06-13 15:05:00+00', 'Giftige Chemikalien - Das Für und Wider eines PFAS-Verbots in Europa', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (366927132708865, '2026-06-16 09:27:16.923753', 297942154895360, NULL, NULL, '', NULL, NULL, 'Seit mehr als drei Milliarden Jahren gibt es Leben auf unserer Erde. Unklar ist, wie es sich gebildet hat. Wurden auf der jungen Erde aus chemischen Prozessen irgendwann biologische? Oder haben einst Asteroiden Lebenskeime angeliefert? Lorenzen, Dirk', 'sternzeit-13-juni-2026-kam-das-leben-aus-den-tiefen-des-alls-100', 'https://www.deutschlandfunk.de/sternzeit-13-juni-2026-kam-das-leben-aus-den-tiefen-des-alls-100.html', '2026-06-13 00:05:16+00', 'Panspermie-Idee - Kam das Leben aus den Tiefen des Alls?', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367686229372928, '2026-06-18 12:56:03.257339', 295853820891136, NULL, NULL, '', NULL, NULL, 'Überraschung in Wolfsburg: Zur Wahl der Aufsichtsräte auf der heutigen VW-Hauptversammlung tritt die Managerin Susanne Wiegand nicht mehr an. Sie galt als einzige unabhängige Kontrolleurin in dem Gremium.', 'd5f2779e-84bc-4f26-a3e1-a43b05eafe86', 'https://www.tagesschau.de/wirtschaft/finanzen/vw-ar-wahl-wiegand-100.html', '2026-06-18 12:43:31+00', 'VW-Konzern verliert Aufsichtsrätin Wiegand', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (366927134412800, '2026-06-16 09:27:17.339492', 295500424519680, NULL, 'DIE ZEIT: Arbeit - Dana Hajek, David Gutensohn, Anne Jeschke', 'Arbeit', NULL, NULL, 'Nicht KI, sondern das Homeoffice soll dazu führen, dass junge Menschen weniger Jobs finden – das zeigen zwei neue Studien. Echt? Wir haben Experten um Einordnung gebeten.', '{urn:uuid:73acb83c-d833-4ae8-94ff-1515cc9b3a54}', 'https://www.zeit.de/arbeit/2026-06/homeoffice-berufseinstieg-ki-remote-work', '2026-06-16 09:17:14+00', 'Homeoffice und KI: Ist das Homeoffice schuld, dass Berufseinsteiger keine Jobs finden?', NULL);
