INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (366927134416896, '2026-06-16 09:27:17.340492', 295500424519680, NULL, 'DIE ZEIT: wochenmarkt - Angelika Schwaff', 'wochenmarkt', NULL, NULL, 'Die Deutschen sind Kohlrabiweltmeister, das beste Rezept kommt aber aus Amerika. Als Slaw mit Aprikosen und Jalapeños wird aus der Knolle ein internationaler Star.', '{urn:uuid:7cb09bf0-2fd5-42ad-9850-dcb803109434}', 'https://www.zeit.de/zeit-magazin/wochenmarkt/2026-06/kohlrabi-aprikosen-salat-rezept-wochenmarkt', '2026-06-16 09:07:05+00', 'Kohlrabi-Aprikosen-Salat: Diese Knolle ist gar nicht so olle', NULL);
