INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (366927137415168, '2026-06-16 09:27:18.072418', 295853820891136, NULL, NULL, '', NULL, NULL, 'Es ist die größte offene Kunstausstellung der Welt: die Summer Exhibition in London. Jeder Brite und jede Britin konnte dafür Kunstwerke einreichen - nun ist das Ergebnis zu bewundern. Von Franziska Hoppen.', '24564546-9a6f-4fdc-aa4b-1f67b109e7e4', 'https://www.tagesschau.de/kultur/london-demokratische-ausstellung-100.html', '2026-06-16 07:19:16+00', 'Summer Exhibition in London: Wenn Hobbykünstler neben Ikonen ausstellen', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (366927137415169, '2026-06-16 09:27:18.072418', 295853820891136, NULL, NULL, '', NULL, NULL, 'In den Städten und Gemeinden fehlt jede Menge Geld. 95 Prozent der Kommunen werden laut einer SWR-Recherche 2026 keinen ausgeglichenen Haushalt erreichen. Das könnte zunehmend die Demokratie gefährden. Von K. Singer.', 'ff60a93a-63d9-45f6-883a-5de40d04f232', 'https://www.tagesschau.de/inland/innenpolitik/kommunen-finanzlage-102.html', '2026-06-16 07:18:24+00', 'Klamme Kommunen - eine Gefahr für die Demokratie?', NULL);
