INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (366927137415171, '2026-06-16 09:27:18.072418', 295853820891136, NULL, NULL, '', NULL, NULL, 'Die Betreiber von Stromnetzen gehören laut dem Bundesverband Neue Energiewirtschaft zu den lukrativsten Unternehmen in Deutschland. Demnach erwirtschafteten die größten Netzbetreiber 2024 Renditen auf Rekordniveau. Von N. Schader.', 'a272c70f-44d6-4b29-9ed2-0cbfb91d0a61', 'https://www.tagesschau.de/investigativ/swr/stromnetzbetreiber-rendite-100.html', '2026-06-16 06:02:35+00', 'Analyse der Stromnetzbetreiber - Rekordrenditen und massive Kritik', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (366927137415172, '2026-06-16 09:27:18.072418', 295853820891136, NULL, NULL, '', NULL, NULL, 'Das US-Justizministerium ermittelt offenbar gegen den kalifornischen Gouverneur Newsom und seine Ehefrau. Der Demokrat, der als Präsidentschaftskandidat gehandelt wird, vermutet politische Motive.', '921566f4-8847-4bd6-bb77-888603107c43', 'https://www.tagesschau.de/ausland/amerika/ermittlungen-newsom-vorwuerfe-gegen-trump-100.html', '2026-06-16 05:49:19+00', 'Newsom wirft Trump politisch motivierte Ermittlungen vor', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (366927137415173, '2026-06-16 09:27:18.072418', 295853820891136, NULL, NULL, '', NULL, NULL, 'Die tschechische Regierung schraubt am öffentlich-rechtlichen Rundfunk. Dazu gehört die Abschaffung der allgemeinen Gebühr. Künftig finanziert der Staat den Rundfunk direkt - allerdings deutlich schlechter. Von Marianne Allweiss.', '52e49f31-6701-4519-8c4e-4b4ec1e33f9c', 'https://www.tagesschau.de/ausland/europa/tschechien-medienreform-100.html', '2026-06-16 05:29:06+00', 'Tschechische Regierung spart beim öffentlich-rechtlichen Rundfunk', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (366927137419264, '2026-06-16 09:27:18.073711', 295853820891136, NULL, NULL, '', NULL, NULL, 'Rechenzentren für Künstliche Intelligenz gelten als Zukunftsinvestition. 11KM über die Frage, warum der Ausbau in Deutschland trotzdem stockt und was das für Folgen haben wird.', 'd0107ba2-da51-497b-8a23-8c27ecded08e', 'https://www.tagesschau.de/podcast-11km-ki-rechenzentren-100.html', '2026-06-16 04:29:03+00', '11KM-Podcast: KI-Rechenzentren - verspielt Deutschland die Zukunft?', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (366927137419265, '2026-06-16 09:27:18.073711', 295853820891136, NULL, NULL, '', NULL, NULL, 'Die Staats- und Regierungschefs der G7 setzen ihr Treffen mit Beratungen über Friedensbemühungen in der Ukraine fort. Auch Präsident Selenskyj nimmt teil und könnte die jüngsten Erfolge im Krieg gegen Russland für sich nutzen.', '50944112-2293-4bc0-9d44-b9edb4030093', 'https://www.tagesschau.de/ausland/g7-gipfel-evian-100.html', '2026-06-16 07:57:05+00', 'G7-Staaten beraten in Évian über Krieg in der Ukraine', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (366927137419266, '2026-06-16 09:27:18.073711', 295853820891136, NULL, NULL, '', NULL, NULL, 'Dünger, Futter oder Saatgut: Über solche Wege gelangen Nährstoffe in die Umwelt. Bauern mussten darüber Bilanzen führen - bis die sogenannte Stoffstrombilanzverordnung gestrichen wurde. Der Bundestag blieb dabei außen vor. Von A. Stephany.', '5db78de2-2292-4e35-badd-ed1b972e7818', 'https://www.tagesschau.de/inland/innenpolitik/bundesverfassungsgericht-stoffstrombilanzverordnung-100.html', '2026-06-16 03:40:01+00', 'Bundesverfassungsgericht verhandelt zu Abschaffung der Stoffstrombilanzverordnung', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (366927137419267, '2026-06-16 09:27:18.073711', 295853820891136, NULL, NULL, '', NULL, NULL, 'Die Folgen des Klimawandels sind besonders heftig für schutzbedürftige Menschen - allen voran für Kinder. Das Kinderhilfswerk UNICEF warnt in seiner neusten Studie davor, dass jedes zweite Kind auf der Erde dadurch mehrfach gefährdet ist. Von K. Wilhelm.', '5c003e01-a44a-46f0-8eae-e9735bd81b61', 'https://www.tagesschau.de/wissen/klima/klima-kinder-unicef-100.html', '2026-06-16 00:28:14+00', 'Jedes zweite Kind laut UNICEF-Studie von Klimarisiken betroffen', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (366927137419268, '2026-06-16 09:27:18.073711', 295853820891136, NULL, NULL, '', NULL, NULL, 'Bei einem Flugzeugunglück in Kalifornien sind acht Menschen ums Leben gekommen. Ein B-52-Bomber stürzte nach Angaben der US-Luftwaffe kurz nach dem Start ab. Die Ursache für den Absturz ist unklar.', '94ddbdfb-5939-46ea-a080-51121274ccaa', 'https://www.tagesschau.de/ausland/amerika/usa-kaliformien-b52-absturz-100.html', '2026-06-16 01:31:06+00', 'B-52-Bomber der US-Luftwaffe in Kalifornien abgestürzt', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (366964306731008, '2026-06-16 11:58:32.612567', 295514619002880, NULL, NULL, '', NULL, NULL, 'When Germany and Poland signed the Treaty on Good‑Neighborliness and Friendly Cooperation in 1991, they chose partnership over enmity and became close allies in NATO and the EU. But it has not all been plain sailing.', NULL, 'https://www.dw.com/en/how-germany-and-poland-rebooted-relations-35-years-ago/a-77576779?maca=en-rss-en-all-1573-rdf', '2026-06-16 11:52:00+00', 'How Germany and Poland rebooted relations 35 years ago', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367321637187584, '2026-06-17 12:12:31.493105', 295500424519680, NULL, 'DIE ZEIT: Zeitgeschehen - Theresa Walter', 'Zeitgeschehen', NULL, NULL, 'Das NS-Regime hat Kunst- und Kulturgegenstände aus Polen gestohlen, darunter ein Manuskript aus dem Mittelalter. Deutschland gibt sie jetzt an das Nachbarland zurück.', '{urn:uuid:c0455dfd-454c-4f5e-835e-34babfa5109d}', 'https://www.zeit.de/gesellschaft/zeitgeschehen/2026-06/ns-raubgut-kulturgueter-polen-rueckgabe-johann-wadephul', '2026-06-17 11:59:34+00', 'Restitution: Deutschland gibt NS-Raubgüter an Polen zurück', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (366927137419269, '2026-06-16 09:27:18.073711', 295853820891136, NULL, NULL, '', NULL, NULL, 'Nach CSU-interner Kritik verspricht Parteichef Söder mehr Mitbestimmung. Ein Versuch, auf Unmut zu reagieren, ohne seinem Kontrahenten Weber recht zu geben. Der Konflikt ist damit nur vorerst entschärft. Von P. Jerabek und A. Wendler.', '0ea929c7-62de-49cc-abb9-d08c09317c64', 'https://www.tagesschau.de/inland/innenpolitik/csu-markus-soeder-manfred-weber-100.html', '2026-06-15 18:27:32+00', 'Zehn-Punkte-Plan: CSU-Chef Söder verschafft sich Zeit', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (366927137419270, '2026-06-16 09:27:18.073711', 295853820891136, NULL, NULL, '', NULL, NULL, 'Ihre Kriegsziele haben die USA nicht erreicht, es gibt keine Klarheit über das iranische Atomprogramm und die Hardliner in Teheran sitzen weiter fest im Sattel. Dennoch versucht Trump, das Abkommen als Sieg zu verkaufen, sagt Nahost-Experte Adebahr.', '95b88274-d0a3-4326-8844-57f2df5e953a', 'https://www.tagesschau.de/ausland/asien/iran-usa-abkommen-adebahr-100.html', '2026-06-16 05:38:53+00', 'Interview: "Trump will ein Minimalabkommen als Sieg darstellen"', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (366927137419271, '2026-06-16 09:27:18.073711', 295853820891136, NULL, NULL, '', NULL, NULL, 'Ungeachtet des Iran-Abkommens will Israels Premier Netanjahu weiter Soldaten in den besetzten Gebieten im Libanon stationieren. Frankreichs Präsident Macron hat angeboten, Kampfjets zur Sicherung der Straße von Hormus bereitzustellen.', '81f9bfe6-8e4f-44da-a160-2e98335e27a3', 'https://www.tagesschau.de/newsticker/liveblog-iran-montag-126.html', '2026-06-15 21:30:16+00', 'Iran-Liveblog: ++ Netanjahu will Truppen im Libanon lassen ++', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (366927137419272, '2026-06-16 09:27:18.073711', 295853820891136, NULL, NULL, '', NULL, NULL, 'Der Iran-Krieg ist wohl vorbei - das ist eine gute Nachricht. Doch das Abkommen mit den USA ist fragil und stärkt nur die Führung in Teheran, meint Benjamin Weber. Es zeugt von der Ahnungslosigkeit der Regierung von US-Präsident Trump.', '3d78ad63-c27d-457b-9969-1d062f83868e', 'https://www.tagesschau.de/kommentar/iran-usa-abkommen-102.html', '2026-06-15 17:53:06+00', 'Kommentar zum Abkommen zwischen USA und Iran: Ein schlechter Deal', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (366927137419273, '2026-06-16 09:27:18.073711', 295853820891136, NULL, NULL, '', NULL, NULL, 'Der AfD-Bundesvorstand greift in die Auseinandersetzung um den Einfluss eines Geschäftsmannes innerhalb der Partei ein. Laut WDR, NDR und SZ beschloss der Vorstand, dass er weder an Parteiveranstaltungen teilnehmen noch sie mitorganisieren darf.', 'c877d3a3-53ca-471a-8a57-fc3f7641f173', 'https://www.tagesschau.de/investigativ/afd-beschluss-tom-rohrboeck-100.html', '2026-06-15 17:27:08+00', 'AfD-Bundesvorstand verbietet Zusammenarbeit mit Politikberater', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (366927137419274, '2026-06-16 09:27:18.073711', 295853820891136, NULL, NULL, '', NULL, NULL, 'Brandenburgs Bildungsminister schlägt Alarm: Zu viele Lehrer fehlen. Einige Fächer können nach den Sommerferien möglicherweise nicht mehr unterrichtet werden. Könnte das Folgen für die bundesweite Anerkennung von Abschlüssen haben? Von M. Reher.', '2fd2a1fd-dad9-48d7-84f8-deb95d1d40f1', 'https://www.tagesschau.de/inland/gesellschaft/lehrermangel-brandenburg-100.html', '2026-06-15 16:56:49+00', 'Wie der Lehrermangel Schulen in Brandenburg zusetzt', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (366927137423360, '2026-06-16 09:27:18.074715', 295853820891136, NULL, NULL, '', NULL, NULL, 'Die Bildungschancen sind in Deutschland sehr ungleich verteilt. Doch meist entsteht das Problem schon vor der Schule. Lösungen gibt es, doch knappe Kassen und der Föderalismus erschweren diese. Von P. Kuntschner und S. Beham.', 'a22eccaf-0971-4ac5-bd01-1dd713462bb0', 'https://www.tagesschau.de/inland/innenpolitik/bildungsbericht-bundesregierung-100.html', '2026-06-15 16:56:12+00', 'Bericht der Bundesregierung: Die Bildungsschere öffnet sich schon vor der Schule', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (366927137423361, '2026-06-16 09:27:18.074715', 295853820891136, NULL, NULL, '', NULL, NULL, 'Die Hoffnung auf Frieden in Iran hat die Aktienkurse beflügelt und die Ölpreise nach unten geschickt. Da aber viele Fragen offen bleiben, konnte der DAX nur einen Teil der Gewinne halten.', 'f9f7ef40-992c-4b14-8bcc-cff375d0d35f', 'https://www.tagesschau.de/wirtschaft/finanzen/marktberichte/marktbericht-dax-dow-oel-friedensabkommen-100.html', '2026-06-15 16:24:22+00', 'Marktbericht: Die Hoffnung regiert', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (366927137423362, '2026-06-16 09:27:18.074715', 295853820891136, NULL, NULL, '', NULL, NULL, 'Der Sohn der norwegischen Kronprinzessin Mette-Marit ist wegen Vergewaltigung zu vier Jahren Gefängnis verurteilt worden. Marius Borg Høiby hält sich für "eindeutig unschuldig" und will in Berufung gehen. Von Jana Sinram.', '3c119b9c-3c15-423b-bd9e-dc2e3bc4b611', 'https://www.tagesschau.de/ausland/europa/norwegen-hoiby-urteil-berufung-100.html', '2026-06-15 16:05:02+00', 'Urteil gegen Sohn von Mette-Marit: Høiby will in Berufung gehen', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (366927137423363, '2026-06-16 09:27:18.074715', 295853820891136, NULL, NULL, '', NULL, NULL, 'Für Deutschland kämpften sie im Ausland: Am heutigen Veteranentag werden Soldaten gewürdigt. Doch die persönlichen Folgen der Einsätze - wie psychische Probleme - stehen zu wenig im Fokus, kritisieren Veteranen. Von T. Peters.', '7d97ee96-9384-447a-8a1e-ece8e0b8ee2e', 'https://www.tagesschau.de/inland/gesellschaft/veteranentag-soldaten-psychische-belastungen-100.html', '2026-06-15 15:19:57+00', 'Belastungen für Soldaten: Wenn Jahre später die Panikattacken kommen', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (366927137423364, '2026-06-16 09:27:18.074715', 295853820891136, NULL, NULL, '', NULL, NULL, 'Mehr als vier Jahrzehnte leitete François Michelin den weltbekannten Reifenhersteller. Michelin ist ein französischer Mythos, aber inzwischen auch ein Symbol für die Probleme der Industrie. Heute wäre Michelin 100 Jahre geworden. Von C. Dylla.', 'dc65ed8a-e915-4b85-a304-18a006c63b0f', 'https://www.tagesschau.de/wirtschaft/unternehmen/michelin-geburtstag-100.html', '2026-06-15 14:36:11+00', 'Reifen-Unternehmer Michelin wäre heute 100 Jahre alt geworden', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (366927137423365, '2026-06-16 09:27:18.074715', 295853820891136, NULL, NULL, '', NULL, NULL, 'Beim G7-Gipfel in Évian erhoffen sich die Teilnehmer von US-Präsident Trump Details zur Vereinbarung mit Iran. Die Europäer sprechen sich für eine Mission zur Sicherung der Straße von Hormus aus. Doch Teheran winkt bislang ab.', '7de7d5fa-70cd-4c56-a381-ce85458070e2', 'https://www.tagesschau.de/ausland/europa/iran-usa-europa-abkommen-100.html', '2026-06-15 18:49:48+00', 'Nach Iran-Abkommen: Europäer bereit für Hormus-Mission', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (366927137427456, '2026-06-16 09:27:18.075715', 295853820891136, NULL, NULL, '', NULL, NULL, 'Für das iranische Nationalteam ist die WM weit mehr als nur ein Sportereignis. Von Anfang an ist die Teilnahme vom Krieg mit den USA überschattet - und vor Ort nutzen viele Exil-Iraner das Turnier für politische Botschaften. Von Gabriele Dunkel.', 'f759e2fe-c05a-4dda-96f6-5654e4aa6126', 'https://www.tagesschau.de/ausland/amerika/wm-team-iran-100.html', '2026-06-15 12:58:40+00', 'Iran bei der Fußball-WM: Die politischen Konflikte reisen mit', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (366927137427457, '2026-06-16 09:27:18.075715', 295853820891136, NULL, NULL, '', NULL, NULL, 'Norwegens Königshaus rutscht tiefer in die Krise: Für vier Jahre soll der Sohn von Kronprinzessin Mette-Marit hinter Gitter. Verurteilt wurde Høiby unter anderem für zwei Vergewaltigungen. Offenbar will er in Berufung gehen. Von Jana Sinram.', 'e14c0eee-2b62-42b9-824c-27f42ebe6604', 'https://www.tagesschau.de/ausland/europa/norwegen-hoiby-urteil-102.html', '2026-06-15 12:31:04+00', 'Urteil gegen Høiby - ein Schlag für die Königsfamilie', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (366927137427458, '2026-06-16 09:27:18.075715', 295853820891136, NULL, NULL, '', NULL, NULL, 'An den Märkten wird das angekündigte Abkommen zwischen Iran und den USA gefeiert. Die Ölpreise fallen, die Aktienkurse steigen. Bis sich das weltweite Ölangebot normalisiert, wird es auf jeden Fall aber noch Monate dauern.', 'ab0fb52a-5ab2-45ff-a4b8-696394b4ab3b', 'https://www.tagesschau.de/wirtschaft/finanzen/marktbericht-oelpreise-hormus-100.html', '2026-06-15 12:28:11+00', 'Ölpreise bleiben auf Krisenniveau', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (366927137427459, '2026-06-16 09:27:18.075715', 295853820891136, NULL, NULL, '', NULL, NULL, 'Auch nach einem Ende des Iran-Kriegs will Israel seine Streitkräfte in Teilen des benachbarten Libanon belassen. Es gehe darum, die eigene Sicherheit zu bewahren, schrieb Verteidigungsminister Katz. Von Bettina Meier.', '10585b00-4f42-4028-b5ea-e02b5955d202', 'https://www.tagesschau.de/ausland/asien/usa-iran-abkommen-israel-100.html', '2026-06-15 12:27:10+00', 'Israel sieht durch möglichen Iran-Deal eigene Sicherheit gefährdet', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (366927137427460, '2026-06-16 09:27:18.075715', 295853820891136, NULL, NULL, '', NULL, NULL, 'Bei russischen Angriffen sind in Kiew Teile des bekannten Höhlenklosters in Flammen geraten. Präsident Selenskyj sprach von einem "Angriff auf unsere Geschichte". Von Frederik Rother.', 'eda0f97d-dba0-4c42-8d0f-ed3f56adfc7f', 'https://www.tagesschau.de/ausland/europa/ukraine-russland-angriffe-kloster-100.html', '2026-06-15 11:53:48+00', 'Kloster in Kiew getroffen: "Ein Angriff auf unsere Geschichte"', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (366927137427461, '2026-06-16 09:27:18.075715', 295853820891136, NULL, NULL, '', NULL, NULL, 'Lange lebte die deutsche Wirtschaft sehr gut vom Handel mit aller Welt. Doch aktuell sind die Unsicherheiten groß. Für eine Exportnation hat das drastische Konsequenzen - vor allem für den Mittelstand. Von Axel John.', 'e1e3aabd-c1da-4237-9333-f3d1439b1bdd', 'https://www.tagesschau.de/wirtschaft/konjunktur/g7-handel-100.html', '2026-06-15 11:27:33+00', 'G7-Gipfel: Wie der Mittelstand unter globalen Krisen leidet', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (366927137427462, '2026-06-16 09:27:18.075715', 295853820891136, NULL, NULL, '', NULL, NULL, 'Nach dem erfolgreichen Börsenstart von SpaceX könnten nun OpenAI und Anthropic folgen. Doch die Trump-Regierung wird zum Unsicherheitsfaktor für die KI-Branche - und das Kapital der Anleger ist begrenzt. Von Angela Göpfert.', '9a95f964-bbce-4763-976f-90549607bfff', 'https://www.tagesschau.de/wirtschaft/boerse/spacex-openai-anthropic-ki-boersengang-100.html', '2026-06-15 10:50:03+00', 'Nach SpaceX: OpenAI und Anthropic vor dem Börsengang', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (366927137427463, '2026-06-16 09:27:18.075715', 295853820891136, NULL, NULL, '', NULL, NULL, 'US-Präsident Trump wird heute zum G7-Gipfel im französischen Évian erwartet. Mit der Drohung einer 100-prozentigen Steuer auf französischen Wein sorgte er kurz vor dem Treffen für neuen Zündstoff.', 'de1ca7e1-3fa0-41d1-9d49-5ee6883b47b0', 'https://www.tagesschau.de/ausland/europa/usa-frankreich-zoelle-wein-100.html', '2026-06-15 10:12:18+00', 'Vor G7-Gipfel: Trump droht Paris mit 100 Prozent Weinsteuer', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (366927137427464, '2026-06-16 09:27:18.075715', 295853820891136, NULL, NULL, '', NULL, NULL, 'In Großbritannien soll der Zugang zu sozialen Medien für Kinder und Jugendliche unter 16 Jahren bald tabu sein. Mehrere EU-Staaten erwägen ebenfalls ein Social-Media-Verbot, auch in Deutschland werden Einschränkungen geprüft.', '4aeffc50-7be2-4259-bd8d-2eef990b4ba3', 'https://www.tagesschau.de/ausland/europa/grossbritannien-verbot-socialmedia-100.html', '2026-06-15 09:31:22+00', 'Großbritannien plant Social-Media-Verbot für unter 16-Jährige', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (366927137431552, '2026-06-16 09:27:18.076719', 295853820891136, NULL, NULL, '', NULL, NULL, 'Der Sohn von Norwegens Kronprinzessin soll für vier Jahre hinter Gitter. Ein Gericht verurteilte Marius Borg Høiby für zwei Vergewaltigungen nach norwegischem Recht. Gegen das Urteil kann noch Berufung eingelegt werden.', '3050135d-7762-4baa-bc51-35ac0b03672c', 'https://www.tagesschau.de/ausland/europa/norwegen-hoiby-urteil-100.html', '2026-06-15 09:00:55+00', 'Norwegen: Marius Borg Høiby zu vier Jahren Haft verurteilt', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (366927137431553, '2026-06-16 09:27:18.076719', 295853820891136, NULL, NULL, '', NULL, NULL, 'Die USA und Iran haben sich auf ein Abkommen geeinigt. Doch das ist erst der Auftakt für weitere Verhandlungen. Wie geht es nun weiter? Und was könnte die Einigung für die Wirtschaft und die Preise an den Zapfsäulen bedeuten?', 'ae93ea36-c7e3-4667-90d3-a6175faf5be2', 'https://www.tagesschau.de/ausland/asien/usa-iran-abkommen-102.html', '2026-06-15 11:30:58+00', 'USA und Iran: Was bedeutet das Abkommen und wie geht es weiter?', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (366927137431554, '2026-06-16 09:27:18.076719', 295853820891136, NULL, NULL, '', NULL, NULL, 'Fliegende Fäuste in einer Kampfarena - direkt vor dem Weißen Haus. US-Präsident Trump hat zu seinem 80. Geburtstag in einer eigens dafür aufgebauten Arena ein Kampfsportspektakel verfolgt - Tausende Gäste waren dabei.', '868c3952-0153-4b25-8c55-69e5480ebb34', 'https://www.tagesschau.de/ausland/amerika/trump-geburtstag-kampfsportveranstaltung-100.html', '2026-06-15 07:20:28+00', 'Feier zu Trumps 80. Geburtstag: Prügeln für den Präsidenten', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (366927137431555, '2026-06-16 09:27:18.076719', 295853820891136, NULL, NULL, '', NULL, NULL, 'Der Protest in Genf gegen den G7-Gipfel ist nach friedlichem Beginn eskaliert: Protestierende warfen Scheiben ein und legten Feuer, Sicherheitskräfte antworteten mit Tränengas. Von Angela Ulrich.', '147ba8ac-3e28-4d20-ad67-2a375ef09fb4', 'https://www.tagesschau.de/ausland/europa/schweiz-proteste-ausschreitungen-g7-genf-100.html', '2026-06-15 06:51:04+00', 'Friedlicher G7-Protest in Genf endet mit Ausschreitungen', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (366927137431556, '2026-06-16 09:27:18.076719', 295853820891136, NULL, NULL, '', NULL, NULL, 'Werden Kinder pflegebedürftiger Eltern weiter bis zu einem Einkommen von 100.000 Euro finanziell geschützt? Gesundheitsministerin Warken will diese Grenze streichen. Die Pflegebeauftragte der Regierung lehnt das ab. Von Kirsten Girschick.', '9af0c1f0-da10-45b9-a26f-1365cabe9fc4', 'https://www.tagesschau.de/inland/pflegekosten-angehoerige-pflegebeauftragte-100.html', '2026-06-15 05:33:24+00', 'Angehörige im Pflegefall: Debatte über 100.000-Euro-Grenze', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (368021158846464, '2026-06-19 11:38:53.148889', 295514619002880, NULL, NULL, '', NULL, NULL, 'Germany is bracing for a mix of high temperatures and thunderstorms on Friday. DW has the latest.', NULL, 'https://www.dw.com/en/germany-news-heat-alerts-in-effect-for-millions/live-77625380?maca=en-rss-en-all-1573-rdf', '2026-06-19 11:34:00+00', 'Germany news: Heat alerts in effect for millions', NULL);
