INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (366927143874580, '2026-06-16 09:27:19.649883', 295514619002880, NULL, NULL, '', NULL, NULL, 'Germany''s research minister, Dorothee Bär, says the situation of German students is "very privileged" and has rejected reform of the Federal Training Assistance Act (BAföG), thereby turning many students against her.', NULL, 'https://www.dw.com/en/german-students-up-in-arms-about-funding-cuts/a-77528594?maca=en-rss-en-all-1573-rdf', '2026-06-12 16:03:00+00', 'German students up in arms about funding cuts', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367351547609089, '2026-06-17 14:14:13.842162', 295500424519680, NULL, 'DIE ZEIT: Ausland - Tom-Luca Freund', 'Ausland', NULL, NULL, 'Falls Burnham einen Sitz im Parlament erhält, soll er laut Starmer in die Regierung kommen. Damit möchte der Premierminister einen innerparteilichen Kritiker einbinden.', '{urn:uuid:ebb151ea-951f-40ab-8196-4cc001d79076}', 'https://www.zeit.de/politik/ausland/2026-06/keir-starmer-andy-burnham-labour-parteivorsitz-manchester', '2026-06-17 14:03:28+00', 'Großbritannien: Keir Starmer bietet Parteirivalen Burnham Posten in der Regierung an', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367351547609090, '2026-06-17 14:14:13.842162', 295500424519680, NULL, 'DIE ZEIT: Sport - Mathis Gann, Yannick von Eisenhart Rothe, Dieter Hoß', 'Sport', NULL, NULL, 'Auch beim zweiten deutschen Gruppenspiel gibt es ein WM-Debüt an der Pfeife. Thomas Tuchel erklärt, warum er die englische Hymne nicht mitsingt. Das Liveblog', '{urn:uuid:e528ca8b-f67f-493e-b77e-30d2cb57e930}', 'https://www.zeit.de/sport/2026-05/fussball-wm-2026-liveblog', '2026-06-17 13:53:07+00', 'Fußball-WM 2026: Schiedsrichter aus Paraguay pfeift Deutschland gegen Côte d’Ivoire', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367351548047360, '2026-06-17 14:14:13.949028', 295853820891136, NULL, NULL, '', NULL, NULL, 'Mehr als vier Millionen geflüchtete und vertriebene Menschen haben im vergangenen Jahr in Deutschland gelebt. Vor allem aus zwei Ländern sind laut Statistischem Bundesamt besonders viele Menschen gekommen.', '906e5892-9665-49dc-979d-7531fceeb63f', 'https://www.tagesschau.de/inland/weltfluechtlingstag-2026-100.html', '2026-06-17 14:12:11+00', 'Mehr als vier Millionen Geflüchtete und Vertriebene in Deutschland', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367667221057541, '2026-06-18 11:38:42.555608', 295500424519680, NULL, 'DIE ZEIT: Ausland - Alice Bota, Heinrich Wefing', 'Ausland', NULL, NULL, 'Shimon Stein war israelischer Botschafter in Berlin. Nach dem Iran-Deal sieht er Benjamin Netanjahu als gescheitert – und Israel in gefährlicher Lage.', '{urn:uuid:c59a49ac-56c8-4420-bab8-13b049a6021e}', 'https://www.zeit.de/2026/27/shimon-stein-israel-netanjahu-trump-iran-deal', '2026-06-18 11:19:31+00', 'Shimon Stein: »Wir verdrängen, was auf uns zukommt«', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367667221528576, '2026-06-18 11:38:42.670391', 295853820891136, NULL, NULL, '', NULL, NULL, 'Knapp drei Wochen vor dem NATO-Gipfel drohen die USA Bündnispartnern, die ihre Verteidigungsausgaben nicht deutlich steigern. Minister Hegseth will zudem die US-Truppenpräsenz überprüfen lassen. Von Sabrina Fritz.', 'f578895f-3814-4641-b122-1d3d1c212c89', 'https://www.tagesschau.de/ausland/europa/hegseth-in-bruessel-100.html', '2026-06-18 11:31:27+00', 'NATO: Hegseth kündigt Überprüfung der US-Truppenpräsenz an', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367667221528577, '2026-06-18 11:38:42.670391', 295853820891136, NULL, NULL, '', NULL, NULL, 'Die Bundeswehr hat zwei Marineschiffe ins Rote Meer verlegt. Sie sollen für einen möglichen Einsatz in der Straße von Hormus bereitstehen. Ob es dort tatsächlich zu einem Minenräumeinsatz kommt, ist noch offen.', '08567811-7cc9-43b4-bfce-85eae941d015', 'https://www.tagesschau.de/ausland/europa/bundeswehr-marineschiffe-strasse-von-hormus-100.html', '2026-06-18 09:33:16+00', 'Bundeswehr bereitet Marineeinsatz in Hormus vor', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367667221528578, '2026-06-18 11:38:42.670391', 295853820891136, NULL, NULL, '', NULL, NULL, 'Beim heute beginnenden EU-Gipfel geht es um schwierige Themen: Ukraine, Chinas Handelspraktiken und EU-Haushalt. Sonst dauern diese Treffen nur einen Tag - das reicht diesmal nicht. Von Christian Feld.', 'e2176ad1-a04b-4157-b01d-023ef62c3485', 'https://www.tagesschau.de/ausland/europa/eu-gipfel-648.html', '2026-06-18 09:06:09+00', 'EU-Gipfel: Zu viele schwierige Themen für nur einen Tag', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367667221528579, '2026-06-18 11:38:42.670391', 295853820891136, NULL, NULL, '', NULL, NULL, 'Der rasant wachsende Handelsüberschuss Chinas belastet Europas Wirtschaft. Die EU-Kommission will durchgreifen - und hofft auf Rückendeckung von den Staats- und Regierungschefs beim EU-Gipfel. Doch Deutschland zögert. Von Ruth Kirchner.', '5917c161-7b60-414a-86ff-fff666d03543', 'https://www.tagesschau.de/inland/innenpolitik/china-politik-deutschland-100.html', '2026-06-18 09:04:41+00', 'Deutschland als Bremser beim Schutz vor Chinas Übermacht?', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367667221528580, '2026-06-18 11:38:42.670391', 295853820891136, NULL, NULL, '', NULL, NULL, 'Bei einem schweren ukrainischen Drohnenangriff auf Moskau ist eine Raffinerie in Brand geraten. Der Flugverkehr in der russischen Hauptstadt ist gestört. In der Nacht waren russische Raketen erneut auf Kiew geflogen.', '01c55623-b6eb-4af4-8c96-98e7166e261f', 'https://www.tagesschau.de/ausland/russland-ukraine-selenskyj-100.html', '2026-06-18 08:44:14+00', 'Ukrainische Drohnen treffen Raffinerie in Moskau', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367667221528581, '2026-06-18 11:38:42.670391', 295853820891136, NULL, NULL, '', NULL, NULL, 'Die Aussicht auf steigende Zinsen in den USA sorgt dafür, dass die Freude über das vorläufige Abkommen zwischen Iran und USA nur verhalten bleibt. Der DAX legt nur leicht zu, die Ölpreise sinken dagegen deutlich.', '3165d2e5-a599-4661-ad54-ad5ed8779c18', 'https://www.tagesschau.de/wirtschaft/finanzen/marktberichte/marktbericht-dax-dow-oelmarkt-fed-100.html', '2026-06-18 08:33:28+00', 'Marktbericht: Zinsausblick der Fed stört die Anleger', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367667221532672, '2026-06-18 11:38:42.671869', 295853820891136, NULL, NULL, '', NULL, NULL, 'Die US-Streichpläne für die Verteidigung Europas treten in Kraft. Vor dem Treffen der NATO-Verteidigungsminister macht Generalsekretär Rutte klar: Europa muss stärker werden. US-Ressortchef Hegseth schwebt eine "NATO 3.0" vor.', 'a0fec1e6-4d5e-49eb-87cd-f1f1bb9d4a98', 'https://www.tagesschau.de/ausland/amerika/rutte-vor-nato-treffen-100.html', '2026-06-18 09:03:23+00', 'NATO-Generalsekretär Rutte: US-Streichpläne gelten ab sofort', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (366927145467904, '2026-06-16 09:27:20.038082', 295880188006400, NULL, NULL, '', NULL, NULL, 'Robin Hood ist am Ende seines Lebens angelangt. Während seine Legende eines edlen Banditen, der für die Gerechtigkeit eintritt, noch immer verbreitet ist, lebt er mit den Konsequenzen seiner wahren, von Mord und Gewalt geprägten Vergangenheit. Als er bei einem Kampf schwer verletzt wird, gelangt er auf eine Klosterinsel, wo sich eine Nonne seiner annimmt und seine Hoffnung auf Erlösung neu erweckt. Eine düstere Variante der Robin-Hood-Geschichte fernab des Mythos, die konsequent vom Weg aus der Barbarei heraus erzählt und dafür archaisches Pathos wie auch christliche Symbolik bemüht. Historie und Stoff legen dem Film eine besondere Schwere auf, die durch die Aussicht auf Erlösung aufgebrochen wird.', 'https://www.filmdienst.de/film/details/626287/the-death-of-robin-hood', 'https://www.filmdienst.de/film/details/626287/the-death-of-robin-hood', '2026-06-15 11:29:18+00', 'The Death of Robin Hood', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (366927145467905, '2026-06-16 09:27:20.038082', 295880188006400, NULL, NULL, '', NULL, NULL, 'Ein unscheinbarer, stummer Mann muss erleben, dass seine Tochter von einem Verbrechersyndikat entführt wird. Als er auf einen Investigativjournalisten trifft, dem das gleiche mit seiner Frau widerfahren ist, verbünden sich die beiden rachsüchtigen Männer. Dank ihrer Entschlossenheit und kombinierten Kampfkraft können sie eine Horde von Schurken nach der anderen bezwingen. Der rasante und extrem brutale Martial-Arts-Actionfilm legt die Handlung bewusst einfach an, um eine Abfolge raffinierter Kampfchoreografien zu entfesseln. Dabei bemüht sich der Film um stetige Steigerung, kann dies allerdings nicht bis zum Finale durchhalten.', 'https://www.filmdienst.de/film/details/625667/the-furious', 'https://www.filmdienst.de/film/details/625667/the-furious', '2026-06-15 12:34:01+00', 'The Furious', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (366968949608448, '2026-06-16 12:17:26.127872', 295500424519680, NULL, 'DIE ZEIT: Ausland - Isabelle Daniel, Claudia Thaler', 'Ausland', NULL, NULL, 'Die G7-Staaten wollen den Druck auf Russland erhöhen, Selenskyj hofft auf mehr Unterstützung bei der Flugabwehr. Trump erneuert Kritik an Netanjahu. Das Liveblog', '{urn:uuid:5723c41e-8120-4e74-b7e7-cdca99002193}', 'https://www.zeit.de/politik/ausland/2026-06/g7-evian-genf-proteste', '2026-06-16 12:06:05+00', 'Évian-les-Bains: G7 planen offenbar neue Energiesanktionen gegen Russland', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (366968950059008, '2026-06-16 12:17:26.237899', 295853820891136, NULL, NULL, '', NULL, NULL, 'KI- und Friedenshoffnungen treiben die Aktienmärkte weiter an. Aber vieles bleibt unsicher, und weitere Belastungen könnten die Hochstimmung an der Börse trüben. Von Detlev Landmesser.', 'f02aa111-f97a-4930-afca-c39e5da71949', 'https://www.tagesschau.de/wirtschaft/finanzen/marktbericht-optimismus-100.html', '2026-06-16 12:12:10+00', 'Marktbericht: Zuviel Optimismus an der Börse?', NULL);
