INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367321637670914, '2026-06-17 12:12:31.611308', 295853820891136, NULL, NULL, '', NULL, NULL, 'Das Bayerische Landesamt für Verfassungsschutz darf die AfD beobachten. Das hat der Bayerische Verwaltungsgerichtshof entschieden. Er begründete die Entscheidung unter anderem mit der Parteilinie zur "Remigration".', 'tagesschau_fm-story-br24-VMmpava', 'https://www.tagesschau.de/inland/regional/bayern/bayern-verfassungsschutz-afd-100.html', '2026-06-17 11:47:41+00', 'Urteil: Verfassungsschutz darf AfD in Bayern beobachten', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (368037240680448, '2026-06-19 12:44:19.378664', 295514619002880, NULL, NULL, '', NULL, NULL, 'The socialist Left Party has seen its membership soar and is especially popular with young female voters. Could it soon come to power in the city state of Berlin?', NULL, 'https://www.dw.com/en/germany-s-post-communist-left-party-is-dreaming-big/a-77627530?maca=en-rss-en-all-1573-rdf', '2026-06-19 12:28:00+00', 'Germany''s post-communist Left Party is dreaming big', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (368037243379712, '2026-06-19 12:44:20.036364', 295500424519680, NULL, 'DIE ZEIT: wochenmarkt - Gabriele Hussenether', 'wochenmarkt', NULL, NULL, 'Zucchini schmecken am besten, wenn sie höchstens zehn Zentimeter lang sind. So bleiben sie fest und cremig, statt zu verwässern. Diese gefüllten Halbmonde nutzen das aus.', '{urn:uuid:9a210978-d0f1-460e-8827-9b6314d1ca67}', 'https://www.zeit.de/zeit-magazin/wochenmarkt/2026-06/zucchini-haeppchen-rezept-wochenmarkt', '2026-06-19 12:36:27+00', 'Zucchini-Häppchen: Wetten, Sie kaufen zu große Zucchini?', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (368062079176704, '2026-06-19 14:25:23.463572', 295500424519680, NULL, 'DIE ZEIT: Wissenschaft - Uwe Jean Heuser', 'Wissenschaft', NULL, NULL, 'Überall auf der Welt wird gekämpft und konkurriert. Dabei legt eine Studie nahe, dass Menschen eigentlich ganz anders sind.', '{urn:uuid:4d2b12ed-34e1-46a9-843c-534c6bc9982e}', 'https://www.zeit.de/2026/27/zusammenarbeit-kooperation-studie-gemeinwohl-sozialverhalten', '2026-06-19 14:23:27+00', 'Zusammenarbeit: Überall gute Menschen', NULL);
