INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (368062079176706, '2026-06-19 14:25:23.463572', 295500424519680, NULL, 'DIE ZEIT: Mobilitaet - Haiko Tobias Prengel', 'Mobilitaet', NULL, NULL, 'Tesla hat bei E-Autos Maßstäbe gesetzt. Doch zuletzt verlor das Unternehmen seinen Glanz. Eine Billigversion des Model Y soll die Wende bringen. Wir haben sie getestet.', '{urn:uuid:8a5e3031-89e8-49b3-b756-910cf915da61}', 'https://www.zeit.de/mobilitaet/2026-06/tesla-model-y-elektroauto-absatz-autotest', '2026-06-19 14:20:47+00', 'Tesla Model Y: Es ist das beliebteste E-Auto der Welt. Aber ist es auch das beste?', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (368062079180800, '2026-06-19 14:25:23.464879', 295500424519680, NULL, 'DIE ZEIT: Deutschland - Yannick von Eisenhart Rothe', 'Deutschland', NULL, NULL, 'Im Darknet hat ein Rechtsextremist aus Dortmund Todeslisten mit Politikern und Anleitungen zum Bombenbau verbreitet. Dafür muss er drei Jahre in Haft.', '{urn:uuid:dc9ca913-f58c-4401-a828-224318f5ef07}', 'https://www.zeit.de/politik/deutschland/2026-06/assassination-politics-darknet-rechtsextremist-dortmund-olg-duesseldorf', '2026-06-19 14:20:37+00', 'Plattform »Assassination Politics«: Rechtsextremist wegen Mordaufrufen im Darknet zu Haftstrafe verurteilt', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (366972923531264, '2026-06-16 12:33:36.32353', 295500424519680, NULL, 'DIE ZEIT: Ausland - Isabelle Daniel, Claudia Thaler', 'Ausland', NULL, NULL, 'Die G7-Staaten wollen den Druck auf Russland erhöhen, Selenskyj hofft auf mehr Unterstützung bei der Flugabwehr. Trump erneuert Kritik an Netanjahu. Das Liveblog', '{urn:uuid:5723c41e-8120-4e74-b7e7-cdca99002193}', 'https://www.zeit.de/politik/ausland/2026-06/g7-evian-genf-proteste', '2026-06-16 12:21:56+00', 'Évian-les-Bains: G7 planen offenbar neue Energiesanktionen gegen Russland', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367355928227840, '2026-06-17 14:32:03.329711', 295500424519680, NULL, 'DIE ZEIT: Gesellschaft - Elisabeth Raether', 'Gesellschaft', NULL, NULL, 'Das Urteil gegen Marius zeigt: Auch ein Kronprinzessinnen-Sohn darf nicht tun, was er will. Die Frauen, mit denen er zusammenlebte, haben Unfassbares erlebt.', '{urn:uuid:5d5e0917-f915-403c-8104-6454d70517d1}', 'https://www.zeit.de/2026/27/marius-borg-hoeyby-mette-marit-urteil-oslo-vergewaltigung', '2026-06-17 14:15:56+00', 'Marius Borg Høiby: Nur weil Frauen Mut hatten, wieder mal', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367355929575424, '2026-06-17 14:32:03.658964', 295514619002880, NULL, NULL, '', NULL, NULL, 'The EU has eased restrictions on crops developed using novel genetic techniques. While supporters say the technology could help farmers adapt to climate change, critics argue its effects remain poorly understood.', NULL, 'https://www.dw.com/en/crispr-gene-editing-for-crops-precision-tool-or-new-risk/a-77579053?maca=en-rss-en-all-1573-rdf', '2026-06-17 14:29:00+00', 'CRISPR gene-editing for crops: Precision tool or new risk?', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (366972923531265, '2026-06-16 12:33:36.32353', 295500424519680, NULL, 'DIE ZEIT: Gesellschaft - Hella Kemper', 'Gesellschaft', NULL, NULL, 'Das Europaparlament findet einen Veggie-Kompromiss: Bezeichnungen wie »Veggie-Burger«, »-Wurst« und »-Nuggets« sind erlaubt. »Veggie-Speck« soll verboten werden.', '{urn:uuid:a497b240-9c17-4a27-bfa0-1637a10a0337}', 'https://www.zeit.de/gesellschaft/2026-06/eu-fleischbezeichnungen-verbot-vegane-produkte-landwirtschaft', '2026-06-16 12:19:19+00', 'Veggie-Ersatzprodukte: EU-Parlament verbietet Begriffe wie »veganer Speck«', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (366972923920384, '2026-06-16 12:33:36.418621', 295853820891136, NULL, NULL, '', NULL, NULL, 'Das Parlament hat für den sogenannten Turnberry-Deal gestimmt. Geplant sind 15 Prozent Zoll auf die meisten EU-Produkte, die in die USA importiert werden. Einfuhrzoll auf US-Industriegüter sollen dafür wegfallen. Von Sarah Lopez.', '2285ec12-9d42-494d-b6cb-3bcc2b616ce9', 'https://www.tagesschau.de/ausland/europa/eu-usa-handelsabkommen-100.html', '2026-06-16 12:21:13+00', 'Abstimmung im EU-Parlament: Weg frei für Handelsdeal mit USA', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (366972924579840, '2026-06-16 12:33:36.579083', 295514619002880, NULL, NULL, '', NULL, NULL, 'The US is still unrivaled in its ability to project military strength around the world, but Iran''s success in blocking the Strait of Hormuz has raised tough question on America''s role as protector of global trade.', NULL, 'https://www.dw.com/en/does-the-iran-war-diminish-us-superpower-status/a-77577337?maca=en-rss-en-all-1573-rdf', '2026-06-16 12:27:00+00', 'Does the Iran war diminish US superpower status?', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367321637670915, '2026-06-17 12:12:31.611308', 295853820891136, NULL, NULL, '', NULL, NULL, 'Jahrelang steckten die deutschen Werften in der Krise, nun weckt ein Milliardenauftrag Hoffnungen. Neptun Smulders und Siemens Energy bauen eine Offshore-Plattform, um Windstrom an Land zu bringen. Bis zu 500 Jobs könnten entstehen.', 'bbd02256-7fbd-42f8-aeea-5bbd0d02a600', 'https://www.tagesschau.de/wirtschaft/unternehmen/offshore-windkraft-rostock-milliardenauftrag-jobs-100.html', '2026-06-17 10:35:45+00', 'Offshore-Netzanbindung: Milliardenauftrag bleibt in Deutschland', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367321637670916, '2026-06-17 12:12:31.611308', 295853820891136, NULL, NULL, '', NULL, NULL, 'Mehr als zehn Monate lang war die Strecke zwischen Berlin und Hamburg gesperrt: Gleise, Bahnhöfe und Technik wurden erneuert. Nun rollt der Verkehr wieder. Doch längst nicht alles funktioniert reibungslos. Von Ole Hilgert.', 'b6d6ad0d-1c94-4029-b1dd-59a239c5cb94', 'https://www.tagesschau.de/wirtschaft/verbraucher/bahnstrecke-hamburg-berlin-108.html', '2026-06-17 10:33:48+00', 'Nach Sanierung weiter Verspätungen auf Bahnstrecke Berlin-Hamburg', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367321637675008, '2026-06-17 12:12:31.612314', 295853820891136, NULL, NULL, '', NULL, NULL, 'Jugendliche bewerten Social Media positiver als ihre Eltern und verbringen mehr Zeit online, als die Eltern vermuten. Empfehlungen von Experten zu möglichen Verboten für Minderjährige werden im Juli erwartet.', '587bee74-4ca4-4663-ad59-e3bbd2c46e65', 'https://www.tagesschau.de/ausland/europa/eu-umfrage-social-media-100.html', '2026-06-17 10:05:06+00', 'EU-Umfrage: Jugendliche sehen Social Media positiver als Eltern', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367321637675009, '2026-06-17 12:12:31.612314', 295853820891136, NULL, NULL, '', NULL, NULL, 'Norwegens schwer kranke Kronprinzessin Mette-Marit hat eine Spenderlunge erhalten. Die Transplantation sei erfolgreich verlaufen, teilte das Königshaus mit. Zusätzlich zu ihrer Krankheit belasten mehrere Skandale die Kronprinzessin.', '5edbf307-89be-47a1-a68c-d7f12450b573', 'https://www.tagesschau.de/ausland/europa/norwegens-kronprinzessin-erhaelt-lunge-100.html', '2026-06-17 10:34:59+00', 'Kronprinzessin Mette-Marit hat neue Lunge erhalten', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367321637675010, '2026-06-17 12:12:31.612314', 295853820891136, NULL, NULL, '', NULL, NULL, 'Vor dem Zinsentscheid der US-Notenbank am Abend halten sich die Anleger auch hierzulande noch bedeckt. Der DAX tendiert leicht schwächer, bleibt aber auf hohem Niveau. Im Fokus stehen im DAX BMW, die enttäuschen.', '9f6228e4-de19-4cb6-97bb-571c48d58d0f', 'https://www.tagesschau.de/wirtschaft/finanzen/marktberichte/marktbericht-dow-dax-100.html', '2026-06-17 09:15:20+00', 'Anleger halten sich vor Fed-Entscheidung zurück', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367321637675011, '2026-06-17 12:12:31.612314', 295853820891136, NULL, NULL, '', NULL, NULL, 'Die deutsch-polnischen Beziehungen sind eng, doch es gibt Verstimmungen. Vor allem über Nazi-Verbrechen wird gestritten. Ein Dauerthema: polnische Reparationsforderungen. Es beschäftigt nicht nur Rechte in Polen. Von Palina Milling.', '9e1c7220-fb8f-43af-8c4a-8ef793cd18b8', 'https://www.tagesschau.de/ausland/europa/deutsch-polnische-beziehung-proteste-100.html', '2026-06-17 08:34:39+00', 'Deutschland und Polen: Eine komplizierte Freundschaft', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367321637675012, '2026-06-17 12:12:31.612314', 295853820891136, NULL, NULL, '', NULL, NULL, 'BMW hat seine Jahresprognose deutlich gesenkt. Die Krise auf dem chinesischen Automarkt und hohe Energiepreise infolge des Iran-Kriegs belasten Absatz, Marge und Gewinn.', '4c381b68-6688-4dda-b552-40409b47c6b9', 'https://www.tagesschau.de/wirtschaft/unternehmen/bmw-prognose-china-iran-sparkurs-100.html', '2026-06-17 07:46:14+00', 'BMW senkt Prognose wegen China-Krise und Iran-Krieg', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367321637675013, '2026-06-17 12:12:31.61357', 295853820891136, NULL, NULL, '', NULL, NULL, 'Wie feiert man die eigene Hochzeit oder den WM-Auftritt der Nationalmannschaft, während Ebola grassiert? Die Menschen im kongolesischen Bunia sind verunsichert. Doch die Angst soll das Leben nicht beherrschen. Von K. Bensch.', '612e32c9-3c10-4502-9853-c4bfea4e87b7', 'https://www.tagesschau.de/ausland/ebola-alltag-kongo-100.html', '2026-06-17 07:14:21+00', 'Kongo: Alltag, Heiraten und Fußball in Zeiten von Ebola', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367321637679104, '2026-06-17 12:12:31.61357', 295853820891136, NULL, NULL, '', NULL, NULL, 'Mehr als 30 Grad, viel Sonne - und Gewitter: Auf Deutschland kommt in den kommenden Tagen eine hochsommerliche Hitzewelle zu. Doch mit den Temperaturen steigt auch die Unwettergefahr.', 'd0de684e-86da-49ed-a467-46b0c0ab21c7', 'https://www.tagesschau.de/wetter/deutschland/hitzewelle-136.html', '2026-06-17 07:11:49+00', 'Erste Hitzewelle des Jahres im Anmarsch', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367321637679105, '2026-06-17 12:12:31.61357', 295853820891136, NULL, NULL, '', NULL, NULL, 'Bei russischen Angriffen auf die Ukraine sind in der vergangenen Nacht mindestens vier Menschen ums Leben gekommen. Besonders schwer wurde auch Saporischschja im Südosten des Landes getroffen.', '00fd9801-b78e-4742-92a2-024101a7e140', 'https://www.tagesschau.de/ausland/europa/ukraine-russische-angriffe-saporischschja-100.html', '2026-06-17 06:34:56+00', 'Vier Tote bei russischen Angriffen auf Saporischschja und Slowjansk', NULL);
