INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (366976353751040, '2026-06-16 12:47:33.779181', 295500424519680, NULL, 'DIE ZEIT: Digital - Alena Kammer', 'Digital', NULL, NULL, 'Mit Hilfe künstlicher Intelligenz können täuschend echt wirkende Bilder ins Netz gestellt werden. Sexualisierte Deepfakes sollen künftig EU-weit verboten sein.', '{urn:uuid:6f20d45a-47d6-48f1-be4c-4a0195383f6e}', 'https://www.zeit.de/digital/2026-06/deepfakes-eu-verbot-ki-anwendungen-parlament', '2026-06-16 12:42:53+00', 'Deepfakes in der EU: EU-Parlament beschließt Verbot von KI für sexualisierte Deepfakes', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (366976353751041, '2026-06-16 12:47:33.779709', 295500424519680, NULL, 'DIE ZEIT: Umwelt - Tom-Luca Freund', 'Umwelt', NULL, NULL, 'Die große Mehrheit von Europas Gewässern sind laut einem Bericht badetauglich. In Deutschland waren mehr als 90 Prozent der Meere, Flüsse und Seen sogar exzellent.', '{urn:uuid:0b05f775-729c-4bcc-b608-2238ac199a24}', 'https://www.zeit.de/wissenschaft/umwelt/2026-06/wasserqualitaet-badegewaesser-europa-eu-meere-seen', '2026-06-16 12:37:14+00', 'Wasserqualität: Fast alle Badegewässer in Europa erfüllen Mindeststandards', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367321637679107, '2026-06-17 12:12:31.61357', 295853820891136, NULL, NULL, '', NULL, NULL, 'Zum 35. Jahrestag des deutsch-polnischen Nachbarschaftsvertrags wollen die beiden EU-Länder ihre Zusammenarbeit im Bereich Verteidigung stärken. Doch ihr Verhältnis gilt weiterhin als belastet.', '9c885565-ad4e-4f9b-b36c-7fce1d77e830', 'https://www.tagesschau.de/ausland/europa/pistorius-polen-verteidigungsabkommen-102.html', '2026-06-17 06:02:56+00', 'Deutschland schließt Verteidigungsabkommen mit Polen ab', NULL);
