INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367667221532673, '2026-06-18 11:38:42.671869', 295853820891136, NULL, NULL, '', NULL, NULL, 'Künstliche Intelligenz hebt Smartphones noch einmal auf ein ganz anderes Level. Doch das treibt auch die Kosten bei der Entwicklung und Produktion nach oben. Marktführer Apple kündigt nun Preiserhöhungen für iPhones und weitere Produkte an.', 'd0953504-c01a-49f6-83c5-eb17e96bcffb', 'https://www.tagesschau.de/wirtschaft/unternehmen/apple-iphone-preise-ki-chips-100.html', '2026-06-18 08:24:31+00', 'Apple: KI-Boom treibt iPhone-Preise nach oben', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367667221532674, '2026-06-18 11:38:42.671869', 295853820891136, NULL, NULL, '', NULL, NULL, 'Auf Deutschland kommt eine Hitzephase mit Werten von mehr als 30 Grad zu. Der Deutsche Wetterdienst warnt zudem vor Gewitter mit heftigem Starkregen, für den Südwesten gelten Hitzewarnungen.', 'bc7e4637-acd4-4ac1-ab6c-c82aab42f9e4', 'https://www.tagesschau.de/inland/gesellschaft/hitzewelle-138.html', '2026-06-18 08:09:30+00', 'Deutscher Wetterdienst: Hitzewarnungen, Gewitter, Starkregen', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367667221536768, '2026-06-18 11:38:42.672877', 295853820891136, NULL, NULL, '', NULL, NULL, 'Ein geplantes Luxusresort mit Beteiligung der Trump-Tochter Ivanka und ihres Ehemanns hat in Albanien eine Protestbewegung ausgelöst. Kritisiert wird nicht nur das Projekt, sondern auch die eigene Regierung. Von David Freches.', 'ed72e36b-d129-4c2b-b93e-116f61b788dd', 'https://www.tagesschau.de/ausland/europa/albanien-flamingo-proteste-100.html', '2026-06-18 08:06:39+00', 'Albanien: Proteste wegen Luxusprojekt von Kushner und Ivanka Trump', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367667221536769, '2026-06-18 11:38:42.672877', 295853820891136, NULL, NULL, '', NULL, NULL, 'Früher als geplant haben die USA und Iran eine Absichtserklärung für ein Kriegsende unterzeichnet. Doch vieles ist unklar, wie Fragen zum iranischen Atomprogramm. Was bekannt ist - und wie es jetzt weitergeht.', '95024597-df31-41ca-a96b-758b6fa2d4b0', 'https://www.tagesschau.de/ausland/asien/iran-abkommen-was-es-bedeutet-100.html', '2026-06-18 07:09:09+00', 'Iran und USA: Wie es nach der Unterzeichnung des Abkommens weitergeht', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367667221536770, '2026-06-18 11:38:42.672877', 295853820891136, NULL, NULL, '', NULL, NULL, 'Volkswagen müsse nicht nur die Kosten senken, sondern vor allem attraktive Modelle entwickeln, warnen Analysten großer Fondsgesellschaften. Auf der Hauptversammlung des Konzerns heute dürften kritische Nachfragen kommen. Von Annette Deutskens.', '52192b1b-f7ca-4f7a-a4b7-c92cb51afd1d', 'https://www.tagesschau.de/wirtschaft/vw-sparprogramm-hauptversammlung-100.html', '2026-06-18 04:26:09+00', 'Lage des VW-Konzerns: "Ein Sparprogramm allein ist keine Strategie"', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367667221536771, '2026-06-18 11:38:42.672877', 295853820891136, NULL, NULL, '', NULL, NULL, 'Bestehende Gesetze zum Schutz von Natur und Umwelt werden oft unzureichend umgesetzt, so ein Gutachten des Umweltrates, das dem ARD-Hauptstadtstudio vorliegt. Die Folge: Klimaziele werden oft nicht erreicht. Von D. Hebestreit.', 'd64f3f84-46f6-41ca-a5c2-385ad2c49def', 'https://www.tagesschau.de/inland/gutachten-umweltrat-100.html', '2026-06-18 03:39:52+00', 'Eine klaffende Lücke zwischen Anspruch und Wirklichkeit', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367321637679109, '2026-06-17 12:12:31.61357', 295853820891136, NULL, NULL, '', NULL, NULL, 'In Haiti kontrollieren kriminelle Banden den Großteil des Landes, immer wieder gibt es Gewalt. UN-Generalsekretär Guterres war nun für einen Kurzbesuch in dem Karibikstaat und bat um Entschuldigung.', '4076da95-ce2b-4a58-bc5e-9513c6d6513f', 'https://www.tagesschau.de/ausland/amerika/guterres-haiti-100.html', '2026-06-17 04:59:22+00', 'Gewalt in Haiti: Guterres bittet um Verzeihung für Untätigkeit der Welt', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367321637679110, '2026-06-17 12:12:31.61357', 295853820891136, NULL, NULL, '', NULL, NULL, 'Funktionäre und Vorstandsmitglieder der Linksjugend inszenieren Stalin, Mao und die DDR als Vorbilder. In einem internen Forum und in Chats verbreiten sie zudem antisemitische Parolen. Das zeigen BR-Recherchen.', '891c5902-3ef6-43f8-95be-827cdf463f08', 'https://www.tagesschau.de/investigativ/br-recherche/linksjugend-106.html', '2026-06-17 04:00:13+00', 'Stalin, Mao, Hamas - Was in der Linksjugend sagbar ist', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367321637679111, '2026-06-17 12:12:31.61357', 295853820891136, NULL, NULL, '', NULL, NULL, 'Die Sorge, Trump könnte vom G7-Treffen wieder vorzeitig abreisen, hat sich nicht bewahrheitet - im Gegenteil. Kanzler Merz spricht von neuer Harmonie und Fortschritten zur Ukraine und Iran. Für Trump wird es heute nochmal pompös. Von A. Ulrich.', 'db010967-da79-4f22-9177-de1e5caa09f8', 'https://www.tagesschau.de/ausland/europa/g7-gipfel-evian-102.html', '2026-06-17 03:02:31+00', 'G7-Gipfel: Merz zieht positives Fazit vor letztem Tag', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367321637683200, '2026-06-17 12:12:31.614631', 295853820891136, NULL, NULL, '', NULL, NULL, 'Migrationspolitik wird eines der Themen auf der Innenministerkonferenz sein. Hamburgs Innensenator Grote forderte im Vorfeld, die Hürden für die Abschiebung straffälliger Flüchtlinge zu senken - auch solcher mit Schutzstatus.', 'edeec517-f20c-4135-97b7-a72039fb19b1', 'https://www.tagesschau.de/inland/innenministerkonferenz-154.html', '2026-06-17 01:08:08+00', 'Migration und zivile Verteidigungsfähigkeit Themen bei Innenministerkonferenz', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367321637683201, '2026-06-17 12:12:31.614631', 295853820891136, NULL, NULL, '', NULL, NULL, 'Kann aus dem Rahmenabkommen zwischen den USA und Iran eine endgültige Friedenseinigung werden? Viel hängt davon ab, ob Israel mit seinem Vorgehen gegen die Hisbollah im Libanon weitermacht oder seine Truppen abzieht. Von Bettina Meier.', '63e6d059-eb39-425f-a2e1-86541f0218e6', 'https://www.tagesschau.de/ausland/europa/libanon-israel-friedensloesung-100.html', '2026-06-16 18:43:36+00', 'Israels Libanon-Politik wird zur Belastungsprobe für Rahmenabkommen', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367667221536772, '2026-06-18 11:38:42.672877', 295853820891136, NULL, NULL, '', NULL, NULL, 'Die Hitze in den kommenden Tagen kann auch am Arbeitsplatz und in der Schule schnell zur Belastung werden. Welche Regeln gelten, wenn die Temperatur immer weiter steigt? Ein Überblick. Von Michael-Matthias Nordhardt.', 'a9268537-a8e0-4cb7-b212-b961f6e556d8', 'https://www.tagesschau.de/wirtschaft/verbraucher/faq-hitze-rechte-100.html', '2026-06-18 03:13:52+00', 'Hitze in Deutschland: Regeln am Arbeitsplatz und in der Schule', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367704216866816, '2026-06-18 14:09:14.735281', 295500424519680, NULL, 'DIE ZEIT: Ausland - Peter Dausend', 'Ausland', NULL, NULL, 'Zwei deutsche Schiffe machen sich bereit für eine mögliche Mission in der Straße von Hormus. Ob sie zum Einsatz kommen? Dafür müssten vier Bedingungen erfüllt sein.', '{urn:uuid:8b0e6350-a7c6-4d5b-916f-892aac6fd02e}', 'https://www.zeit.de/politik/ausland/2026-06/minenraeumung-strasse-von-hormus-deutsche-marine-schiffe', '2026-06-18 14:07:20+00', 'Minenräumung in der Straße von Hormus: Minenräumung ohne Eile', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367704216866817, '2026-06-18 14:09:14.735281', 295500424519680, NULL, 'DIE ZEIT: Sport - Leon Ginzel, Mathis Gann, Iven Yorick Fenker', 'Sport', NULL, NULL, 'Elye Wahi wird am Samstag beim Spiel gegen Deutschland fehlen. Die dreiminütigen »Hydrationbreaks« pro Halbzeit spalten die Fans. Was halten Sie davon? Das Liveblog', '{urn:uuid:e528ca8b-f67f-493e-b77e-30d2cb57e930}', 'https://www.zeit.de/sport/2026-05/fussball-wm-2026-liveblog', '2026-06-18 14:06:14+00', 'Fußball-WM 2026: Kanada verweigert Ivorer Wahi vor dem Deutschlandspiel die Einreise', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367983260143616, '2026-06-19 09:04:40.535777', 297942154895360, NULL, NULL, '', NULL, NULL, 'Keine Kennzeichnungspflicht im Supermarkt, weniger Umweltprüfungen, Patente auf neue Pflanzensorten: Das EU-Parlament hat die Regeln für den Einsatz von Gentechnik gelockert. Was das für Verbraucher und Biobauern bedeutet.', 'gentechnik-eu-regeln-lebensmittel-pflanzen-ngt-100', 'https://www.deutschlandfunk.de/gentechnik-eu-regeln-lebensmittel-pflanzen-ngt-100.html', '2026-06-19 07:56:00+00', 'Gen-Food im Supermarkt - Welche Folgen die neuen Gentechnik-Regeln der EU haben', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367983260147712, '2026-06-19 09:04:40.536303', 297942154895360, NULL, NULL, '', NULL, NULL, 'Künftig soll die Astronomie in der Elfenbeinküste eine größere Rolle spielen. Das All trägt zur besseren Bildung in Naturwissenschaften, Mathematik und Technik bei, hofft ein engagiertes Team. Von diesem Land aus ist fast der gesamte Himmel zu sehen. Lorenzen, Dirk', 'sternzeit-19-juni-2026-astronomische-anfaenge-in-der-elfenbeinkueste-100', 'https://www.deutschlandfunk.de/sternzeit-19-juni-2026-astronomische-anfaenge-in-der-elfenbeinkueste-100.html', '2026-06-19 00:57:41+00', 'WM-Gegner - Astronomische Anfänge in der Elfenbeinküste', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367983260147713, '2026-06-19 09:04:40.536303', 297942154895360, NULL, NULL, '', NULL, NULL, 'Die soziale Umwelt von Kindern beeinflusst ihre Gehirnentwicklung. Einkommen und Bildungsgrad der Eltern spielen die größte Rolle. Wie sich Stress und Schlafmangel auswirken, unter denen Kinder armer Familien eher leiden, zeigt eine Studie aus den USA. Wildermuth, Volkart', 'sozio-oekonomik-armut-kann-sogar-gehirnfunktionen-beeinflussen-100', 'https://www.deutschlandfunk.de/sozio-oekonomik-armut-kann-sogar-gehirnfunktionen-beeinflussen-100.html', '2026-06-18 14:35:55+00', 'US-Studie bei Kindern - Armut kann Gehirnfunktion beeinflussen', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367983267954688, '2026-06-19 09:04:42.442215', 295500424519680, NULL, 'DIE ZEIT: Digital - Lennart Jerke', 'Digital', NULL, NULL, 'Auf allen Websites, wo ein Widerrufsrecht besteht, gilt die Pflicht für einen »Widerrufsbutton«. So sollen Verbraucher ihre Verträge mit wenigen Klicks kündigen können.', '{urn:uuid:76c731f2-905e-46e2-90a1-a052684fbb79}', 'https://www.zeit.de/digital/2026-06/widerrufsbutton-online-widerruf-gesetz-internet-vertraege', '2026-06-19 08:56:31+00', 'Online-Widerruf: Gesetz zum verpflichtenden »Widerrufsbutton« in Kraft', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367983267954689, '2026-06-19 09:04:42.442215', 295500424519680, NULL, 'DIE ZEIT: Wirtschaft - Alara  Yılmaz', 'Wirtschaft', NULL, NULL, 'Die deutschen Herstellerpreise sind im Mai aufgrund des Ölpreisanstiegs besonders schnell gestiegen. Produkte kosteten im Durchschnitt 2,2 Prozent mehr als im Jahr zuvor.', '{urn:uuid:ac3b5c93-87a0-4f17-a303-239e34ddb8ef}', 'https://www.zeit.de/wirtschaft/2026-06/erzeugerpreise-mai-2024-oel-inflation-ezb', '2026-06-19 08:47:19+00', 'Inflation: Erzeugerpreise steigen so stark wie seit Mai 2023 nicht mehr', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367983267954690, '2026-06-19 09:04:42.442215', 295500424519680, NULL, 'DIE ZEIT: Entdecken - Christoph Amend, Ubin Eoh', 'Entdecken', NULL, NULL, 'Im Wochenendpodcast erzählt die Schauspielerin Mala Emde, mit welchem Trick sie in ihrer Wohnung Espressoduft verteilt. Und wie es war, mit 400 Schafen aufzuwachsen.', '{urn:uuid:092f0f00-9d06-4dbd-96a9-a1b62dd119a4}', 'https://www.zeit.de/entdecken/2026-06/mala-emde-ostsee-wochenende-tipps-podcast', '2026-06-19 08:40:08+00', 'Mala Emde: »Sonntage sind für mich orange«', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367983267954691, '2026-06-19 09:04:42.442215', 295500424519680, NULL, 'DIE ZEIT: Ausland - Jona Spreter', 'Ausland', NULL, NULL, 'Seit 2018 hat der frühere Bundesgesundheitsminister wiederholt an vertraulichen Treffen des »Dialog«-Netzwerks teilgenommen. Dieses Jahr will er nicht mehr kommen.', '{urn:uuid:c3398981-e39d-4877-ab47-a37aecd58357}', 'https://www.zeit.de/politik/ausland/2026-06/jens-spahn-peter-thiel-dialog-organisation-treffen', '2026-06-19 08:24:00+00', '»Dialog«-Netzwerk: Jens Spahn bestätigt Teilnahme an Treffen von Peter Thiel', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367983267954692, '2026-06-19 09:04:42.442215', 295500424519680, NULL, 'DIE ZEIT: Deutschland - Caspar Leder', 'Deutschland', NULL, NULL, 'Organisationen, Verbände und Kirchen haben ein Umdenken in Bezug auf den Schutz Geflüchteter gefordert. Besonders stark kritisierte das Bündnis den politischen Diskurs.', '{urn:uuid:6308d6f6-c6be-414c-86c9-088eec2db758}', 'https://www.zeit.de/politik/deutschland/2026-06/weltfluechtlingstag-gefluechtete-schutz-genfer-fluechtlingskonvention', '2026-06-19 08:20:58+00', 'Weltflüchtlingstag: Bündnis fordert Umdenken und mehr Flüchtlingsschutz', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367983267954693, '2026-06-19 09:04:42.442215', 295500424519680, NULL, 'DIE ZEIT: Deutschland - Hella Kemper', 'Deutschland', NULL, NULL, 'Fast drei Viertel der Menschen in Deutschland glauben nicht an den Zeitplan der Regierung für ein Reformpaket. Und nur wenige sind bereit, Einschränkungen hinzunehmen.', '{urn:uuid:835320d4-5750-4926-bb2d-214cbaa4fd97}', 'https://www.zeit.de/politik/deutschland/2026-06/zdf-politbarometer-reformpaket-bundesregierung-umfrage', '2026-06-19 08:16:17+00', 'ZDF-»Politbarometer«: Mehrheit der Deutschen glaubt nicht an Reformen bis zum Sommer', NULL);
