INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367983268462594, '2026-06-19 09:04:42.56672', 295853820891136, NULL, NULL, '', NULL, NULL, 'Nach der Öffnung der Straße von Hormus plant die Bundesregierung, sich an einer internationalen Aktion zur Minenräumung zu beteiligen. Aber es gibt rechtliche Risiken. Von Max Bauer.', '684cf809-2fe3-41a3-b7cc-ac448f53f7f1', 'https://www.tagesschau.de/ausland/asien/strasse-hormus-bundeswehreinsatz-faq-100.html', '2026-06-19 08:25:22+00', 'Wäre ein Bundeswehreinsatz in der Straße von Hormus rechtlich möglich?', NULL);
