INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367983268462595, '2026-06-19 09:04:42.56672', 295853820891136, NULL, NULL, '', NULL, NULL, 'Die Fußball-Weltmeisterschaft ist auch ein Schaulaufen der drei großen Sportartikel-Hersteller. Die Marken-Logos der Konzerne sind omnipräsent auf den Trikots. Hat das einen Effekt über die WM hinaus? Von Bianca von der Au.', '0d4f36a3-c9f2-4b05-be21-45aef276b1f2', 'https://www.tagesschau.de/wirtschaft/unternehmen/fussball-wm-sportartikel-adidas-nike-puma-100.html', '2026-06-19 06:39:36+00', 'Welche Rolle die WM für die großen Sportartikel-Hersteller spielt', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367983268466688, '2026-06-19 09:04:42.567726', 295853820891136, NULL, NULL, '', NULL, NULL, 'Der Deutsche Wetterdienst weitete seine Hitzewarnungen auf alle Bundesländer aus - mit wenigen Ausnahmen. Örtlich können Starkregen, Hagel, Sturmböen und Unwetter auftreten. In Norddeutschland gibt es Zug-Probleme.', '22c684fb-df22-4d3b-a108-02cb017de68d', 'https://www.tagesschau.de/inland/gesellschaft/hitze-unwetter-104.html', '2026-06-19 08:09:16+00', 'Warnung des DWD: Hitzewelle und Gewitter über Deutschland', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367983268466689, '2026-06-19 09:04:42.567726', 295853820891136, NULL, NULL, '', NULL, NULL, 'Schon heute sollten die Gespräche zwischen den USA und Iran über ein finales Friedensabkommen beginnen. Doch der Verhandlungstisch in der Schweiz bleibt vorerst leer, die Anreise von US-Vizepräsident Vance wurde abgesagt.', '6ea3daf3-e080-41a9-a242-9f87475a6d8e', 'https://www.tagesschau.de/ausland/asien/iran-usa-abkommen-verhandlungen-100.html', '2026-06-19 05:52:18+00', 'Gespräche zwischen Iran und USA über Friedensabkommen verschoben', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367983268466690, '2026-06-19 09:04:42.567726', 295853820891136, NULL, NULL, '', NULL, NULL, 'Er fluchte, trank, prügelte - und wurde zur Kultfigur: Götz George sprengte als Horst Schimanski alle Konventionen des braven TV-Kommissars und schenkte dem Ruhrgebiet neues Selbstbewusstsein. Vor zehn Jahren starb er. Von S. Fritz.', '26df9740-3637-4375-a031-36ef888eda66', 'https://www.tagesschau.de/kultur/schimanski-praegt-deutsche-fernsehen-bis-heute,goetz-george-142.html', '2026-06-19 05:25:22+00', '10. Todestag Götz George: "Schimanski" prägt das deutsche Fernsehen bis heute', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367983268466691, '2026-06-19 09:04:42.567726', 295853820891136, NULL, NULL, '', NULL, NULL, 'Das deutsche Zugangebot könnte bald aufgemischt werden. Das italienische Unternehmen Italo will in den Fernverkehr einsteigen. Wie realistisch ist das? Und was heißt das für Bahnkunden? Von Jan Zimmermann.', 'fced03ee-25e1-4f40-8446-160764acd359', 'https://www.tagesschau.de/wirtschaft/unternehmen/einstieg-italo-deutsche-bahn-100.html', '2026-06-19 05:19:20+00', 'Was der Einstieg von Italo ins deutsche Bahngeschäft bringen könnte ', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367983268466692, '2026-06-19 09:04:42.567726', 295853820891136, NULL, NULL, '', NULL, NULL, 'Die Bundeswehr soll bis Ende des Jahrzehnts verteidigungsfähig werden. Doch Insider warnen vor einem massiven Reparaturstau bei den Panzerfahrzeugen. 11KM fragt: Ist die Bundeswehr einsatzbereit?', '9e5cecf0-0068-4b9a-a633-72891102c9fe', 'https://www.tagesschau.de/podcast-11km-bundeswehr-reparaturstau-100.html', '2026-06-19 04:29:06+00', '11KM-Podcast: Reparaturstau - ist die Bundeswehr einsatzbereit?', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367983268466693, '2026-06-19 09:04:42.567726', 295853820891136, NULL, NULL, '', NULL, NULL, '"Turbo", "Upgrade" und jetzt "Aktionsplan": Mit weiteren Maßnahmen will das Ministerium das Bauen bezahlbarer machen. Denn die Kosten bremsen den Wohnungsbau in Deutschland. Was sieht der Plan vor? Von Frank Jahn.', 'c676d363-01e5-4a74-b6df-6e0c205deef5', 'https://www.tagesschau.de/inland/innenpolitik/aktionsplan-baukosten-100.html', '2026-06-19 04:22:44+00', 'Bauministerium legt "Aktionsplan zur Senkung der Baukosten" vor', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367983268474880, '2026-06-19 09:04:42.569149', 295853820891136, NULL, NULL, '', NULL, NULL, 'Sie sieht sich als Partei des Sozialprotests, fordert Umverteilung und eine Abschaffung der Schuldenbremse: Auf ihrem Parteitag will die Linke einen Gegenentwurf zu den Regierungsplänen präsentieren. Und es geht um Personalien. Von A. Budweg.', 'b7d5768c-225f-4b1a-9bd5-0dcf3f9ee907', 'https://www.tagesschau.de/inland/innenpolitik/parteitag-linkspartei-102.html', '2026-06-19 04:01:48+00', 'Parteitag der Linken: Klassenkampf mit neuem Co-Vorsitz', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367983268474881, '2026-06-19 09:04:42.569149', 295853820891136, NULL, NULL, '', NULL, NULL, 'Bei der richtungsweisenden Nachwahl im englischen Wahlkreis Makerfield hat der Labour-interne Konkurrent von Premierminister Starmer, Burnham, gewonnen. Damit zieht er ins britische Unterhaus ein und kann Starmer als Labour-Parteichef herausfordern.', '2e94e682-049f-465b-a279-d3b5d12e5836', 'https://www.tagesschau.de/ausland/burnham-gewinnt-nachwahl-gb-100.html', '2026-06-19 07:11:58+00', 'Großbritannien: Starmer-Herausforderer Burnham gewinnt Nachwahl', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367983268474882, '2026-06-19 09:04:42.569149', 295853820891136, NULL, NULL, '', NULL, NULL, 'Zehn Tage lang haben mehr als 5.000 Delegierte in Bonn die nächste Weltklimakonferenz im November vorbereitet. Dabei gab es Fortschritte, aber auch Widerstände. So ist von "schwerwiegenden" Angriffen auf die Wissenschaft die Rede. Von J. Schreiber.', '397844e0-9a37-4b0b-a137-34e5adffb152', 'https://www.tagesschau.de/wissen/klimakonferenz-bonn-118.html', '2026-06-19 00:26:41+00', 'Klimakonferenz in Bonn: Zwischen Visionen und Widerständen', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367983268474883, '2026-06-19 09:04:42.569149', 295853820891136, NULL, NULL, '', NULL, NULL, 'Die EU hat ihre Russland-Sanktionen um zwölf Monate verlängert. Möglich wurde der längere Zeitraum durch den Regierungswechsel in Ungarn. Ärger gab es über eine Kontaktaufnahme des EU-Ratspräsidenten mit Moskau.', 'd20fa68d-27e0-491e-ab10-f067991ebe43', 'https://www.tagesschau.de/ausland/eu-sanktionen-russland-206.html', '2026-06-19 01:36:24+00', 'EU verlängert Russland-Sanktionen um zwölf Monate', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367983268474884, '2026-06-19 09:04:42.569149', 295853820891136, NULL, NULL, '', NULL, NULL, '"Milliarden für nichts": In den USA stößt das Rahmenabkommen mit Iran nicht nur bei den Demokraten auf Skepsis. Kritiker sehen Iran klar als Profiteur - am Ende stehe das Land sogar besser da als vor dem Krieg. Von Nina Barth.', '683b3261-1f3f-4e75-9174-245ae51b28ae', 'https://www.tagesschau.de/ausland/usa-iran-reax-104.html', '2026-06-18 17:10:37+00', 'In den USA überwiegen nach Rahmenabkommen Skepsis und Kritik', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367983268474885, '2026-06-19 09:04:42.569149', 295853820891136, NULL, NULL, '', NULL, NULL, 'Der russische Künstler Skrepezki demonstriert mit einer Putin-Karikatur in Berlin. Drei Tage später wird er erschossen. Polens Regierungschef glaubt an einen politischen Mord. Von Palina Milling.', 'bea6ed0d-f403-4dd4-8b8c-cf6f0d8bb074', 'https://www.tagesschau.de/ausland/europa/polen-russland-putin-kuenstler-100.html', '2026-06-18 16:55:32+00', 'Nach Schüssen auf Kreml-Kritiker: Verdächtiger festgenommen', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367983268474886, '2026-06-19 09:04:42.569149', 295853820891136, NULL, NULL, '', NULL, NULL, 'Der DAX hat sich heute im Sog einer steigenden Wall Street von seinen Tagestiefs zwar gelöst - die Marke von 25.000 Punkten bleibt aber eine hohe Hürde. Vor allem Halbleiteraktien treiben die US-Indizes.', '3165d2e5-a599-4661-ad54-ad5ed8779c18', 'https://www.tagesschau.de/wirtschaft/finanzen/marktberichte/marktbericht-dax-dow-oelmarkt-fed-100.html', '2026-06-18 16:34:29+00', 'Marktbericht: DAX kommt nicht vom Fleck', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367983268478976, '2026-06-19 09:04:42.570317', 295853820891136, NULL, NULL, '', NULL, NULL, 'Schwarz-Rot hatte sich für flexiblere Arbeitszeiten ausgesprochen - etwa eine wöchentliche Höchstarbeitszeit. Jetzt liegt ein erster Gesetzentwurf vor, der in der Union direkt auf Ablehnung stieß. Von M. Rödle und J.-P. Bartels.', '0a6e5423-5a40-4efc-9fb6-dd09a8dfe06b', 'https://www.tagesschau.de/inland/innenpolitik/entwurf-arbeitszeitgesetz-100.html', '2026-06-18 19:42:36+00', 'Entwurf für Arbeitszeitgesetz sorgt für scharfe Kritik', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367983268478977, '2026-06-19 09:04:42.570317', 295853820891136, NULL, NULL, '', NULL, NULL, 'Während Putin in Kasan Gäste empfängt, trifft einer der wohl schwersten ukrainischen Drohnenangriffe eine Raffinerie in Moskau. Doch zu den Attacken, die zunehmend der russischen Wirtschaft schaden, kommt kein Wort vom Kremlchef. Von B. Blaschke.', 'c7fbd272-ef7b-4255-8359-f9032b9c0e29', 'https://www.tagesschau.de/ausland/europa/ukraine-russland-angriffe-170.html', '2026-06-18 16:02:38+00', 'Putin in Kasan: Kein Wort zum Großangriff auf Raffinerie in Moskau', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367983268478978, '2026-06-19 09:04:42.570317', 295853820891136, NULL, NULL, '', NULL, NULL, 'Chemnitz wird zum Epizentrum internationaler Bühnenkunst: Das Festival "Theater der Welt" zeigt Produktionen von allen Kontinenten. Im Fokus stehen Fragen nach Identität, Herkunft und Gerechtigkeit.', 'c2946646-e6d0-4c64-afa3-0582a433cc50', 'https://www.tagesschau.de/kultur/chemnitz-holt-die-welt-auf-die-buehne,internationales-theaterfestival-100.html', '2026-06-18 15:13:02+00', 'Herkunft, Macht und indigene Stimmen: Chemnitz holt die Welt ins Theater', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367983268478979, '2026-06-19 09:04:42.570317', 295853820891136, NULL, NULL, '', NULL, NULL, 'Viele Reedereien warten auf den Moment, wenn sich der Schiffsverkehr am Golf wieder normalisiert. Eine wichtige Rolle könnte dabei die sogenannte Marine-Schifffahrtsleitung der Bundeswehr übernehmen, die in einer Kaserne in Hamburg sitzt. Von Kai Küstner.', 'd187d5d6-aa52-41a7-b7f7-64831dbafeda', 'https://www.tagesschau.de/inland/deutsche-marine-ostsee-hormus-100.html', '2026-06-18 14:50:10+00', 'Beratung aus Deutschland: Freie Fahrt für Handelsschiffe?', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367983268478980, '2026-06-19 09:04:42.570317', 295853820891136, NULL, NULL, '', NULL, NULL, 'Wenn es an die Heizung geht, wird es heikel für die Politik. So auch beim geplanten Gebäudemodernisierungsgesetz, das gegen das Grundgesetz verstoßen könnte. Ein neues Gutachten ist besonders für die Union unbequem. Von Tina Handel.', '2dcaf88f-6f9d-4991-8051-4ea8cad4c4f8', 'https://www.tagesschau.de/inland/innenpolitik/rechtliche-zweifel-gebaeudemodernisierungsgesetz-100.html', '2026-06-18 14:38:38+00', 'Gutachten: Verfassungsrechtliche Zweifel am Gebäudemodernisierungsgesetz', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367983268478981, '2026-06-19 09:04:42.570317', 295853820891136, NULL, NULL, '', NULL, NULL, 'Die Straße von Hormus soll wieder offen sein. Doch Minen, Versicherungsfragen und Schäden an Förderanlagen stehen einer Rückkehr zum Vorkriegszustand im Weg. Was bedeutet das für den Ölmarkt, Spritpreise und die Konjunktur? Von Angela Göpfert.', '12d936c6-1f9f-4310-9b32-935c031ab48f', 'https://www.tagesschau.de/wirtschaft/weltwirtschaft/iran-abkommen-hormus-oelpreise-schifffahrt-100.html', '2026-06-18 16:51:29+00', 'Straße von Hormus: Warum die Normalisierung Monate dauern wird', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367983268483072, '2026-06-19 09:04:42.571448', 295853820891136, NULL, NULL, '', NULL, NULL, 'Die Rahmenvereinbarung zwischen den USA und Iran ist unterschrieben - von US-Präsident Trump mit Prunk im Schloss Versailles. Nun geht es darum, das dünne Dokument mit Leben zu füllen. In der Schweiz sollen die Verhandlungen beginnen.', 'd899e740-fbfe-45ce-8713-2fed60311aa8', 'https://www.tagesschau.de/ausland/asien/usa-iran-schweiz-verhandlungen-100.html', '2026-06-18 14:19:47+00', 'Gespräche über Friedenslösung zwischen USA und Iran sollen beginnen', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367983268483073, '2026-06-19 09:04:42.571448', 295853820891136, NULL, NULL, '', NULL, NULL, 'Volkswagen müsse nicht nur die Kosten senken, sondern vor allem attraktive Modelle entwickeln, warnen Analysten großer Fondsgesellschaften. Auf der Hauptversammlung des Konzerns gab es heute viel Kritik. Von Annette Deutskens.', '52192b1b-f7ca-4f7a-a4b7-c92cb51afd1d', 'https://www.tagesschau.de/wirtschaft/vw-sparprogramm-hauptversammlung-100.html', '2026-06-18 14:14:07+00', 'Lage des VW-Konzerns: "Ein Sparprogramm allein ist keine Strategie"', NULL);
