INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367983269064713, '2026-06-19 09:04:42.713628', 295514619002880, NULL, NULL, '', NULL, NULL, 'Elephants striker Elye Wahi is being investigated in France in connection to allegations of match-fixing. The 23-year-old, who is contracted to Eintracht Frankfurt, is not the first player to be denied a Canadian visa.', NULL, 'https://www.dw.com/en/world-cup-ivory-coast-s-elye-wahi-denied-entry-to-canada/a-77611710?maca=en-rss-en-all-1573-rdf', '2026-06-18 15:35:00+00', 'World Cup: Ivory Coast''s Elye Wahi denied entry to Canada', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367983269064714, '2026-06-19 09:04:42.713628', 295514619002880, NULL, NULL, '', NULL, NULL, 'Following the tentative deal with the US, Iran is planning to reopen the Strait of Hormuz. The German Bundeswehr is planning to assist with the mine-clearing.', NULL, 'https://www.dw.com/en/strait-of-hormuz-german-military-prepares-for-possible-deployment/a-77613999?maca=en-rss-en-all-1573-rdf', '2026-06-18 15:27:00+00', 'Strait of Hormuz: German military prepares for possible deployment', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367983269068800, '2026-06-19 09:04:42.714149', 295514619002880, NULL, NULL, '', NULL, NULL, 'Israel''s foreign minister says he is severing contact with the EU''s foreign affairs chief Kaja Kallas. Gideon Saar attributed the move to a media report alleging that Kallas compared Israel to apartheid-era South Africa.', NULL, 'https://www.dw.com/en/israel-says-it-s-cutting-ties-to-eu-s-kaja-kallas/a-77605930?maca=en-rss-en-all-1573-rdf', '2026-06-18 15:08:00+00', 'Israel says it''s cutting ties to EU''s Kaja Kallas', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367983269068801, '2026-06-19 09:04:42.714149', 295514619002880, NULL, NULL, '', NULL, NULL, 'Even amid an ongoing energy crunch, major economies are dodging firm timelines to phase out coal, oil and gas. Fossil fuel-producing nations now fear new clean energy alliances could ramp up the pressure to go green.', NULL, 'https://www.dw.com/en/oil-nations-on-edge-in-the-face-of-new-climate-coalition/a-77607010?maca=en-rss-en-all-1573-rdf', '2026-06-18 14:42:00+00', 'Oil nations on edge in the face of new climate coalition', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367983269068802, '2026-06-19 09:04:42.714149', 295514619002880, NULL, NULL, '', NULL, NULL, 'Being encouraging and building confidence is what the German song "Gut genug" ("Good Enough") is all about. A meme is now bringing the track and its message to millions of people around the world.', NULL, 'https://www.dw.com/en/how-a-feel-good-german-song-is-taking-over-social-media/a-77592590?maca=en-rss-en-all-1573-rdf', '2026-06-18 14:13:00+00', 'How a feel-good German song is taking over social media', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367983269068803, '2026-06-19 09:04:42.714149', 295514619002880, NULL, NULL, '', NULL, NULL, 'World leaders welcomed an end to fighting and relief from a global energy crunch — but critics doubt a lasting deal is in sight. Will history be made in Switzerland?', NULL, 'https://www.dw.com/en/us-iran-talks-hope-and-skepticism-in-the-swiss-alps/a-77610766?maca=en-rss-en-all-1573-rdf', '2026-06-18 14:12:00+00', 'US-Iran talks: Hope and skepticism in the Swiss alps', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367983270215680, '2026-06-19 09:04:42.994087', 295880188006400, NULL, NULL, '', NULL, NULL, 'Ein alternder Musiker in einer Hochzeitsband, dem der Durchbruch als Rockstar verwehrt blieb, verbrüdert sich bei einem Trinkgelage mit einem ehemaligen Boyband-Musiker, der seine Solo-Karriere starten will. Wenig später landet der junge Sänger mit einem Lied, das der Hochzeitsmusiker ihm in besagter Nacht vorgesungen hat, einen großen Hit. Düpiert fordert der Ältere seinen Anteil an dem Erfolg ein. Eine Feel-Good-Komödie über Generationenkonflikte, Selbstzweifel und Kompromisse, der es weniger um den Gegensatz von Authentizität und vermarktbaren Songs geht als darum, persönliche Unzulänglichkeiten zu überwinden. Zwar mitunter etwas vorhersehbar und sentimental, streift der Film interessante Fragen über Urheberrecht und vermittelt das Dilemma seiner Figuren mit präzisen Zwischentönen.', 'https://www.filmdienst.de/film/details/626612/power-ballad-der-song-meines-lebens', 'https://www.filmdienst.de/film/details/626612/power-ballad-der-song-meines-lebens', '2026-06-18 08:14:32+00', 'Power Ballad - Der Song meines Lebens', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367983270215681, '2026-06-19 09:04:42.994087', 295880188006400, NULL, NULL, '', NULL, NULL, 'Ein algerisch-stämmiger Koch träumt von einem eigenen Restaurant mit seiner französischen Freundin in Lyon, verschweigt seiner traditionsbewussten Mutter jedoch die Beziehung. Dadurch verstrickt er sich immer tiefer in Ausreden und Notlösungen und nimmt schließlich den Vorschlag einer Barbesitzerin an, gegen Geld vor seiner Freundin seine Mutter zu verkörpern. Eine Komödie über familiäre Erwartungen, kulturelle Identität und den schwierigen Spagat zwischen Herkunft und selbstbestimmtem Leben. Wirklich neue Facetten gewinnt der Film dem bekannten Culture-Clash-Motiv zwar nicht ab, die kulinarische Ebene und einige temperamentvolle Ausreißer bringen aber Schwung in die Story.', 'https://www.filmdienst.de/film/details/626423/couscous-und-geheimnisse', 'https://www.filmdienst.de/film/details/626423/couscous-und-geheimnisse', '2026-06-18 11:05:33+00', 'Couscous und Geheimnisse', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367983270219776, '2026-06-19 09:04:42.995087', 295880188006400, NULL, NULL, '', NULL, NULL, 'Nur noch wenige hundert Exemplare des Löffelstrandläufers leben auf der Erde, Habitatverlust, Umweltverschmutzung und Wilderei haben den Bestand der Vogelart drastisch reduziert. Eine kleine Gruppe von Biologen, Ornithologen und Naturschützern kämpft für das Überleben der Vögel, die sie liebevoll „Spoonie“ nennen. Dabei gelingen, ob in China oder Deutschland, immer wieder Teilerfolge, Verhandlungen mit autokratischen Systemen und die bleibenden Schäden durch Industrieabfälle lassen aber kaum Optimismus zu. Der Dokumentarfilm folgt den Erhaltungsbemühungen und zeigt zwischen leisen Symbolbildern und der Hingabe der Naturschützer, wie frustrierend und dennoch unumgänglich Artenschutz in einer multipolaren, spätkapitalistischen Welt ist.', 'https://www.filmdienst.de/film/details/626408/saving-spoonie', 'https://www.filmdienst.de/film/details/626408/saving-spoonie', '2026-06-18 07:32:26+00', 'Saving Spoonie', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367983270219777, '2026-06-19 09:04:42.995087', 295880188006400, NULL, NULL, '', NULL, NULL, 'Eine über achtzigjährige Frau lebt allein in einem Landhaus in Schleswig-Holstein, kontrolliert und manipuliert aber nach wie vor ihre beiden Töchter. Da diese nicht von der Übermutter loskommen, besteht ein permanenter Kleinkrieg zwischen den dreien, der bei einem gemeinsamen Frankreichurlaub eskaliert. Ein klaustrophobisch verstörendes, surreales Familiendrama um ein dysfunktionales Mutter-Töchter-Verhältnis. Herausragend gespielt und formal ausgefeilt mit dokumentarisch anmutender Handkamera, einer bewusst fragmentarischen Montage und einer dissonanten Musik ist der Film so kraftvoll schmerzhaft in Szene gesetzt, dass er bei allen künstlerischen Qualitäten einen zwiespältigen Eindruck hinterlässt.', 'https://www.filmdienst.de/film/details/625272/donkey-days', 'https://www.filmdienst.de/film/details/625272/donkey-days', '2026-06-18 07:37:19+00', 'Donkey Days', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (367983270219778, '2026-06-19 09:04:42.995087', 295880188006400, NULL, NULL, '', NULL, NULL, 'Ein neunjähriges Mädchen wird nach dem Tod seiner Mutter über den Sommer bei der Großmutter auf einer kleinen Schäreninsel untergebracht. Während der Vater in seiner Trauer versinkt, erkunden das Mädchen und die eigensinnige alte Frau das Eiland. Sie sprechen über Natur, Leben, Liebe, Gott und Vergänglichkeit und kommen sich näher als je zuvor. Die Verfilmung des Romanklassikers von Tove Jansson behält dessen Aufbau aus kleinen Vignetten bei und nimmt sich Zeit, um den Figuren näherzukommen. Die zärtliche, stille Stimmung des Films greift bis auf wenige Momente unaufdringlich seine großen Themen auf und nimmt Kinder wie Erwachsene mit.', 'https://www.filmdienst.de/film/details/625046/das-sommerbuch', 'https://www.filmdienst.de/film/details/625046/das-sommerbuch', '2026-06-18 10:58:35+00', 'Das Sommerbuch', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (368000297934848, '2026-06-19 10:14:00.152769', 295514619002880, NULL, NULL, '', NULL, NULL, 'US and Iranian delegates will not be meeting on Friday as scheduled, the Swiss Foreign Ministry has said. The White House blamed logistical issues for US Vice President JD Vance delaying his flight. DW has more.', NULL, 'https://www.dw.com/en/iran-war-switzerland-talks-called-off-vance-stays-in-us/live-77620493?maca=en-rss-en-all-1573-rdf', '2026-06-19 10:01:00+00', 'Iran war: Switzerland talks called off, Vance stays in US', NULL);
