INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (368000301592576, '2026-06-19 10:14:01.045571', 295500424519680, NULL, 'DIE ZEIT: Ausland -', 'Ausland', NULL, NULL, 'Tag zwei des EU-Gipfels, diesmal geht es auch um den kommenden EU-Haushalt. Kanzler Merz hält den jüngsten Vorschlag für nicht umsetzbar. Damit ist er nicht allein.', '{urn:uuid:094597f8-e479-4a63-8ce1-0fd7233626fe}', 'https://www.zeit.de/politik/ausland/2026-06/eu-haushalt-friedrich-merz-mehrjaehriger-finanzrahmen-schulden', '2026-06-19 09:51:46+00', 'EU-Gipfel in Brüssel: Merz nennt Vorschlag für EU-Haushalt »viel zu hoch«', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (368000301592577, '2026-06-19 10:14:01.045874', 295500424519680, NULL, 'DIE ZEIT: Deutschland - Jona Spreter', 'Deutschland', NULL, NULL, 'In Deutschland werde oft teuer und konventionell »Stein auf Stein« gebaut, sagt die Bauministerin. Modulares Bauen soll in der Förderung künftig bevorzugt werden.', '{urn:uuid:74584e7f-ec55-49d2-8f68-31c5441ef9b5}', 'https://www.zeit.de/politik/deutschland/2026-06/baukosten-verena-hubertz-spd-13-punkte-plan', '2026-06-19 09:48:23+00', 'Baukosten: Verena Hubertz will Bonus-System bei der Neubauförderung einführen', NULL);
