INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (368004702007296, '2026-06-19 10:31:55.365746', 295853820891136, NULL, NULL, '', NULL, NULL, 'Immer wieder prangert die EU unfaire Wettbewerbspraktiken Chinas an. Wie sich besser schützen, ohne den Handelspartner zu verprellen? Auf ihrem Gipfel berieten die EU-Staaten über Antworten, ohne das Problem konkret zu benennen.', 'a2281d06-09b2-4109-933c-01652429aa8c', 'https://www.tagesschau.de/ausland/europa/eu-china-handel-100.html', '2026-06-19 10:24:54+00', 'EU-Staaten ringen um richtigen Umgang mit Handelspartner China', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (368004702007297, '2026-06-19 10:31:55.365746', 295853820891136, NULL, NULL, '', NULL, NULL, '2020 hat China die Einfuhr von deutschem Schweinefleisch verboten. Seitdem ringt Berlin mit Peking um ein Abkommen. Bei seinem Besuch in China zeigt sich Landwirtschaftsminister Rainer zuversichtlich. Von Benjamin Eyssel.', '2aca8998-54a9-4749-83d1-06c516d5dddf', 'https://www.tagesschau.de/ausland/asien/china-rainer-regionalisierungsabkommen-lieferung-schweinefleisch-100.html', '2026-06-19 10:19:58+00', 'Agrarminister Rainer wirbt in China für deutsches Schweinefleisch', NULL);
