INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (368006369398784, '2026-06-19 10:38:42.44386', 295500424519680, NULL, 'DIE ZEIT: Deutschland - Alara  Yılmaz', 'Deutschland', NULL, NULL, 'Die Innenminister des Bundes und der Länder gehen stärker gegen bandenmäßigen Sozialmissbrauch vor. Dafür soll die Kooperation zwischen Behörden ausgebaut werden.', '{urn:uuid:25794027-0028-46bb-87f7-c8c2b96ce3e1}', 'https://www.zeit.de/politik/deutschland/2026-06/sozialmissbrauch-banden-eu-buerger-schrottimmobilien', '2026-06-19 10:26:43+00', 'Sozialmissbrauch: Innenminister wollen Sozialmissbrauch härter bekämpfen', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (368006369865728, '2026-06-19 10:38:42.55784', 295853820891136, NULL, NULL, '', NULL, NULL, 'Juckreiz und schlaflose Nächte - Neurodermitis ist eine enorme Belastung für Babys und deren Eltern. Wie wirkt sich die Ernährung auf das Risiko aus, daran zu erkranken? Das hat nun eine Studie untersucht. Von Constanze Alvarez.', 'be8c5c3f-c037-419d-a3d2-522642227cc4', 'https://www.tagesschau.de/wissen/gesundheit/babynahrung-neurodermitis-100.html', '2026-06-19 10:35:17+00', 'Studie: Beeinflusst Babynahrung das Risiko für Neurodermitis?', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (368006370406400, '2026-06-19 10:38:42.689495', 295514619002880, NULL, NULL, '', NULL, NULL, 'The Barack Obama Presidential Center was opened in Chicago on Thursday in an event that was a celebration of democracy and an optimistic call to embrace "our shared responsibilities as citizens."', NULL, 'https://www.dw.com/en/us-stars-and-ex-leaders-on-hand-to-open-obama-center/a-77623934?maca=en-rss-en-all-1573-rdf', '2026-06-19 10:36:00+00', 'US: Stars and ex-leaders on hand to open Obama Center', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (368021158846465, '2026-06-19 11:38:53.148889', 295514619002880, NULL, NULL, '', NULL, NULL, 'In Europe—unlike in Asia—changes to decades of international norms and institutional systems are often interpreted as a loss. However, these changes may also mark the beginning of a new, more inclusive order.', NULL, 'https://www.dw.com/en/the-collapse-of-world-order-as-an-opportunity-for-asia/a-77625031?maca=en-rss-en-all-1573-rdf', '2026-06-19 10:44:00+00', 'The collapse of ''world order'' as an opportunity for Asia?', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (368021158850560, '2026-06-19 11:38:53.149992', 295514619002880, NULL, NULL, '', NULL, NULL, 'The Barack Obama Presidential Center was opened in Chicago on Thursday in an event that was a celebration of democracy and an optimistic call to embrace "our shared responsibilities as citizens."', NULL, 'https://www.dw.com/en/us-stars-and-ex-leaders-on-hand-to-open-obama-center/a-77623934?maca=en-rss-en-all-1573-rdf', '2026-06-19 10:37:00+00', 'US: Stars and ex-leaders on hand to open Obama Center', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (368021161250816, '2026-06-19 11:38:53.735211', 295500424519680, NULL, 'DIE ZEIT: Deutschland - Hella Kemper', 'Deutschland', NULL, NULL, 'Die Rentenkommission präsentiert ihr Konzept für ein neues Rentensystem bereits am Dienstag. Kanzler Merz und Arbeitsministerin Bas werden den Bericht entgegennehmen.', '{urn:uuid:ca2db9d6-c2b2-4499-bdf5-57c770e6d68d}', 'https://www.zeit.de/politik/deutschland/2026-06/rentenkommission-bericht-rentenreform-friedrich-merz-baerbel-bas', '2026-06-19 11:18:15+00', 'Deutsches Rentensystem: Rentenkommission präsentiert Vorschläge früher als geplant', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (368021162053632, '2026-06-19 11:38:53.931272', 295853820891136, NULL, NULL, '', NULL, NULL, 'Ein ehemaliges Mitglied der Regensburger Domspatzen ist mit einer Klage gegen das Bistum Regensburg gescheitert. Der Mann hatte Schmerzensgeld gefordert, da er im Vorschulalter missbraucht worden sei. Doch die Taten gelten als verjährt.', '5bb4ac47-5d6e-4926-89d9-754778262d52', 'https://www.tagesschau.de/inland/domspatz-klage-schmerzensgeld-100.html', '2026-06-19 11:35:56+00', 'Ehemaliger Domspatz scheitert mit Klage auf Schmerzensgeld', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (368021162053633, '2026-06-19 11:38:53.931272', 295853820891136, NULL, NULL, '', NULL, NULL, 'Auch nach dem Wahlsieg seines parteiinternen Kontrahenten Burnham gibt sich der britische Premier und Labour-Chef Starmer kämpferisch. Einen Rücktritt lehnte er erneut ab. Alles läuft nun auf einen Machtkampf bei Labour hinaus.', 'd18f422c-8d8e-4d71-ae5e-dea28eac0b5f', 'https://www.tagesschau.de/ausland/europa/grossbritannien-starmer-burnham-100.html', '2026-06-19 10:49:51+00', 'Starmer will um sein Amt als Labour-Chef in Großbritannien kämpfen', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (368021162053634, '2026-06-19 11:38:53.931272', 295853820891136, NULL, NULL, '', NULL, NULL, 'Die gesperrte Bonner Nordbrücke wird bis auf Weiteres nicht wieder für den Verkehr freigegeben. Ein Teilstück muss abgerissen und neu gebaut werden. Das sagte Bundesverkehrsminister Schnieder.', 'tagesschau_fm-story-WDR-c98e996a-9057-4520-a703-5754dc93bf37', 'https://www.tagesschau.de/inland/regional/nordrheinwestfalen/wdr-a565-bruecke-bleibt-gesperrt-bonner-nordbruecke-wird-teils-neu-gebaut-100.html', '2026-06-19 11:29:00+00', 'Bonner Nordbrücke bleibt gesperrt - Teilneubau nötig', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (368021162057728, '2026-06-19 11:38:53.932279', 295853820891136, NULL, NULL, '', NULL, NULL, 'Der Deutsche Wetterdienst weitete seine Hitzewarnungen auf alle Bundesländer aus - mit wenigen Ausnahmen. Örtlich können Starkregen, Hagel, Sturmböen und Unwetter auftreten. In Norddeutschland gab es Zug-Probleme.', '22c684fb-df22-4d3b-a108-02cb017de68d', 'https://www.tagesschau.de/inland/gesellschaft/hitze-unwetter-104.html', '2026-06-19 11:22:52+00', 'Warnung des DWD: Hitzewelle und Gewitter über Deutschland', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (368025263005696, '2026-06-19 11:55:35.140561', 295500424519680, NULL, 'DIE ZEIT: Arbeit - Henrik Rampe', 'Arbeit', NULL, NULL, 'Ihr Tag scheint mehr als 24 Stunden zu haben. Mühelos bewältigen Sie Karriere, Familie und Sport. Und das alles, ohne kurz vor dem Burn-out zu stehen? Schreiben Sie uns.', '{urn:uuid:fa6474e5-5195-4dc4-b72e-49b975779c5e}', 'https://www.zeit.de/arbeit/2026-06/arbeitszeiterfassung-reform-highperformer-ueberstunden', '2026-06-19 11:53:52+00', 'Arbeitszeiterfassung: Sind Sie ein Highperformer?', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (368025263009792, '2026-06-19 11:55:35.141559', 295500424519680, NULL, 'DIE ZEIT: Deutschland - Jona Spreter', 'Deutschland', NULL, NULL, 'Die Union hält nichts von Tarifbindung bei der Einführung der Wochenarbeitszeit. Die SPD-Politikerin Cansel Kiziltepe hingegen sagt, das sei »Koalitionsvertrag pur«.', '{urn:uuid:5ad4f958-4d5e-4f02-b09a-6d6025baea66}', 'https://www.zeit.de/politik/deutschland/2026-06/arbeitszeitgesetz-reform-spd-cansel-kiziltepe', '2026-06-19 11:37:24+00', 'Arbeitszeitgesetz: SPD-Arbeitnehmerflügel weist Kritik an Arbeitszeitreform zurück', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (368025263009793, '2026-06-19 11:55:35.141559', 295500424519680, NULL, 'DIE ZEIT: Deutschland - Alara  Yılmaz, Tilman Steffen', 'Deutschland', NULL, NULL, 'Die Innenminister des Bundes und der Länder möchten stärker gegen Destabilisierung von außen ankämpfen. Hybride Bedrohungen waren eines der zentralen Themen auf der IMK.', '{urn:uuid:25794027-0028-46bb-87f7-c8c2b96ce3e1}', 'https://www.zeit.de/politik/deutschland/2026-06/sozialmissbrauch-banden-eu-buerger-schrottimmobilien', '2026-06-19 11:35:47+00', 'Innenministerkonferenz: Innenminister wollen sich besser gegen hybride Bedrohungen wehren', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (368025263009794, '2026-06-19 11:55:35.141559', 295500424519680, NULL, 'DIE ZEIT: Deutschland - Yannick von Eisenhart Rothe, Jana Hensel', 'Deutschland', NULL, NULL, 'Die wissenschaftlichen Dienste des Bundestages halten das geplante Heizungsgesetz aus Klimaschutzgründen für bedenklich. Angefordert wurde das Gutachten von den Grünen.', '{urn:uuid:92b49f32-9e4d-4f08-81b6-2d756f2cbab7}', 'https://www.zeit.de/politik/deutschland/2026-06/heizgesetz-schwarz-rot-koalition-gebaeudemodernisierungsgesetz-verfassungsrechtliche-zweifel', '2026-06-19 11:32:54+00', 'Gebäudemodernisierungsgesetz: Gutachter äußern verfassungsrechtliche Zweifel an Heizungsgesetz', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (368029696110592, '2026-06-19 12:13:37.441478', 295500424519680, NULL, 'DIE ZEIT: Wirtschaft - Thomas Fischermann, Johanna Jürgens, Jakob von Lindern, Heike Buchter', 'Wirtschaft', NULL, NULL, 'Die US-Regierung verbietet Ausländern, die fortschrittlichste KI der Welt zu nutzen. Wie reagiert Europa? In Berlin und Brüssel kursieren radikale Ideen.', '{urn:uuid:d138894d-ff8d-47bb-bb90-e972cc8e302b}', 'https://www.zeit.de/2026/27/anthropic-exportverbot-ki-modelle-claude-mythos-fable-usa', '2026-06-19 12:06:42+00', 'Anthropic: Zugriff ab sofort verweigert', NULL);
