INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (368041472999424, '2026-06-19 13:01:32.658491', 295500424519680, NULL, 'DIE ZEIT: Deutschland - Yannick von Eisenhart Rothe', 'Deutschland', NULL, NULL, 'Unter dem Motto »Es reicht« hält die Linke ihren Bundesparteitag in Potsdam ab. Gewählt wird ein neuer Parteivorsitz, im Fokus stehen Sozialreformen und Nahostkonflikt.', '{urn:uuid:7405812b-458a-4cb9-ab0d-6399f6d42c21}', 'https://www.zeit.de/politik/deutschland/2026-06/parteitag-die-linke-potsdam-afd-ostdeutschland', '2026-06-19 12:58:50+00', 'Bundesparteitag der Linken: Bundesparteitag der Linken in Potsdam hat begonnen', NULL);
