INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (368046879244289, '2026-06-19 13:23:32.542748', 295500424519680, NULL, 'DIE ZEIT: Ausland - Konstantin Zimmermann, Hella Kemper, Lennart Jerke', 'Ausland', NULL, NULL, 'Der Iran verurteilt die jüngsten Angriffe auf den Libanon und verweist auf das US-Iran-Abkommen. Mehr Schiffe durchfahren offenbar die Straße von Hormus. Das Liveblog', '{urn:uuid:2d57f875-64df-4ad6-b830-4fee12760ea8}', 'https://www.zeit.de/politik/ausland/2026-05/iran-krieg-donald-trump-hormus-live', '2026-06-19 13:13:27+00', 'Irankrieg: Iran weist USA Verantwortung für israelische Angriffe auf Libanon zu', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (368046879862784, '2026-06-19 13:23:32.694972', 295853820891136, NULL, NULL, '', NULL, NULL, '"Turbo", "Upgrade" und jetzt "Aktionsplan": Mit weiteren Maßnahmen will das Ministerium das Bauen bezahlbarer machen. Denn die Kosten bremsen den Wohnungsbau in Deutschland. Was sieht der Plan vor? Von Frank Jahn.', 'c676d363-01e5-4a74-b6df-6e0c205deef5', 'https://www.tagesschau.de/inland/innenpolitik/aktionsplan-baukosten-100.html', '2026-06-19 13:16:04+00', 'Bauministerium legt "Aktionsplan zur Senkung der Baukosten" vor', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (368046880481280, '2026-06-19 13:23:32.844017', 295514619002880, NULL, NULL, '', NULL, NULL, 'Indian women fight back against toxic coal dust, the US hits a solar milestone, and there''s good news for soil in Kenya and cars worldwide.', NULL, 'https://www.dw.com/en/women-tackling-coal-dust-and-other-eco-wins-this-week/a-77627984?maca=en-rss-en-all-1573-rdf', '2026-06-19 13:18:00+00', 'Women tackling coal dust and other eco wins this week', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (368049310523392, '2026-06-19 13:33:26.116529', 295500424519680, NULL, 'DIE ZEIT: Musik - Torsten Groß', 'Musik', NULL, NULL, 'Songs schreiben sei wie Angeln, findet Keith Richards. Hier spricht der Gitarrist der Rolling Stones über das neue Album »Foreign Tongues«, das Altern und Mick Jagger.', '{urn:uuid:648de2a9-c765-461f-8e46-f73981819c1a}', 'https://www.zeit.de/feuilleton/musik/2026-06/keith-richards-rolling-stone-musiker-album', '2026-06-19 13:23:38+00', 'Keith Richards: »Ich würde selbst gerne wissen, wie ich auf solche Ideen komme«', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (368049310523393, '2026-06-19 13:33:26.116529', 295500424519680, NULL, 'DIE ZEIT: Ausland - Konstantin Zimmermann', 'Ausland', NULL, NULL, 'Seit dem Nachmittag gilt nach US-Angaben eine Waffenruhe zwischen Israel und der Hisbollah im Libanon. Zuletzt hatte es trotz des Abkommen Angriffe beider Seiten gegeben.', '{urn:uuid:168c4eab-feb8-4512-8063-47aaf6a6fed0}', 'https://www.zeit.de/politik/ausland/2026-06/israel-und-hisbollah-einigen-sich-laut-us-kreisen-auf-waffenruhe', '2026-06-19 13:23:13+00', 'Libanon: Israel und Hisbollah einigen sich laut US-Kreisen auf Waffenruhe', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (368056384430080, '2026-06-19 14:02:13.145218', 295514619002880, NULL, NULL, '', NULL, NULL, 'Opposition leader Domingos Simoes Pereira remains under house arrest months after the Guinea-Bissau coup, deepening a political crisis and raising tensions with international partners.', NULL, 'https://www.dw.com/en/guinea-bissau-opposition-leader-house-arrest-raises-stakes/a-77593866?maca=en-rss-en-all-1573-rdf', '2026-06-19 13:49:00+00', 'Guinea-Bissau: Opposition leader house arrest raises stakes', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (368056387088384, '2026-06-19 14:02:13.79388', 295853820891136, NULL, NULL, '', NULL, NULL, 'Der Iran-Krieg hat Russland nur kurz Luft verschafft. Sinkende Ölpreise, ukrainische Drohnenangriffe und die Rubel-Stärke belasten zunehmend die Wirtschaft. Wie lange kann Putin den Krieg noch finanzieren? Von Angela Göpfert.', 'c3f81774-7271-4d8b-a5b5-ba01aa5405f8', 'https://www.tagesschau.de/wirtschaft/weltwirtschaft/russland-wirtschaft-putin-oelpreis-rubel-100.html', '2026-06-19 13:52:55+00', 'Wie der fallende Ölpreis Russlands Kriegswirtschaft bedroht', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (368062079180801, '2026-06-19 14:25:23.464879', 295500424519680, NULL, 'DIE ZEIT: Gesellschaft - Alara  Yılmaz', 'Gesellschaft', NULL, NULL, 'Bis zu 50 Euro für einen Tag in Venedig: Der neue Bürgermeister der italienischen Lagunenstadt hat eine Debatte ausgelöst. Bisher zahlen Kurzbesucher fünf bis zehn Euro.', '{urn:uuid:f196ea10-195f-4ca9-8d31-5ad608476067}', 'https://www.zeit.de/gesellschaft/2026-06/venedig-eintrittsgebuehr-touristen-massentourismus-simone-venturini', '2026-06-19 14:12:30+00', 'Massentourismus: Venedigs Bürgermeister will Eintrittsgeld für Besucher stark anheben', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (368062079180802, '2026-06-19 14:25:23.464879', 295500424519680, NULL, 'DIE ZEIT: Deutschland - Hauke Friederichs', 'Deutschland', NULL, NULL, 'David Matei kam wegen des Soldes zur Bundeswehr, blieb und wurde als Influencer einer der bekanntesten Soldaten. Wieso er nun ging und dennoch für den Dienst wirbt.', '{urn:uuid:4baab063-353c-4a39-9721-a3177bdf9d83}', 'https://www.zeit.de/politik/deutschland/2026-06/david-matei-bundeswehr-wehrpflicht-soziale-medien-werbung-jugendliche-gxe', '2026-06-19 14:12:11+00', 'David Matei: »Es war nie mein Anliegen, junge Leute zur Bundeswehr zu locken«', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (368062079180803, '2026-06-19 14:25:23.464879', 295500424519680, NULL, 'DIE ZEIT: Geld - Caspar Leder', 'Geld', NULL, NULL, 'Trotz des deutschen Widerstands treibt die Unicredit die Übernahme der Commerzbank voran. Bereits jetzt hat das Kreditinstitut eine Beteiligung von 39 Prozent sicher.', '{urn:uuid:c6484cfd-d844-4bb7-b851-de1a3dc99495}', 'https://www.zeit.de/geld/2026-06/unicredit-commerzbank-uebernahme-angebot-aktien', '2026-06-19 14:06:10+00', 'UniCredit und Commerzbank: Unicredit verlängert Angebot zum Kauf aller Commerzbank-Aktien', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (368064211800064, '2026-06-19 14:34:04.123258', 295514619002880, NULL, NULL, '', NULL, NULL, 'With AI dominated by US firms, Europe is pushing for more independence. New partnerships, investments and startups aim to boost the continent''s digital sovereignty, but challenges around funding and regulation remain.', NULL, 'https://www.dw.com/en/can-europe-build-its-own-ai-heavyweights-to-rival-the-us/a-77629735?maca=en-rss-en-all-1573-rdf', '2026-06-19 14:27:00+00', 'Can Europe build its own AI heavyweights to rival the US?', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (368064214593536, '2026-06-19 14:34:04.805998', 295500424519680, NULL, 'DIE ZEIT: Ausland - Hella Kemper', 'Ausland', NULL, NULL, '»Ganz Italien beleidigt«: Zwischen Giorgia Meloni und Donald Trump ist es erneut zu einem Zerwürfnis gekommen. Italiens Außenminister sagt eine US-Reise ab.', '{urn:uuid:eb5493cf-26bc-409c-987a-7b2d8f9230c2}', 'https://www.zeit.de/politik/ausland/2026-06/giorgia-meloni-donald-trump-g7-foto-frankreich', '2026-06-19 14:23:54+00', 'Beziehung zwischen USA und Italien: Giorgia Meloni wirft Donald Trump Lüge vor', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (368065497911296, '2026-06-19 14:39:18.115675', 295500424519680, NULL, 'DIE ZEIT: Politik - Ileana Grabitz, Peter Dausend, Thomas Fischermann', 'Politik', NULL, NULL, 'Die USA haben sich in Nahost eine »eingedrückte Nase« geholt. Und nun ist klar, wie sehr Geografie auch heute über Macht und Wohlstand bestimmt. Das hat auch etwas Gutes.', '{urn:uuid:1e382e65-bb90-44b6-8935-2e2ceab367d6}', 'https://www.zeit.de/politik/2026-06/strasse-von-hormus-geographie-macht-politikpodcast', '2026-06-19 14:30:22+00', 'Straße von Hormus : Die Welt nach dem Irankrieg ist eine andere', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (368065499770880, '2026-06-19 14:39:18.569397', 295880188006400, NULL, NULL, '', NULL, NULL, 'Ein netter, introvertierter Mann verliebt sich in eine Arbeitskollegin, schreckt aber zurück, als sie ihn direkt nach seinen Gefühlen für ihn fragt. Diese verpasste Chance verärgert ihn so, dass er mittels eines magischen Objekts die bedingungslos glückliche Bindung herbeisehnt. Tatsächlich weicht ihm die Freundin nicht mehr von der Seite, doch erscheint dies mehr und mehr als pathologische, zerstörerische Form der Liebe. Was als harmlose Beziehungskomödie beginnt, wandelt sich langsam in Horror, der immer wieder auf überraschende Weise variiert wird. Der satirische Mystery-Horror-Thriller entwickelt als formal und darstellerisch brillanter Film eine zunehmend verstörende Wirkung, mit der das Amüsement purem Schrecken weicht.', 'https://www.filmdienst.de/film/details/625585/obsession-du-sollst-mich-lieben', 'https://www.filmdienst.de/film/details/625585/obsession-du-sollst-mich-lieben', '2026-06-19 14:36:38+00', 'Obsession - Du sollst mich lieben', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (368066269499392, '2026-06-19 14:42:26.491278', 295853820891136, NULL, NULL, '', NULL, NULL, 'Offizielle Bestätigungen gibt es noch nicht, aber Israel und die Hisbollah haben sich laut Berichten auf eine erneute Waffenruhe geeinigt. Zuvor hatten erneute Gefechte das Rahmenabkommen zwischen USA und Iran gefährdet.', 'e5814872-e2ff-45fa-bc98-aeb6a7dea3da', 'https://www.tagesschau.de/ausland/israel-hisbollah-130.html', '2026-06-19 14:41:03+00', 'Israel und Hisbollah vereinbaren offenbar erneute Waffenruhe', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (368071979982848, '2026-06-19 15:05:40.652078', 295500424519680, NULL, 'DIE ZEIT: Sport - Yannick von Eisenhart Rothe, Fabian Albrecht, Caspar Leder', 'Sport', NULL, NULL, 'Das DFB-Team macht sich auf den Weg nach Toronto, wo es gegen Côte d’Ivoire antritt. Die Türkei verbietet Public Viewings wegen Uniprüfungen. Das Liveblog', '{urn:uuid:e528ca8b-f67f-493e-b77e-30d2cb57e930}', 'https://www.zeit.de/sport/2026-05/fussball-wm-2026-liveblog', '2026-06-19 15:03:12+00', 'Fußball-WM 2026: Alle deutschen Nationalspieler fit für zweites Gruppenspiel', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (368071979982849, '2026-06-19 15:05:40.652078', 295500424519680, NULL, 'DIE ZEIT: Deutschland - Alara  Yılmaz', 'Deutschland', NULL, NULL, 'SPD und Opposition zeigen sich irritiert über Verbindungen des Unionsfraktionschefs zum Trump-Unterstützer Peter Thiel. Spahn hatte Treffen mit dem Milliardär eingeräumt.', '{urn:uuid:60f2581f-74ef-40da-b2b8-5493291b6839}', 'https://www.zeit.de/politik/deutschland/2026-06/jens-spahn-peter-thiel-dialog-netzwerk-treffen', '2026-06-19 14:58:24+00', 'Peter Thiel: Treffen von Jens Spahn mit US-Milliardär Peter Thiel sorgen für Kritik', NULL);
INSERT INTO public.rssitems (id, createdat, secondarykey, updatedat, author, categories, comments, content, description, guid, link, pubdate, title, updateddate) VALUES (368071979982850, '2026-06-19 15:05:40.652078', 295500424519680, NULL, 'DIE ZEIT: Sport - Daniel Gerhardt', 'Sport', NULL, NULL, 'Johan Manzambi macht die Schweiz und seinen Agenten glücklich. Eine Wade macht Sorgen, und die USA spielen im lustigsten Stadion der WM. So wird der Fußballabend.', '{urn:uuid:f4d4a15a-4649-4480-a933-ff2ce62babc0}', 'https://www.zeit.de/sport/2026-06/fussball-wm-heute-usa-australien-seattle', '2026-06-19 14:52:14+00', 'Fußball-WM heute: Ein Name zum Merken', NULL);


